import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface CaptionSegment {
  id: number;
  start: string; // HH:MM:SS,mmm
  end: string;   // HH:MM:SS,mmm
  text: string;
}

export interface ProcessingState {
  status: 'idle' | 'uploading' | 'processing' | 'completed' | 'error';
  progress: number;
  message: string;
}

export interface GeminiTranscriptionResponse {
  segments: {
    start_seconds: number;
    end_seconds: number;
    text: string;
  }[];
}

export const formatSecondsToSRT = (seconds: number): string => {
  const date = new Date(0);
  date.setSeconds(seconds);
  const ms = Math.floor((seconds % 1) * 1000);
  const timePart = date.toISOString().substr(11, 8);
  return `${timePart},${ms.toString().padStart(3, '0')}`;
};

export const generateSRT = (segments: { start_seconds: number; end_seconds: number; text: string }[]): string => {
  return segments
    .map((seg, index) => {
      const start = formatSecondsToSRT(seg.start_seconds);
      const end = formatSecondsToSRT(seg.end_seconds);
      return `${index + 1}\n${start} --> ${end}\n${seg.text}\n`;
    })
    .join('\n');
};

import { GoogleGenAI, Type } from "@google/genai";

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  async transcribeVideo(base64Data: string, mimeType: string) {
    const model = 'gemini-3-flash-preview';

    const prompt = `
      You are a professional video transcriber. 
      Task:
      1. Transcribe the audio from this video.
      2. If the audio is not in English, translate it to English.
      3. Provide the output as a JSON object containing an array of segments.
      4. Each segment must have 'start_seconds', 'end_seconds', and 'text'.
      5. Ensure timestamps are accurate to the speech in the video.
      6. Split text into segments that are easy to read as captions (roughly 5-10 words per segment).
    `;

    try {
      const response = await this.ai.models.generateContent({
        model,
        contents: {
          parts: [
            { inlineData: { data: base64Data, mimeType } },
            { text: prompt }
          ]
        },
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              segments: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    start_seconds: { type: Type.NUMBER },
                    end_seconds: { type: Type.NUMBER },
                    text: { type: Type.STRING }
                  },
                  required: ["start_seconds", "end_seconds", "text"]
                }
              }
            },
            required: ["segments"]
          }
        }
      });

      const jsonStr = response.text.trim();
      return JSON.parse(jsonStr);
    } catch (error) {
      console.error("Gemini API Error:", error);
      throw error;
    }
  }
}

import React, { useState, useRef, useCallback } from 'react';
import { GeminiService } from './services/geminiService';
import { generateSRT } from './utils/timeFormatter';
import { ProcessingState, GeminiTranscriptionResponse } from './types';

const App: React.FC = () => {
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [videoFile, setVideoFile] = useState<File | null>(null);
  const [transcription, setTranscription] = useState<GeminiTranscriptionResponse | null>(null);
  const [status, setStatus] = useState<ProcessingState>({
    status: 'idle',
    progress: 0,
    message: 'Waiting for video upload...'
  });

  const fileInputRef = useRef<HTMLInputElement>(null);
  const geminiService = useRef(new GeminiService());

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      if (file.size > 20 * 1024 * 1024) {
        alert("File size exceeds 20MB limit for this prototype. Please try a smaller video.");
        return;
      }
      setVideoFile(file);
      setVideoUrl(URL.createObjectURL(file));
      setTranscription(null);
      setStatus({ status: 'idle', progress: 0, message: 'Video loaded. Click "Start Transcribing" to begin.' });
    }
  };

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => {
        const base64String = reader.result as string;
        resolve(base64String.split(',')[1]);
      };
      reader.onerror = (error) => reject(error);
    });
  };

  const handleTranscribe = async () => {
    if (!videoFile) return;

    setStatus({ status: 'processing', progress: 10, message: 'Encoding video for AI analysis...' });

    try {
      const base64Data = await fileToBase64(videoFile);
      setStatus({ status: 'processing', progress: 40, message: 'Gemini is transcribing and translating...' });

      const result = await geminiService.current.transcribeVideo(base64Data, videoFile.type);

      setTranscription(result);
      setStatus({ status: 'completed', progress: 100, message: 'Transcription completed successfully!' });
    } catch (error) {
      console.error(error);
      setStatus({ status: 'error', progress: 0, message: 'Failed to transcribe. Check console for details.' });
    }
  };

  const downloadSRT = () => {
    if (!transcription) return;
    const srtContent = generateSRT(transcription.segments);
    const blob = new Blob([srtContent], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${videoFile?.name || 'video'}_captions.srt`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  return (
    <div className="min-h-screen p-4 md:p-8 flex flex-col items-center max-w-6xl mx-auto">
      {/* Header */}
      <header className="w-full mb-8 text-center">
        <h1 className="text-4xl md:text-5xl font-extrabold bg-clip-text text-transparent bg-gradient-to-r from-blue-400 to-indigo-600 mb-2">
          VidiScribe AI
        </h1>
        <p className="text-slate-400 text-lg">
          Transcribe, Translate & Generate YouTube Captions instantly.
        </p>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 w-full">
        {/* Left Column: Video & Controls */}
        <div className="flex flex-col space-y-6">
          <div className="glass-panel p-6 rounded-2xl shadow-xl">
            <h2 className="text-xl font-semibold mb-4 flex items-center gap-2">
              <svg className="w-6 h-6 text-blue-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z" /></svg>
              Upload Video
            </h2>

            <div 
              onClick={() => fileInputRef.current?.click()}
              className="border-2 border-dashed border-slate-700 rounded-xl p-8 text-center cursor-pointer hover:border-blue-500 transition-colors group"
            >
              <input 
                type="file" 
                ref={fileInputRef} 
                onChange={handleFileChange} 
                className="hidden" 
                accept="video/*"
              />
              <div className="mb-4 flex justify-center">
                <div className="p-4 bg-slate-800 rounded-full group-hover:bg-blue-900 transition-colors">
                  <svg className="w-8 h-8 text-slate-400 group-hover:text-blue-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" /></svg>
                </div>
              </div>
              <p className="text-slate-300 font-medium">Click to upload or drag and drop</p>
              <p className="text-slate-500 text-sm mt-1">MP4, MOV, WEBM (Max 20MB)</p>
            </div>

            {videoUrl && (
              <div className="mt-6 rounded-lg overflow-hidden border border-slate-700">
                <video src={videoUrl} controls className="w-full aspect-video bg-black" />
              </div>
            )}
          </div>

          <div className="glass-panel p-6 rounded-2xl">
            <h3 className="text-lg font-semibold mb-4">Actions</h3>
            <div className="flex flex-col sm:flex-row gap-3">
              <button
                onClick={handleTranscribe}
                disabled={!videoFile || status.status === 'processing'}
                className="flex-1 px-6 py-3 bg-blue-600 hover:bg-blue-700 disabled:bg-slate-700 disabled:cursor-not-allowed rounded-xl font-bold transition-all shadow-lg flex items-center justify-center gap-2"
              >
                {status.status === 'processing' ? (
                  <>
                    <svg className="animate-spin h-5 w-5 text-white" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                    Processing...
                  </>
                ) : (
                  'Start Transcribing'
                )}
              </button>
              <button
                onClick={downloadSRT}
                disabled={!transcription}
                className="flex-1 px-6 py-3 bg-emerald-600 hover:bg-emerald-700 disabled:bg-slate-700 disabled:cursor-not-allowed rounded-xl font-bold transition-all shadow-lg flex items-center justify-center gap-2"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                Download SRT
              </button>
            </div>

            <div className="mt-4">
              <div className="flex justify-between text-xs text-slate-500 mb-1 uppercase font-bold tracking-wider">
                <span>Status</span>
                <span>{status.progress}%</span>
              </div>
              <div className="w-full bg-slate-800 rounded-full h-2 overflow-hidden">
                <div 
                  className="bg-blue-500 h-full transition-all duration-500 ease-out"
                  style={{ width: `${status.progress}%` }}
                />
              </div>
              <p className="mt-2 text-sm text-slate-400 italic">{status.message}</p>
            </div>
          </div>
        </div>

        {/* Right Column: Results */}
        <div className="glass-panel p-6 rounded-2xl flex flex-col h-[600px] lg:h-auto">
          <div className="flex justify-between items-center mb-4">
            <h2 className="text-xl font-semibold flex items-center gap-2">
              <svg className="w-6 h-6 text-yellow-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
              Transcription Preview
            </h2>
            {transcription && (
              <span className="bg-blue-900/40 text-blue-300 text-xs px-2 py-1 rounded-full border border-blue-800">
                {transcription.segments.length} segments
              </span>
            )}
          </div>

          <div className="flex-1 overflow-y-auto pr-2 space-y-3 custom-scrollbar">
            {!transcription && status.status === 'idle' && (
              <div className="h-full flex flex-col items-center justify-center text-slate-500 gap-4 opacity-50">
                <svg className="w-16 h-16" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1" d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" /></svg>
                <p>No transcription yet</p>
              </div>
            )}

            {status.status === 'processing' && (
              <div className="h-full flex flex-col items-center justify-center gap-4">
                <div className="relative">
                  <div className="w-12 h-12 border-4 border-blue-500/20 border-t-blue-500 rounded-full animate-spin"></div>
                </div>
                <p className="text-slate-400 animate-pulse">Analyzing audio data...</p>
              </div>
            )}

            {transcription?.segments.map((seg, idx) => (
              <div key={idx} className="bg-slate-800/50 p-4 rounded-xl border border-slate-700/50 hover:bg-slate-800 transition-colors group">
                <div className="flex justify-between items-start mb-2">
                  <span className="text-xs font-bold text-slate-500 bg-slate-900 px-2 py-1 rounded">
                    SEGMENT #{idx + 1}
                  </span>
                  <div className="text-xs font-mono text-blue-400">
                    {Math.floor(seg.start_seconds)}s → {Math.floor(seg.end_seconds)}s
                  </div>
                </div>
                <p className="text-slate-200 leading-relaxed">
                  {seg.text}
                </p>
              </div>
            ))}
          </div>

          <footer className="mt-4 pt-4 border-t border-slate-700/50 text-xs text-slate-500">
            * Translation uses Gemini AI. Accuracy may vary based on audio quality.
          </footer>
        </div>
      </div>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar {
          width: 6px;
        }
        .custom-scrollbar::-webkit-scrollbar-track {
          background: rgba(0,0,0,0.1);
          border-radius: 10px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
          background: rgba(255,255,255,0.1);
          border-radius: 10px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover {
          background: rgba(255,255,255,0.2);
        }
      `}</style>
    </div>
  );
};

export default App;

export function encodeBase64(bytes: Uint8Array): string {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

export function decodeBase64(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export function createPcmBlob(data: Float32Array): { data: string; mimeType: string } {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    int16[i] = data[i] * 32768;
  }
  return {
    data: encodeBase64(new Uint8Array(int16.buffer)),
    mimeType: 'audio/pcm;rate=16000',
  };
}

export interface CaptionSegment {
  id: number;
  start_seconds: number;
  end_seconds: number;
  text: string;
}

export interface ProcessingState {
  status: 'idle' | 'connecting' | 'streaming' | 'completed' | 'error';
  message: string;
}

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { GoogleGenAI, Modality, LiveServerMessage } from '@google/genai';
import { createPcmBlob, decodeBase64, decodeAudioData } from './utils/audioUtils';
import { generateSRT } from './utils/timeFormatter';
import { ProcessingState, CaptionSegment } from './types';

const App: React.FC = () => {
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [status, setStatus] = useState<ProcessingState>({
    status: 'idle',
    message: 'Select a video to start live transcription.'
  });
  const [segments, setSegments] = useState<CaptionSegment[]>([]);
  const [currentText, setCurrentText] = useState("");

  const videoRef = useRef<HTMLVideoElement>(null);
  const audioCtxRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const segmentsRef = useRef<CaptionSegment[]>([]);
  const startTimeRef = useRef<number>(0);

  // Auto-scroll the transcript
  const transcriptEndRef = useRef<HTMLDivElement>(null);
  useEffect(() => {
    transcriptEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [segments, currentText]);

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      setVideoUrl(URL.createObjectURL(file));
      setSegments([]);
      segmentsRef.current = [];
      setStatus({ status: 'idle', message: 'Video loaded. Ready for live stream.' });
    }
  };

  const startLiveSession = async () => {
    if (!videoRef.current) return;

    try {
      setStatus({ status: 'connecting', message: 'Initializing Gemini Live session...' });

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
          systemInstruction: 'You are a real-time translator. Listen to the input audio and provide a continuous, highly accurate English transcription of what is being said. Do not add commentary. Just transcribe and translate.',
        },
        callbacks: {
          onopen: () => {
            console.log("Live connection opened");
            setStatus({ status: 'streaming', message: 'Live: Processing stream...' });

            // Start the video and capture its audio
            if (videoRef.current) {
              videoRef.current.play();
              startTimeRef.current = Date.now();
              const source = audioCtxRef.current!.createMediaElementSource(videoRef.current);
              const processor = audioCtxRef.current!.createScriptProcessor(4096, 1, 1);

              processor.onaudioprocess = (e) => {
                const inputData = e.inputBuffer.getChannelData(0);
                const pcmBlob = createPcmBlob(inputData);
                sessionPromise.then(session => {
                  session.sendRealtimeInput({ media: pcmBlob });
                });
              };

              source.connect(processor);
              processor.connect(audioCtxRef.current!.destination);
              source.connect(audioCtxRef.current!.destination); // Play the audio through speakers
            }
          },
          onmessage: async (msg: LiveServerMessage) => {
            if (msg.serverContent?.inputTranscription) {
              const text = msg.serverContent.inputTranscription.text;
              const isFinal = msg.serverContent.inputTranscription.isFinal;

              if (text) {
                if (isFinal) {
                  const newSegment: CaptionSegment = {
                    id: segmentsRef.current.length + 1,
                    start_seconds: (videoRef.current?.currentTime || 0) - 2, // Approximate
                    end_seconds: videoRef.current?.currentTime || 0,
                    text: text.trim()
                  };
                  segmentsRef.current = [...segmentsRef.current, newSegment];
                  setSegments([...segmentsRef.current]);
                  setCurrentText("");
                } else {
                  setCurrentText(text);
                }
              }
            }
          },
          onerror: (err) => {
            console.error("Live Error:", err);
            setStatus({ status: 'error', message: 'Connection lost. Please try again.' });
          },
          onclose: () => {
            setStatus({ status: 'completed', message: 'Session closed. You can download the SRT now.' });
          }
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (error) {
      console.error(error);
      setStatus({ status: 'error', message: 'Failed to start live session.' });
    }
  };

  const stopSession = () => {
    if (sessionRef.current) {
      sessionRef.current.close();
      sessionRef.current = null;
    }
    if (videoRef.current) {
      videoRef.current.pause();
    }
    setStatus({ status: 'completed', message: 'Live transcription finished.' });
  };

  const downloadSRT = () => {
    const srtContent = generateSRT(segments.map(s => ({
      start_seconds: s.start_seconds < 0 ? 0 : s.start_seconds,
      end_seconds: s.end_seconds,
      text: s.text
    })));
    const blob = new Blob([srtContent], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `live_captions.srt`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
  };

  return (
    <div className="min-h-screen bg-[#020617] text-slate-100 p-4 md:p-10">
      <div className="max-w-7xl mx-auto space-y-8">

        {/* Navbar */}
        <header className="flex flex-col md:flex-row justify-between items-center gap-4 bg-slate-900/50 p-6 rounded-3xl border border-slate-800 backdrop-blur-md">
          <div className="flex items-center gap-3">
            <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center shadow-lg shadow-blue-900/20">
              <svg className="w-7 h-7 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
            </div>
            <div>
              <h1 className="text-2xl font-bold tracking-tight">VidiScribe <span className="text-blue-500">Live</span></h1>
              <p className="text-xs text-slate-500 font-medium uppercase tracking-widest">Real-time AI Captioning</p>
            </div>
          </div>

          <div className="flex items-center gap-4">
            <div className={`px-4 py-2 rounded-full text-xs font-bold flex items-center gap-2 border ${
              status.status === 'streaming' ? 'bg-red-500/10 border-red-500/50 text-red-400' : 
              status.status === 'connecting' ? 'bg-yellow-500/10 border-yellow-500/50 text-yellow-400' :
              'bg-slate-800 border-slate-700 text-slate-400'
            }`}>
              <span className={`w-2 h-2 rounded-full ${status.status === 'streaming' ? 'bg-red-500 animate-pulse' : 'bg-slate-500'}`} />
              {status.status.toUpperCase()}
            </div>
          </div>
        </header>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* Main Video Viewport */}
          <div className="lg:col-span-8 space-y-6">
            <div className="relative aspect-video bg-black rounded-[2rem] overflow-hidden border border-slate-800 shadow-2xl group">
              {videoUrl ? (
                <video 
                  ref={videoRef}
                  src={videoUrl}
                  className="w-full h-full object-contain"
                  playsInline
                />
              ) : (
                <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-600 bg-slate-900/20">
                  <svg className="w-20 h-20 mb-4 opacity-20" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" /></svg>
