export interface CaptionSegment {
  id: number;
  start_seconds: number;
  end_seconds: number;
  text: string;
}

export interface ProcessingState {
  status: 'idle' | 'connecting' | 'streaming' | 'completed' | 'error';
  message: string;
}

export function encodeBase64(bytes: Uint8Array): string {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

export function decodeBase64(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export function createPcmBlob(data: Float32Array): { data: string; mimeType: string } {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    int16[i] = data[i] * 32768;
  }
  return {
    data: encodeBase64(new Uint8Array(int16.buffer)),
    mimeType: 'audio/pcm;rate=16000',
  };
}

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI, Modality, LiveServerMessage } from '@google/genai';
import { createPcmBlob } from './utils/audioUtils';
import { generateSRT } from './utils/timeFormatter';
import { ProcessingState, CaptionSegment } from './types';

const App: React.FC = () => {
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [status, setStatus] = useState<ProcessingState>({
    status: 'idle',
    message: 'Upload a video to begin real-time transcription with PhiliAI.'
  });
  const [segments, setSegments] = useState<CaptionSegment[]>([]);
  const [currentText, setCurrentText] = useState("");

  const videoRef = useRef<HTMLVideoElement>(null);
  const audioCtxRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const segmentsRef = useRef<CaptionSegment[]>([]);
  const transcriptEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    transcriptEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [segments, currentText]);

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      setVideoUrl(URL.createObjectURL(file));
      setSegments([]);
      segmentsRef.current = [];
      setStatus({ status: 'idle', message: 'Video loaded. PhiliAI is ready.' });
    }
  };

  const startLiveSession = async () => {
    if (!videoRef.current) return;

    try {
      setStatus({ status: 'connecting', message: 'Connecting to PhiliAI neural engine...' });

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
          systemInstruction: 'You are PhiliAI, a professional real-time video transcriber. Listen to the input audio and provide a continuous, accurate English transcription. Translate to English if the source is different. No conversational filler, just transcription.',
        },
        callbacks: {
          onopen: () => {
            setStatus({ status: 'streaming', message: 'Live: PhiliAI is listening...' });

            if (videoRef.current) {
              videoRef.current.play();
              const source = audioCtxRef.current!.createMediaElementSource(videoRef.current);
              const processor = audioCtxRef.current!.createScriptProcessor(4096, 1, 1);

              processor.onaudioprocess = (e) => {
                const inputData = e.inputBuffer.getChannelData(0);
                const pcmBlob = createPcmBlob(inputData);
                sessionPromise.then(session => {
                  session.sendRealtimeInput({ media: pcmBlob });
                });
              };

              source.connect(processor);
              processor.connect(audioCtxRef.current!.destination);
              source.connect(audioCtxRef.current!.destination);
            }
          },
          onmessage: async (msg: LiveServerMessage) => {
            if (msg.serverContent?.inputTranscription) {
              const text = msg.serverContent.inputTranscription.text;
              const isFinal = msg.serverContent.inputTranscription.isFinal;

              if (text) {
                if (isFinal) {
                  const newSegment: CaptionSegment = {
                    id: segmentsRef.current.length + 1,
                    start_seconds: Math.max(0, (videoRef.current?.currentTime || 0) - 1.5),
                    end_seconds: videoRef.current?.currentTime || 0,
                    text: text.trim()
                  };
                  segmentsRef.current = [...segmentsRef.current, newSegment];
                  setSegments([...segmentsRef.current]);
                  setCurrentText("");
                } else {
                  setCurrentText(text);
                }
              }
            }
          },
          onerror: (err) => {
            console.error(err);
            setStatus({ status: 'error', message: 'Engine error. Please restart PhiliAI.' });
          },
          onclose: () => {
            setStatus({ status: 'completed', message: 'Session finalized. Captions ready.' });
          }
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (error) {
      console.error(error);
      setStatus({ status: 'error', message: 'Initialization failed.' });
    }
  };

  const stopSession = () => {
    if (sessionRef.current) {
      sessionRef.current.close();
      sessionRef.current = null;
    }
    if (videoRef.current) videoRef.current.pause();
    setStatus({ status: 'completed', message: 'Transcription saved.' });
  };

  const downloadSRT = () => {
    const srtContent = generateSRT(segments.map(s => ({
      start_seconds: s.start_seconds,
      end_seconds: s.end_seconds,
      text: s.text
    })));
    const blob = new Blob([srtContent], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `philiai_captions.srt`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
  };

  return (
    <div className="min-h-screen p-4 md:p-8 flex flex-col items-center max-w-7xl mx-auto">
      {/* Header */}
      <header className="w-full mb-12 flex flex-col md:flex-row items-center justify-between gap-6 bg-slate-900/40 p-8 rounded-[2.5rem] border border-slate-800 shadow-2xl">
        <div className="flex items-center gap-4">
          <div className="w-14 h-14 bg-indigo-600 rounded-3xl flex items-center justify-center shadow-2xl shadow-indigo-900/40">
            <svg className="w-8 h-8 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M13 10V3L4 14h7v7l9-11h-7z" />
            </svg>
          </div>
          <div>
            <h1 className="text-3xl font-black tracking-tight text-white">Phili<span className="text-indigo-400">AI</span> Live</h1>
            <p className="text-slate-500 text-xs font-bold uppercase tracking-[0.2em]">Neural Transcription Engine</p>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <div className={`px-5 py-2.5 rounded-2xl text-xs font-bold border flex items-center gap-2.5 ${
            status.status === 'streaming' ? 'bg-emerald-500/10 border-emerald-500/30 text-emerald-400' :
            status.status === 'connecting' ? 'bg-amber-500/10 border-amber-500/30 text-amber-400' :
            'bg-slate-800/50 border-slate-700 text-slate-500'
          }`}>
            <span className={`w-2.5 h-2.5 rounded-full ${status.status === 'streaming' ? 'bg-emerald-500 animate-pulse' : 'bg-slate-600'}`} />
            {status.status.toUpperCase()}
          </div>
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 w-full">
        {/* Main Interface */}
        <div className="lg:col-span-8 space-y-6">
          <div className="relative aspect-video bg-black rounded-[3rem] overflow-hidden border border-slate-800 shadow-2xl group ring-1 ring-slate-800">
            {videoUrl ? (
              <video ref={videoRef} src={videoUrl} className="w-full h-full object-contain" playsInline />
            ) : (
              <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-900/30 backdrop-blur-sm">
                <label className="cursor-pointer group flex flex-col items-center">
                  <div className="w-20 h-20 bg-slate-800 rounded-full flex items-center justify-center mb-6 group-hover:bg-indigo-600 transition-all shadow-xl">
                    <svg className="w-8 h-8 text-slate-400 group-hover:text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg>
                  </div>
                  <span className="text-slate-300 font-bold text-lg">Import Video Source</span>
                  <input type="file" className="hidden" accept="video/*" onChange={handleFileChange} />
                </label>
              </div>
            )}

            {/* Live Caption Overlay */}
            {status.status === 'streaming' && (
              <div className="absolute bottom-12 left-0 right-0 px-12 pointer-events-none">
                <div className="bg-black/80 backdrop-blur-xl px-8 py-4 rounded-3xl border border-white/5 text-center mx-auto max-w-3xl shadow-2xl">
                  <p className="text-xl md:text-3xl font-medium text-white drop-shadow-md">
                    {currentText || (segments.length > 0 ? segments[segments.length - 1].text : "PhiliAI is waiting for speech...")}
                  </p>
                </div>
              </div>
            )}
          </div>

          {/* Action Bar */}
          <div className="bg-slate-900/50 p-8 rounded-[2.5rem] border border-slate-800 flex flex-wrap gap-6 items-center justify-between">
            <div className="flex gap-4">
              {status.status !== 'streaming' ? (
                <button 
                  onClick={startLiveSession}
                  disabled={!videoUrl || status.status === 'connecting'}
                  className="bg-indigo-600 hover:bg-indigo-500 disabled:bg-slate-800 text-white px-10 py-5 rounded-[1.5rem] font-bold flex items-center gap-3 transition-all active:scale-95 shadow-xl shadow-indigo-900/30"
                >
                  <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" /></svg>
                  Start Transcription
                </button>
              ) : (
                <button 
                  onClick={stopSession}
                  className="bg-rose-600 hover:bg-rose-500 text-white px-10 py-5 rounded-[1.5rem] font-bold flex items-center gap-3 transition-all active:scale-95 shadow-xl shadow-rose-900/30"
                >
                  <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path d="M10 18a8 8 0 100-16 8 8 0 000 16zM8 7a1 1 0 00-1 1v4a1 1 0 001 1h4a1 1 0 001-1V8a1 1 0 00-1-1H8z" /></svg>
                  Finalize Stream
                </button>
              )}
            </div>

            <button 
              onClick={downloadSRT}
              disabled={segments.length === 0}
              className="bg-slate-800 hover:bg-slate-700 disabled:opacity-20 disabled:cursor-not-allowed text-slate-300 px-8 py-5 rounded-[1.5rem] font-bold border border-slate-700 flex items-center gap-3 transition-all"
            >
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
              Export Captions
            </button>
          </div>
        </div>

        {/* Live History Sidebar */}
        <div className="lg:col-span-4 flex flex-col h-[700px] lg:h-auto">
          <div className="bg-slate-900/60 rounded-[3rem] border border-slate-800 flex flex-col h-full shadow-2xl overflow-hidden">
            <div className="p-8 border-b border-slate-800">
              <h3 className="text-xl font-bold text-white flex items-center gap-3">
                <svg className="w-6 h-6 text-indigo-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
                Transcription Feed
              </h3>
            </div>

            <div className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar bg-slate-950/20">
              {segments.length === 0 && !currentText && (
                <div className="h-full flex flex-col items-center justify-center text-center p-8 opacity-20">
                  <svg className="w-16 h-16 mb-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1" d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" /></svg>
                  <p className="text-sm font-medium">History is empty. PhiliAI will populate this list as the stream processes.</p>
                </div>
              )}

              {segments.map((seg) => (
                <div key={seg.id} className="animate-in fade-in slide-in-from-bottom-4 duration-500">
                  <div className="bg-slate-800/30 p-6 rounded-[2rem] border border-slate-700/30 hover:bg-slate-800/50 transition-all group">
                    <div className="flex justify-between items-center mb-3">
                      <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">SEGMENT {seg.id}</span>
                      <span className="text-[10px] font-mono text-indigo-400 bg-indigo-500/10 px-2 py-1 rounded-lg border border-indigo-500/20">{seg.start_seconds.toFixed(2)}s</span>
                    </div>
                    <p className="text-slate-300 text-sm leading-relaxed font-medium">{seg.text}</p>
                  </div>
                </div>
              ))}

              {currentText && (
                <div className="bg-indigo-600/5 p-6 rounded-[2rem] border border-indigo-500/10 animate-pulse">
                  <div className="flex items-center gap-3 mb-3">
                    <span className="w-2 h-2 rounded-full bg-indigo-500" />
                    <span className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">Processing</span>
                  </div>
                  <p className="text-indigo-200/70 text-sm italic">{currentText}...</p>
                </div>
              )}

              <div ref={transcriptEndRef} />
            </div>

            <div className="p-6 bg-slate-900 border-t border-slate-800 text-center">
              <span className="text-[10px] text-slate-600 font-bold uppercase tracking-[0.3em]">
                PhiliAI Engine v2.5
              </span>
            </div>
          </div>
        </div>
      </div>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.05); border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: rgba(255,255,255,0.1); }
      `}</style>
