export async function blobToBase64(blob: Blob): Promise<string> {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = (reader.result as string).split(',')[1];
      resolve(base64String);
    };
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
}

// Keeping these for potential PCM needs, but chunked approach uses standard blobs
export function encode(bytes: Uint8Array): string {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from '@google/genai';
import { blobToBase64 } from './utils/audioUtils';
import { generateSRT } from './utils/timeFormatter';
import { ProcessingState, CaptionSegment } from './types';

const App: React.FC = () => {
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [status, setStatus] = useState<ProcessingState>({
    status: 'idle',
    message: 'Upload a video to begin high-accuracy translation with PhilipAI.'
  });
  const [segments, setSegments] = useState<CaptionSegment[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);

  const videoRef = useRef<HTMLVideoElement>(null);
  const audioCtxRef = useRef<AudioContext | null>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const segmentsRef = useRef<CaptionSegment[]>([]);
  const transcriptEndRef = useRef<HTMLDivElement>(null);
  const lastChunkTimeRef = useRef(0);

  useEffect(() => {
    transcriptEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [segments]);

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      setVideoUrl(URL.createObjectURL(file));
      setSegments([]);
      segmentsRef.current = [];
      setStatus({ status: 'idle', message: 'Video source imported. Neural engine ready.' });
    }
  };

  const processAudioChunk = async (blob: Blob, startTime: number, endTime: number) => {
    try {
      const base64Data = await blobToBase64(blob);
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [
          {
            parts: [
              {
                inlineData: {
                  mimeType: blob.type || 'audio/webm',
                  data: base64Data
                }
              },
              {
                text: "You are PhilipAI. Transcribe this audio clip and translate it perfectly into fluent English. Return ONLY the translation text. If there is no speech, return an empty string. Maintain the tone and context of the video."
              }
            ]
          }
        ],
        config: {
          temperature: 0.1, // Low temperature for higher accuracy/consistency
        }
      });

      const text = response.text?.trim();
      if (text) {
        const newSegment: CaptionSegment = {
          id: segmentsRef.current.length + 1,
          start_seconds: startTime,
          end_seconds: endTime,
          text: text
        };
        segmentsRef.current = [...segmentsRef.current, newSegment];
        setSegments([...segmentsRef.current]);
      }
    } catch (error: any) {
      console.error("Transcription Error:", error);
      if (error.message?.includes("unavailable")) {
        setStatus({ status: 'error', message: 'Gemini Engine is saturated. Retrying next chunk...' });
      }
    }
  };

  const startEngine = async () => {
    if (!videoRef.current) return;

    try {
      setIsProcessing(true);
      setStatus({ status: 'streaming', message: 'PhilipAI Engine Active: Processing neural chunks...' });

      audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
      const source = audioCtxRef.current.createMediaElementSource(videoRef.current);
      const destination = audioCtxRef.current.createMediaStreamDestination();

      source.connect(destination);
      source.connect(audioCtxRef.current.destination); // For local playback

      const recorder = new MediaRecorder(destination.stream);
      mediaRecorderRef.current = recorder;

      recorder.ondataavailable = async (e) => {
        if (e.data.size > 0) {
          const startTime = lastChunkTimeRef.current;
          const endTime = videoRef.current?.currentTime || startTime + 8;
          lastChunkTimeRef.current = endTime;

          await processAudioChunk(e.data, startTime, endTime);
        }
      };

      // Set chunk interval to 8 seconds for optimal context vs latency
      recorder.start(8000); 
      videoRef.current.play();
      lastChunkTimeRef.current = videoRef.current.currentTime;

    } catch (error) {
      console.error(error);
      setIsProcessing(false);
      setStatus({ status: 'error', message: 'Failed to initialize PhilipAI engine.' });
    }
  };

  const stopEngine = () => {
    if (mediaRecorderRef.current) {
      mediaRecorderRef.current.stop();
    }
    if (videoRef.current) videoRef.current.pause();
    setIsProcessing(false);
    setStatus({ status: 'completed', message: 'Processing finished. Ready for export.' });
  };

  const downloadSRT = () => {
    const srtContent = generateSRT(segments);
    const blob = new Blob([srtContent], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `PhilipAI_Captions.srt`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
  };

  return (
    <div className="min-h-screen p-4 md:p-8 flex flex-col items-center max-w-7xl mx-auto bg-[#020617] selection:bg-indigo-500/30">
      {/* Header */}
      <header className="w-full mb-8 flex flex-col md:flex-row items-center justify-between gap-6 bg-slate-900/40 p-8 rounded-[2.5rem] border border-slate-800 shadow-2xl backdrop-blur-md">
        <div className="flex items-center gap-5">
          <div className="w-16 h-16 bg-gradient-to-br from-indigo-500 to-purple-600 rounded-3xl flex items-center justify-center shadow-2xl shadow-indigo-900/40 transform hover:rotate-6 transition-transform">
            <svg className="w-9 h-9 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M13 10V3L4 14h7v7l9-11h-7z" />
            </svg>
          </div>
          <div>
            <h1 className="text-3xl font-black tracking-tight text-white">Philip<span className="text-indigo-400">AI</span> <span className="text-slate-500 font-light">Pro</span></h1>
            <p className="text-slate-500 text-xs font-bold uppercase tracking-[0.3em] flex items-center gap-2">
              <span className="w-2 h-2 rounded-full bg-indigo-500 animate-pulse" />
              High-Accuracy Neural Engine
            </p>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <div className={`px-6 py-3 rounded-2xl text-xs font-black border flex items-center gap-3 transition-colors ${
            isProcessing ? 'bg-indigo-500/10 border-indigo-500/30 text-indigo-400' :
            status.status === 'completed' ? 'bg-emerald-500/10 border-emerald-500/30 text-emerald-400' :
            'bg-slate-800/50 border-slate-700 text-slate-500'
          }`}>
            <span className={`w-2.5 h-2.5 rounded-full ${isProcessing ? 'bg-indigo-500 animate-ping' : 'bg-slate-600'}`} />
            {status.status.toUpperCase()}
          </div>
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 w-full">
        {/* Main Interface */}
        <div className="lg:col-span-8 space-y-6">
          <div className="relative aspect-video bg-black rounded-[3rem] overflow-hidden border border-slate-800 shadow-2xl group ring-1 ring-white/5 shadow-indigo-500/5">
            {videoUrl ? (
              <video ref={videoRef} src={videoUrl} className="w-full h-full object-contain" playsInline crossOrigin="anonymous" />
            ) : (
              <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-900/20 backdrop-blur-sm">
                <label className="cursor-pointer group flex flex-col items-center">
                  <div className="w-24 h-24 bg-slate-800 rounded-[2rem] flex items-center justify-center mb-8 group-hover:bg-indigo-600 transition-all shadow-2xl group-hover:scale-110">
                    <svg className="w-10 h-10 text-slate-400 group-hover:text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg>
                  </div>
                  <span className="text-slate-400 font-bold text-xl group-hover:text-white transition-colors">Import Video Source</span>
                  <input type="file" className="hidden" accept="video/*" onChange={handleFileChange} />
                </label>
              </div>
            )}

            {/* Subtitle Display */}
            {isProcessing && segments.length > 0 && (
              <div className="absolute bottom-16 left-0 right-0 px-16 pointer-events-none animate-in fade-in slide-in-from-bottom-4">
                <div className="bg-black/80 backdrop-blur-2xl px-10 py-5 rounded-[2.5rem] border border-white/10 text-center mx-auto max-w-4xl shadow-2xl">
                  <p className="text-xl md:text-3xl font-semibold text-white drop-shadow-xl leading-relaxed">
                    {segments[segments.length - 1].text}
                  </p>
                </div>
              </div>
            )}
          </div>

          {/* Action Bar */}
          <div className="bg-slate-900/50 p-8 rounded-[2.5rem] border border-slate-800 flex flex-wrap gap-6 items-center justify-between backdrop-blur-sm">
            <div className="flex gap-4">
              {!isProcessing ? (
                <button 
                  onClick={startEngine}
                  disabled={!videoUrl}
                  className="bg-indigo-600 hover:bg-indigo-500 disabled:bg-slate-800 disabled:opacity-50 text-white px-12 py-5 rounded-[1.8rem] font-black text-lg flex items-center gap-4 transition-all active:scale-95 shadow-2xl shadow-indigo-900/40"
                >
                  <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" /></svg>
                  Analyze Video
                </button>
              ) : (
                <button 
                  onClick={stopEngine}
                  className="bg-rose-600 hover:bg-rose-500 text-white px-12 py-5 rounded-[1.8rem] font-black text-lg flex items-center gap-4 transition-all active:scale-95 shadow-2xl shadow-rose-900/40"
                >
                  <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path d="M10 18a8 8 0 100-16 8 8 0 000 16zM8 7a1 1 0 00-1 1v4a1 1 0 001 1h4a1 1 0 001-1V8a1 1 0 00-1-1H8z" /></svg>
                  Stop Analysis
                </button>
              )}
            </div>

            <button 
              onClick={downloadSRT}
              disabled={segments.length === 0}
              className="bg-slate-800 hover:bg-slate-700 disabled:opacity-10 disabled:cursor-not-allowed text-slate-200 px-8 py-5 rounded-[1.8rem] font-bold border border-slate-700 flex items-center gap-4 transition-all shadow-xl"
            >
              <svg className="w-6 h-6 text-indigo-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
              Export SRT Captions
            </button>
          </div>

          <div className="text-center">
            <p className={`text-sm font-medium transition-all ${isProcessing ? 'text-indigo-400 animate-pulse' : 'text-slate-600'}`}>
              {status.message}
            </p>
          </div>
        </div>

        {/* Neural Feed Sidebar */}
        <div className="lg:col-span-4 flex flex-col h-[750px] lg:h-auto">
          <div className="bg-slate-900/40 rounded-[3rem] border border-slate-800/60 flex flex-col h-full shadow-2xl overflow-hidden backdrop-blur-md">
            <div className="p-8 border-b border-slate-800/60 flex items-center justify-between">
              <h3 className="text-xl font-black text-white flex items-center gap-4">
                <div className="w-2 h-8 bg-indigo-500 rounded-full" />
                Neural Feed
              </h3>
              <span className="bg-indigo-500/10 text-indigo-400 px-3 py-1 rounded-full text-[10px] font-black border border-indigo-500/20">
                {segments.length} LOGS
              </span>
            </div>

            <div className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar bg-slate-950/20">
              {segments.length === 0 && (
                <div className="h-full flex flex-col items-center justify-center text-center p-8 opacity-10">
                  <svg className="w-20 h-20 mb-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
                  <p className="text-lg font-bold">Waiting for input...</p>
                </div>
              )}

              {segments.map((seg) => (
                <div key={seg.id} className="animate-in fade-in slide-in-from-bottom-8 duration-700">
                  <div className="bg-slate-800/20 p-6 rounded-[2.2rem] border border-white/5 hover:border-indigo-500/30 hover:bg-slate-800/40 transition-all group">
                    <div className="flex justify-between items-center mb-4">
                      <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest bg-slate-800/50 px-3 py-1 rounded-lg">SEGMENT {seg.id.toString().padStart(2, '0')}</span>
                      <div className="flex items-center gap-2">
                         <span className="text-[10px] font-mono text-indigo-400 font-bold bg-indigo-500/10 px-2.5 py-1 rounded-lg border border-indigo-500/20">
                           {Math.floor(seg.start_seconds / 60)}:{(seg.start_seconds % 60).toFixed(0).padStart(2, '0')}
                         </span>
                      </div>
                    </div>
                    <p className="text-slate-300 text-sm leading-relaxed font-medium group-hover:text-white transition-colors">
                      {seg.text}
                    </p>
                  </div>
                </div>
              ))}
