      for (let i = 0; i < chunks.length; i++) {
        setStatus({ status: 'streaming', message: `Analyzing Neural Batch ${i + 1} of ${chunks.length}...` });
        const success = await processBatchWithRetry(chunks[i].buffer, chunks[i].offset, i);
        if (!success) {
          throw new Error(`Critical failure in batch ${i + 1}`);
