            <svg className="w-9 h-9 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M13 10V3L4 14h7v7l9-11h-7z" />
            </svg>
          </div>
          <div>
            <div className="flex items-center gap-3">
              <h1 className="text-4xl font-black tracking-tighter text-white">Philip<span className="text-indigo-400">AI</span></h1>
              <span className="bg-indigo-500 text-[10px] font-black px-2.5 py-1 rounded-lg text-white tracking-[0.2em] border border-white/5 uppercase shadow-lg shadow-indigo-500/20">PRO</span>
            </div>
            <p className="text-slate-500 text-xs font-bold uppercase tracking-[0.4em] mt-2 flex items-center gap-2">
              Deep-Core Translation Engine
