            <div className="w-48 h-1.5 bg-slate-800 rounded-full overflow-hidden border border-white/5">
              <div className="h-full bg-indigo-500 transition-all duration-700 ease-out" style={{ width: `${progress}%` }} />
            </div>
          )}
        </div>
