export async function blobToBase64(blob: Blob): Promise<string> {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = (reader.result as string).split(',')[1];
      resolve(base64String);
    };
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
}

/**
 * Downsamples an AudioBuffer to 16kHz Mono.
 * This is the industry standard for high-accuracy AI transcription.
 */
export async function downsampleAudioBuffer(buffer: AudioBuffer, targetSampleRate: number = 16000): Promise<AudioBuffer> {
  const offlineCtx = new OfflineAudioContext(1, buffer.duration * targetSampleRate, targetSampleRate);
  const source = offlineCtx.createBufferSource();
  source.buffer = buffer;
  source.connect(offlineCtx.destination);
  source.start();
  return await offlineCtx.startRendering();
}

/**
 * Encodes an AudioBuffer to a WAV blob (16-bit PCM).
 */
export function audioBufferToWav(buffer: AudioBuffer): Blob {
  const numOfChan = 1; // Force Mono
  const length = buffer.length * 2 + 44;
  const bufferArr = new ArrayBuffer(length);
  const view = new DataView(bufferArr);
  const channels = [buffer.getChannelData(0)];
  let pos = 0;

  const setUint16 = (data: number) => { view.setUint16(pos, data, true); pos += 2; };
  const setUint32 = (data: number) => { view.setUint32(pos, data, true); pos += 4; };

  setUint32(0x46464952); // "RIFF"
  setUint32(length - 8);
  setUint32(0x45564157); // "WAVE"
  setUint32(0x20746d66); // "fmt "
  setUint32(16);
  setUint16(1); // PCM
  setUint16(numOfChan);
  setUint32(buffer.sampleRate);
  setUint32(buffer.sampleRate * 2 * numOfChan);
  setUint16(numOfChan * 2);
  setUint16(16);
  setUint32(0x61746164); // "data"
  setUint32(length - pos - 4);

  let offset = 0;
  while (pos < length) {
    let sample = Math.max(-1, Math.min(1, channels[0][offset]));
    sample = (sample < 0 ? sample * 0x8000 : sample * 0x7fff);
    view.setInt16(pos, sample, true);
    pos += 2;
    offset++;
  }

  return new Blob([bufferArr], { type: 'audio/wav' });
}

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI, Type } from '@google/genai';
import { blobToBase64, audioBufferToWav, downsampleAudioBuffer } from './utils/audioUtils';
import { generateSRT } from './utils/timeFormatter';
import { ProcessingState, CaptionSegment } from './types';

// Neural Model Pool for Failover - Hierarchical order
const MODEL_POOL = [
  { id: 'gemini-3-flash-preview', label: 'Flash 3.0', description: 'Optimal Balanced Core' },
  { id: 'gemini-2.5-flash-native-audio-preview-12-2025', label: 'Audio Native 2.5', description: 'Waveform Specialist' },
  { id: 'gemini-3-pro-preview', label: 'Pro 3.0', description: 'Advanced Reasoning Logic' },
  { id: 'gemini-flash-lite-latest', label: 'Flash Lite', description: 'High-Throughput Fallback' }
];

const CHUNK_DURATION = 300; // 5-minute segments
const REQUEST_GAP = 5000; // 5s gap between batches to prevent 429

const App: React.FC = () => {
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [videoFile, setVideoFile] = useState<File | null>(null);
  const [status, setStatus] = useState<ProcessingState>({
    status: 'idle',
    message: 'Multi-Engine System Ready.'
  });
  const [segments, setSegments] = useState<CaptionSegment[]>([]);
  const [progress, setProgress] = useState(0);
  const [isProcessing, setIsProcessing] = useState(false);
  const [activeModelIndex, setActiveModelIndex] = useState(0);
  const [cooldown, setCooldown] = useState(0);

  const videoRef = useRef<HTMLVideoElement>(null);
  const transcriptEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    transcriptEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [segments]);

  useEffect(() => {
    if (cooldown > 0) {
      const timer = setTimeout(() => setCooldown(cooldown - 1), 1000);
      return () => clearTimeout(timer);
    }
  }, [cooldown]);

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      setVideoFile(file);
      setVideoUrl(URL.createObjectURL(file));
      setSegments([]);
      setProgress(0);
      setStatus({ status: 'idle', message: 'Video Imported. Engines Warm.' });
    }
  };

  const processBatchWithFailover = async (
    audioBuffer: AudioBuffer, 
    offset: number, 
    batchIndex: number, 
    poolIndex: number = 0,
    retryCount: number = 0
  ): Promise<boolean> => {
    if (poolIndex >= MODEL_POOL.length) {
      return false;
    }

    const currentModel = MODEL_POOL[poolIndex];
    setActiveModelIndex(poolIndex);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

      // Resample to 16kHz for perfect AI balance
      const optimizedBuffer = await downsampleAudioBuffer(audioBuffer, 16000);
      const wavBlob = audioBufferToWav(optimizedBuffer);
      const base64Data = await blobToBase64(wavBlob);

      setStatus({ 
        status: 'streaming', 
        message: `Analyzing Batch ${batchIndex + 1} with ${currentModel.label}...` 
      });

      const response = await ai.models.generateContent({
        model: currentModel.id,
        contents: [{
          parts: [
            { inlineData: { mimeType: 'audio/wav', data: base64Data } },
            { text: "Precisely transcribe and translate this audio into natural English. Return a JSON array of objects with: start (float seconds), end (float seconds), text (English string)." }
          ]
        }],
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                start: { type: Type.NUMBER },
                end: { type: Type.NUMBER },
                text: { type: Type.STRING }
              },
              required: ['start', 'end', 'text']
            }
          }
        }
      });

      const data = JSON.parse(response.text || "[]");
      const adjustedSegments = data.map((s: any, i: number) => ({
        id: Date.now() + Math.random() + i,
        start_seconds: s.start + offset,
        end_seconds: s.end + offset,
        text: s.text
      }));

      setSegments(prev => {
        const next = [...prev, ...adjustedSegments].sort((a, b) => a.start_seconds - b.start_seconds);
        return next;
      });

      return true;
    } catch (error: any) {
      console.error(`Core Error (${currentModel.label}):`, error);
      const isQuota = error.message?.includes("429") || error.message?.includes("RESOURCE_EXHAUSTED");

      if (isQuota && poolIndex < MODEL_POOL.length - 1) {
        setStatus({ status: 'connecting', message: `Quota Over. Switching to ${MODEL_POOL[poolIndex + 1].label}...` });
        setCooldown(10);
        await new Promise(r => setTimeout(r, 10000));
        return processBatchWithFailover(audioBuffer, offset, batchIndex, poolIndex + 1, 0);
      } else if (retryCount < 2) {
        setStatus({ status: 'connecting', message: `Sync Failure. Retrying Core ${currentModel.label}...` });
        await new Promise(r => setTimeout(r, 5000));
        return processBatchWithFailover(audioBuffer, offset, batchIndex, poolIndex, retryCount + 1);
      }

      return false;
    }
  };

  const startProcessing = async () => {
    if (!videoFile || isProcessing) return;

    try {
      setIsProcessing(true);
      setStatus({ status: 'connecting', message: 'Extracting High-Fidelity Audio...' });

      const arrayBuffer = await videoFile.arrayBuffer();
      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
      const decodedBuffer = await audioCtx.decodeAudioData(arrayBuffer);

      const duration = decodedBuffer.duration;
      const numChunks = Math.ceil(duration / CHUNK_DURATION);

      for (let i = 0; i < numChunks; i++) {
        const start = i * CHUNK_DURATION;
        const end = Math.min(start + CHUNK_DURATION, duration);
        const frameStart = Math.floor(start * decodedBuffer.sampleRate);
        const frameEnd = Math.floor(end * decodedBuffer.sampleRate);

        const chunkBuffer = audioCtx.createBuffer(1, frameEnd - frameStart, decodedBuffer.sampleRate);
        chunkBuffer.copyToChannel(decodedBuffer.getChannelData(0).subarray(frameStart, frameEnd), 0);

        const success = await processBatchWithFailover(chunkBuffer, start, i, 0);

        if (!success) throw new Error("All Neural Cores reported exhaustion. Try again in 60s.");

        setProgress(Math.round(((i + 1) / numChunks) * 100));

        if (i < numChunks - 1) {
          setStatus({ status: 'connecting', message: 'Waiting for Quota Reset (5s)...' });
          await new Promise(r => setTimeout(r, REQUEST_GAP));
        }
      }

      setStatus({ status: 'completed', message: 'All Segments Synced & Translated.' });
      setIsProcessing(false);
    } catch (error: any) {
      setIsProcessing(false);
      setStatus({ status: 'error', message: error.message });
    }
  };

  const downloadSRT = () => {
    const srt = generateSRT(segments);
    const blob = new Blob([srt], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `PhilipAI_Captions.srt`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
  };

  return (
    <div className="min-h-screen p-4 md:p-10 flex flex-col gap-8 max-w-7xl mx-auto">
      {/* Header / Engine Status */}
      <header className="flex flex-col lg:flex-row items-stretch gap-6">
        <div className="flex-1 glass-panel p-8 rounded-[2.5rem] flex items-center gap-6">
          <div className="w-16 h-16 bg-emerald-500 rounded-2xl flex items-center justify-center shadow-[0_0_30px_rgba(16,185,129,0.2)]">
            <svg className="w-10 h-10 text-slate-950" fill="currentColor" viewBox="0 0 24 24">
              <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 14h-2v-2h2v2zm0-4h-2V7h2v5z"/>
            </svg>
          </div>
          <div>
            <h1 className="text-4xl font-black tracking-tighter text-white">Philip<span className="text-emerald-500">AI</span></h1>
            <p className="text-[10px] font-black uppercase tracking-[0.4em] text-slate-500 mt-1">Multi-Engine Failover</p>
          </div>
        </div>

        <div className="flex-[2] glass-panel p-6 rounded-[2.5rem] flex flex-wrap items-center justify-around gap-4">
          {MODEL_POOL.map((model, idx) => (
            <div key={model.id} className={`flex items-center gap-3 px-4 py-2 rounded-xl border transition-all ${
              activeModelIndex === idx && isProcessing ? 'bg-emerald-500/10 border-emerald-500/50 shadow-lg shadow-emerald-500/10 scale-105' : 'bg-slate-900/40 border-white/5 opacity-40'
            }`}>
              <div className={`w-2 h-2 rounded-full ${activeModelIndex === idx && isProcessing ? 'bg-emerald-500 animate-pulse' : 'bg-slate-600'}`} />
              <div>
                <p className={`text-[10px] font-black uppercase ${activeModelIndex === idx && isProcessing ? 'text-emerald-500' : 'text-slate-400'}`}>{model.label}</p>
                <p className="text-[8px] text-slate-600 truncate max-w-[80px]">{model.description}</p>
              </div>
            </div>
          ))}
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Workspace */}
        <div className="lg:col-span-8 flex flex-col gap-6">
          <div className="aspect-video bg-black rounded-[3rem] overflow-hidden border border-white/5 shadow-2xl relative ring-1 ring-white/10 group">
            {videoUrl ? (
              <video src={videoUrl} controls className="w-full h-full object-contain" />
            ) : (
              <label className="absolute inset-0 flex flex-col items-center justify-center cursor-pointer hover:bg-slate-900/50 transition-all">
                <div className="w-20 h-20 bg-slate-900 rounded-[2rem] flex items-center justify-center mb-4 border border-white/10 group-hover:border-emerald-500/50 transition-all duration-500">
                  <svg className="w-8 h-8 text-slate-500 group-hover:text-emerald-500 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg>
                </div>
                <span className="text-slate-500 font-bold uppercase tracking-widest text-xs">Import Local Source</span>
                <input type="file" className="hidden" accept="video/*" onChange={handleFileChange} />
              </label>
            )}

            {isProcessing && (
              <div className="absolute top-6 right-6 px-4 py-2 bg-slate-950/80 backdrop-blur-md rounded-xl border border-white/10 text-[10px] font-black text-emerald-500 flex items-center gap-2">
                <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-ping" />
                LIVE NEURAL LINK: {progress}%
              </div>
            )}
          </div>

          <div className="glass-panel p-10 rounded-[3rem] flex flex-col md:flex-row items-center justify-between gap-8">
            <div className="space-y-1">
              <span className="text-emerald-500 text-[10px] font-black uppercase tracking-widest">Active Sequence</span>
              <h2 className="text-2xl font-bold text-white tracking-tight">Caption Processing</h2>
              <p className="text-slate-500 text-sm">Automated translation to English SRT format.</p>
            </div>
            <div className="flex gap-4 w-full md:w-auto">
              <button 
                onClick={startProcessing}
                disabled={!videoFile || isProcessing}
                className="flex-1 md:flex-none bg-emerald-500 hover:bg-emerald-400 disabled:opacity-20 text-slate-950 font-black px-12 py-5 rounded-2xl transition-all shadow-[0_15px_40px_-10px_rgba(16,185,129,0.3)] active:scale-95"
              >
                {isProcessing ? `Processing...` : 'Run Pipeline'}
              </button>
              <button 
                onClick={downloadSRT}
                disabled={segments.length === 0}
                className="flex-1 md:flex-none bg-slate-800 hover:bg-slate-700 disabled:opacity-20 text-white font-bold px-10 py-5 rounded-2xl border border-white/10 transition-all"
              >
                Export SRT
              </button>
            </div>
          </div>

          <div className="text-center px-10">
            <p className="text-[10px] text-slate-600 font-black uppercase tracking-[0.4em] animate-pulse">
              {status.message} {cooldown > 0 && `(Cooling ${cooldown}s)`}
            </p>
          </div>
        </div>

        {/* Sidebar Stream */}
        <div className="lg:col-span-4 h-[700px] lg:h-auto">
          <div className="glass-panel rounded-[3.5rem] h-full flex flex-col shadow-2xl overflow-hidden ring-1 ring-white/10">
            <div className="p-8 border-b border-white/5 bg-slate-950/20">
              <h3 className="text-xs font-black uppercase tracking-widest text-white flex items-center justify-between">
                Transcription Stream
                <span className="text-emerald-500 bg-emerald-500/10 px-3 py-1 rounded-lg text-[9px]">{segments.length} UNITS</span>
              </h3>
            </div>

            <div className="flex-1 overflow-y-auto p-6 space-y-4 custom-scrollbar">
              {segments.length === 0 && !isProcessing && (
                <div className="h-full flex flex-col items-center justify-center text-center opacity-20 italic text-xs space-y-2">
                  <div className="w-12 h-12 border-2 border-slate-700 border-dashed rounded-full mb-2" />
                  <p>Awaiting Signal Extraction</p>
                </div>
              )}
              {segments.map((seg, idx) => (
                <div key={seg.id} className="bg-slate-800/30 p-5 rounded-2xl border border-white/5 hover:border-emerald-500/30 transition-all group animate-in fade-in slide-in-from-bottom-2 duration-300">
                  <div className="flex justify-between items-center mb-2">
                    <span className="text-[9px] font-black text-slate-600">UNIT {idx + 1}</span>
                    <span className="text-[9px] font-mono text-emerald-500 bg-emerald-500/5 px-2 py-1 rounded-md">
                      {Math.floor(seg.start_seconds / 60)}:{(seg.start_seconds % 60).toFixed(1).padStart(4, '0')}
                    </span>
                  </div>
                  <p className="text-slate-300 text-xs leading-relaxed font-medium group-hover:text-white transition-colors">
                    {seg.text}
                  </p>
                </div>
              ))}
              <div ref={transcriptEndRef} />
            </div>

            <div className="p-4 bg-slate-950/50 border-t border-white/5">
              <div className="w-full h-1 bg-slate-800 rounded-full overflow-hidden">
                <div className={`h-full bg-emerald-500 transition-all duration-1000 ${isProcessing ? 'animate-pulse' : ''}`} style={{ width: `${progress}%` }} />
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;

export interface CaptionSegment {
  id: number;
  start_seconds: number;
  end_seconds: number;
  text: string;
}

export interface ProcessingState {
  status: 'idle' | 'connecting' | 'streaming' | 'completed' | 'error';
  message: string;
}

export interface ModelMetric {
  success: number;
  fail: number;
  avgLatency: number;
  totalLatency: number;
}

export interface AnalyticsData {
  totalRequests: number;
  successfulRequests: number;
  failoverEvents: number;
  startTime: number | null;
  endTime: number | null;
  modelMetrics: Record<string, ModelMetric>;
}

export interface CaptionSegment {
  id: number;
  start_seconds: number;
  end_seconds: number;
  text: string;
}

export interface ProcessingState {
  status: 'idle' | 'connecting' | 'streaming' | 'completed' | 'error';
  message: string;
}

export interface ModelMetric {
  success: number;
  fail: number;
  avgLatency: number;
  totalLatency: number;
}

export interface AnalyticsData {
  totalRequests: number;
  successfulRequests: number;
  failoverEvents: number;
  startTime: number | null;
  endTime: number | null;
  modelMetrics: Record<string, ModelMetric>;
}

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { GoogleGenAI, Type } from '@google/genai';
import { blobToBase64, audioBufferToWav, downsampleAudioBuffer } from './utils/audioUtils';
import { generateSRT } from './utils/timeFormatter';
import { ProcessingState, CaptionSegment, AnalyticsData, ModelMetric } from './types';

// Neural Model Pool for Failover - Hierarchical order
const MODEL_POOL = [
  { id: 'gemini-3-flash-preview', label: 'Flash 3.0', description: 'Optimal Balanced Core' },
  { id: 'gemini-2.5-flash-native-audio-preview-12-2025', label: 'Audio Native 2.5', description: 'Waveform Specialist' },
  { id: 'gemini-3-pro-preview', label: 'Pro 3.0', description: 'Advanced Reasoning Logic' },
  { id: 'gemini-flash-lite-latest', label: 'Flash Lite', description: 'High-Throughput Fallback' }
];

const CHUNK_DURATION = 300; // 5-minute segments
const REQUEST_GAP = 5000; // 5s gap between batches to prevent 429

const INITIAL_ANALYTICS: AnalyticsData = {
  totalRequests: 0,
  successfulRequests: 0,
  failoverEvents: 0,
  startTime: null,
  endTime: null,
  modelMetrics: MODEL_POOL.reduce((acc, model) => {
    acc[model.id] = { success: 0, fail: 0, avgLatency: 0, totalLatency: 0 };
    return acc;
  }, {} as Record<string, ModelMetric>)
};

const App: React.FC = () => {
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [videoFile, setVideoFile] = useState<File | null>(null);
  const [status, setStatus] = useState<ProcessingState>({
    status: 'idle',
    message: 'Multi-Engine System Ready.'
  });
  const [segments, setSegments] = useState<CaptionSegment[]>([]);
  const [progress, setProgress] = useState(0);
  const [isProcessing, setIsProcessing] = useState(false);
  const [activeModelIndex, setActiveModelIndex] = useState(0);
  const [cooldown, setCooldown] = useState(0);
  const [analytics, setAnalytics] = useState<AnalyticsData>(INITIAL_ANALYTICS);

  const transcriptEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    transcriptEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [segments]);

  useEffect(() => {
    if (cooldown > 0) {
      const timer = setTimeout(() => setCooldown(cooldown - 1), 1000);
      return () => clearTimeout(timer);
    }
  }, [cooldown]);

  const updateAnalytics = (modelId: string, latency: number, success: boolean, failover: boolean = false) => {
    setAnalytics(prev => {
      const modelMetric = prev.modelMetrics[modelId];
      const newSuccess = modelMetric.success + (success ? 1 : 0);
      const newFail = modelMetric.fail + (success ? 0 : 1);
      const newTotalLatency = modelMetric.totalLatency + latency;

      return {
        ...prev,
        totalRequests: prev.totalRequests + 1,
        successfulRequests: prev.successfulRequests + (success ? 1 : 0),
        failoverEvents: prev.failoverEvents + (failover ? 1 : 0),
        modelMetrics: {
          ...prev.modelMetrics,
          [modelId]: {
            success: newSuccess,
            fail: newFail,
            totalLatency: newTotalLatency,
            avgLatency: newTotalLatency / (newSuccess + newFail)
          }
        }
      };
    });
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      setVideoFile(file);
      setVideoUrl(URL.createObjectURL(file));
      setSegments([]);
      setProgress(0);
      setAnalytics(INITIAL_ANALYTICS);
      setStatus({ status: 'idle', message: 'Video Imported. Engines Warm.' });
    }
  };

  const processBatchWithFailover = async (
    audioBuffer: AudioBuffer, 
    offset: number, 
    batchIndex: number, 
    poolIndex: number = 0,
    retryCount: number = 0
  ): Promise<boolean> => {
    if (poolIndex >= MODEL_POOL.length) {
      return false;
    }

    const currentModel = MODEL_POOL[poolIndex];
    setActiveModelIndex(poolIndex);
    const requestStart = performance.now();

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

      const optimizedBuffer = await downsampleAudioBuffer(audioBuffer, 16000);
      const wavBlob = audioBufferToWav(optimizedBuffer);
      const base64Data = await blobToBase64(wavBlob);

      setStatus({ 
        status: 'streaming', 
        message: `Analyzing Batch ${batchIndex + 1} with ${currentModel.label}...` 
      });

      const response = await ai.models.generateContent({
        model: currentModel.id,
        contents: [{
          parts: [
            { inlineData: { mimeType: 'audio/wav', data: base64Data } },
            { text: "Precisely transcribe and translate this audio into natural English. Return a JSON array of objects with: start (float seconds), end (float seconds), text (English string)." }
          ]
        }],
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                start: { type: Type.NUMBER },
                end: { type: Type.NUMBER },
                text: { type: Type.STRING }
              },
              required: ['start', 'end', 'text']
            }
          }
        }
      });

      const latency = performance.now() - requestStart;
      updateAnalytics(currentModel.id, latency, true);

      const data = JSON.parse(response.text || "[]");
      const adjustedSegments = data.map((s: any, i: number) => ({
        id: Date.now() + Math.random() + i,
        start_seconds: s.start + offset,
        end_seconds: s.end + offset,
        text: s.text
      }));

      setSegments(prev => {
        const next = [...prev, ...adjustedSegments].sort((a, b) => a.start_seconds - b.start_seconds);
        return next;
      });

      return true;
    } catch (error: any) {
      const latency = performance.now() - requestStart;
      const isQuota = error.message?.includes("429") || error.message?.includes("RESOURCE_EXHAUSTED");

      updateAnalytics(currentModel.id, latency, false, isQuota);

      if (isQuota && poolIndex < MODEL_POOL.length - 1) {
        setStatus({ status: 'connecting', message: `Quota Over. Switching to ${MODEL_POOL[poolIndex + 1].label}...` });
        setCooldown(10);
        await new Promise(r => setTimeout(r, 10000));
        return processBatchWithFailover(audioBuffer, offset, batchIndex, poolIndex + 1, 0);
      } else if (retryCount < 2) {
        setStatus({ status: 'connecting', message: `Sync Failure. Retrying Core ${currentModel.label}...` });
        await new Promise(r => setTimeout(r, 5000));
        return processBatchWithFailover(audioBuffer, offset, batchIndex, poolIndex, retryCount + 1);
      }

      return false;
    }
  };

  const startProcessing = async () => {
    if (!videoFile || isProcessing) return;

    try {
      setIsProcessing(true);
      setAnalytics(prev => ({ ...prev, startTime: Date.now(), endTime: null }));
      setStatus({ status: 'connecting', message: 'Extracting High-Fidelity Audio...' });

      const arrayBuffer = await videoFile.arrayBuffer();
      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
      const decodedBuffer = await audioCtx.decodeAudioData(arrayBuffer);

      const duration = decodedBuffer.duration;
      const numChunks = Math.ceil(duration / CHUNK_DURATION);

      for (let i = 0; i < numChunks; i++) {
        const start = i * CHUNK_DURATION;
        const end = Math.min(start + CHUNK_DURATION, duration);
        const frameStart = Math.floor(start * decodedBuffer.sampleRate);
        const frameEnd = Math.floor(end * decodedBuffer.sampleRate);

        const chunkBuffer = audioCtx.createBuffer(1, frameEnd - frameStart, decodedBuffer.sampleRate);
        chunkBuffer.copyToChannel(decodedBuffer.getChannelData(0).subarray(frameStart, frameEnd), 0);

        const success = await processBatchWithFailover(chunkBuffer, start, i, 0);

        if (!success) throw new Error("All Neural Cores reported exhaustion. Try again in 60s.");

        setProgress(Math.round(((i + 1) / numChunks) * 100));

        if (i < numChunks - 1) {
          setStatus({ status: 'connecting', message: 'Waiting for Quota Reset (5s)...' });
          await new Promise(r => setTimeout(r, REQUEST_GAP));
        }
      }

      setAnalytics(prev => ({ ...prev, endTime: Date.now() }));
      setStatus({ status: 'completed', message: 'All Segments Synced & Translated.' });
      setIsProcessing(false);
    } catch (error: any) {
      setIsProcessing(false);
      setAnalytics(prev => ({ ...prev, endTime: Date.now() }));
      setStatus({ status: 'error', message: error.message });
    }
  };

  const downloadSRT = () => {
    const srt = generateSRT(segments);
    const blob = new Blob([srt], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `PhilipAI_Captions.srt`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
  };

  const globalSuccessRate = useMemo(() => {
    if (analytics.totalRequests === 0) return 0;
    return Math.round((analytics.successfulRequests / analytics.totalRequests) * 100);
  }, [analytics]);

  const totalTimeElapsed = useMemo(() => {
    if (!analytics.startTime) return '0s';
    const end = analytics.endTime || Date.now();
    const diff = (end - analytics.startTime) / 1000;
    return diff < 60 ? `${diff.toFixed(1)}s` : `${Math.floor(diff / 60)}m ${Math.floor(diff % 60)}s`;
  }, [analytics]);

  return (
    <div className="min-h-screen p-4 md:p-10 flex flex-col gap-8 max-w-7xl mx-auto">
      {/* Header / Engine Status */}
      <header className="flex flex-col lg:flex-row items-stretch gap-6">
        <div className="flex-1 glass-panel p-8 rounded-[2.5rem] flex items-center gap-6 shadow-xl ring-1 ring-white/5">
          <div className="w-16 h-16 bg-emerald-500 rounded-2xl flex items-center justify-center shadow-[0_0_30px_rgba(16,185,129,0.2)]">
            <svg className="w-10 h-10 text-slate-950" fill="currentColor" viewBox="0 0 24 24">
              <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 14h-2v-2h2v2zm0-4h-2V7h2v5z"/>
            </svg>
          </div>
          <div>
            <h1 className="text-4xl font-black tracking-tighter text-white">Philip<span className="text-emerald-500">AI</span></h1>
            <p className="text-[10px] font-black uppercase tracking-[0.4em] text-slate-500 mt-1">Intelligence Pipeline</p>
          </div>
        </div>

        <div className="flex-[2] glass-panel p-6 rounded-[2.5rem] flex flex-wrap items-center justify-around gap-4 shadow-xl ring-1 ring-white/5">
          {MODEL_POOL.map((model, idx) => (
            <div key={model.id} className={`flex items-center gap-3 px-4 py-2 rounded-xl border transition-all ${
              activeModelIndex === idx && isProcessing ? 'bg-emerald-500/10 border-emerald-500/50 shadow-lg shadow-emerald-500/10 scale-105' : 'bg-slate-900/40 border-white/5 opacity-40'
            }`}>
              <div className={`w-2 h-2 rounded-full ${activeModelIndex === idx && isProcessing ? 'bg-emerald-500 animate-pulse' : 'bg-slate-600'}`} />
              <div>
                <p className={`text-[10px] font-black uppercase ${activeModelIndex === idx && isProcessing ? 'text-emerald-500' : 'text-slate-400'}`}>{model.label}</p>
                <div className="flex items-center gap-2">
                   <p className="text-[8px] text-slate-600 truncate max-w-[80px]">{model.description}</p>
                   {analytics.modelMetrics[model.id].success > 0 && (
                     <span className="text-[7px] font-bold text-emerald-500/80">{(analytics.modelMetrics[model.id].avgLatency / 1000).toFixed(1)}s</span>
                   )}
                </div>
              </div>
            </div>
          ))}
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Workspace */}
        <div className="lg:col-span-8 flex flex-col gap-6">
          <div className="aspect-video bg-black rounded-[3rem] overflow-hidden border border-white/5 shadow-2xl relative ring-1 ring-white/10 group">
            {videoUrl ? (
              <video src={videoUrl} controls className="w-full h-full object-contain" />
            ) : (
              <label className="absolute inset-0 flex flex-col items-center justify-center cursor-pointer hover:bg-slate-900/50 transition-all">
                <div className="w-20 h-20 bg-slate-900 rounded-[2rem] flex items-center justify-center mb-4 border border-white/10 group-hover:border-emerald-500/50 transition-all duration-500">
                  <svg className="w-8 h-8 text-slate-500 group-hover:text-emerald-500 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg>
                </div>
                <span className="text-slate-500 font-bold uppercase tracking-widest text-xs">Import Local Source</span>
                <input type="file" className="hidden" accept="video/*" onChange={handleFileChange} />
              </label>
            )}

            {isProcessing && (
              <div className="absolute top-6 right-6 px-4 py-2 bg-slate-950/80 backdrop-blur-md rounded-xl border border-white/10 text-[10px] font-black text-emerald-500 flex items-center gap-2 shadow-xl">
                <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-ping" />
                NEURAL LINK: {progress}%
              </div>
            )}
          </div>

          {/* Controls & Mini Stats */}
          <div className="flex flex-col md:flex-row gap-6">
            <div className="flex-1 glass-panel p-10 rounded-[3rem] flex flex-col md:flex-row items-center justify-between gap-8 shadow-xl">
              <div className="space-y-1">
                <span className="text-emerald-500 text-[10px] font-black uppercase tracking-widest">Processing Core</span>
                <h2 className="text-2xl font-bold text-white tracking-tight">Transcription</h2>
                <p className="text-slate-500 text-sm">Target: English SRT Format.</p>
              </div>
              <div className="flex gap-4 w-full md:w-auto">
                <button 
                  onClick={startProcessing}
                  disabled={!videoFile || isProcessing}
                  className="flex-1 md:flex-none bg-emerald-500 hover:bg-emerald-400 disabled:opacity-20 text-slate-950 font-black px-12 py-5 rounded-2xl transition-all shadow-[0_15px_40px_-10px_rgba(16,185,129,0.3)] active:scale-95"
                >
                  {isProcessing ? `Processing...` : 'Run Pipeline'}
                </button>
                <button 
                  onClick={downloadSRT}
                  disabled={segments.length === 0}
                  className="flex-1 md:flex-none bg-slate-800 hover:bg-slate-700 disabled:opacity-20 text-white font-bold px-10 py-5 rounded-2xl border border-white/10 transition-all"
                >
                  Export SRT
                </button>
              </div>
            </div>

            <div className="md:w-64 glass-panel p-8 rounded-[3rem] flex flex-col justify-center items-center gap-2 shadow-xl border border-emerald-500/20">
               <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Health Score</span>
               <div className="text-4xl font-black text-emerald-500">{globalSuccessRate}%</div>
               <div className="w-full bg-slate-900 h-1 rounded-full overflow-hidden mt-2">
                 <div className="bg-emerald-500 h-full transition-all duration-700" style={{ width: `${globalSuccessRate}%` }} />
               </div>
            </div>
          </div>

          <div className="text-center px-10">
            <p className="text-[10px] text-slate-600 font-black uppercase tracking-[0.4em] animate-pulse">
              {status.message} {cooldown > 0 && `(Cooling ${cooldown}s)`}
            </p>
          </div>
        </div>

        {/* Sidebar Diagnostics & Stream */}
        <div className="lg:col-span-4 flex flex-col gap-6">
          {/* Diagnostics Panel */}
          <div className="glass-panel rounded-[2.5rem] p-6 shadow-xl ring-1 ring-white/10">
            <h3 className="text-[10px] font-black uppercase tracking-widest text-slate-500 mb-4 flex items-center gap-2">
              <svg className="w-3 h-3 text-emerald-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" /></svg>
              Neural Diagnostics
            </h3>
            <div className="grid grid-cols-2 gap-4">
              <div className="bg-slate-900/50 p-4 rounded-2xl border border-white/5">
                <p className="text-[8px] font-black text-slate-600 uppercase">Requests</p>
                <p className="text-lg font-bold text-white">{analytics.totalRequests}</p>
              </div>
              <div className="bg-slate-900/50 p-4 rounded-2xl border border-white/5">
                <p className="text-[8px] font-black text-slate-600 uppercase">Latency Avg</p>
                <p className="text-lg font-bold text-white">
                  {(Object.values(analytics.modelMetrics).reduce((a, b) => a + b.totalLatency, 0) / (analytics.totalRequests || 1) / 1000).toFixed(2)}s
                </p>
              </div>
              <div className="bg-slate-900/50 p-4 rounded-2xl border border-white/5">
                <p className="text-[8px] font-black text-slate-600 uppercase">Failovers</p>
                <p className="text-lg font-bold text-emerald-500">{analytics.failoverEvents}</p>
