              <div className="bg-slate-900/50 p-4 rounded-2xl border border-white/5">
                <p className="text-[8px] font-black text-slate-600 uppercase">Elapsed</p>
                <p className="text-lg font-bold text-white">{totalTimeElapsed}</p>
