          {/* Stream Panel */}
          <div className="glass-panel rounded-[3rem] flex-1 flex flex-col shadow-2xl overflow-hidden ring-1 ring-white/10 min-h-[400px]">
            <div className="p-8 border-b border-white/5 bg-slate-950/20">
              <h3 className="text-xs font-black uppercase tracking-widest text-white flex items-center justify-between">
                Output Stream
                <span className="text-emerald-500 bg-emerald-500/10 px-3 py-1 rounded-lg text-[9px]">{segments.length} BLOCKS</span>
              </h3>
            </div>

            <div className="flex-1 overflow-y-auto p-6 space-y-4 custom-scrollbar">
              {segments.length === 0 && !isProcessing && (
                <div className="h-full flex flex-col items-center justify-center text-center opacity-20 italic text-xs space-y-2">
                  <div className="w-12 h-12 border-2 border-slate-700 border-dashed rounded-full mb-2" />
                  <p>System Idle - Stream Empty</p>
                </div>
              )}
              {segments.map((seg, idx) => (
                <div key={seg.id} className="bg-slate-800/30 p-5 rounded-2xl border border-white/5 hover:border-emerald-500/30 transition-all group animate-in fade-in slide-in-from-bottom-2 duration-300">
                  <div className="flex justify-between items-center mb-2">
                    <span className="text-[9px] font-black text-slate-600 uppercase">Block {idx + 1}</span>
                    <span className="text-[9px] font-mono text-emerald-500 bg-emerald-500/5 px-2 py-1 rounded-md">
                      {Math.floor(seg.start_seconds / 60)}:{(seg.start_seconds % 60).toFixed(1).padStart(4, '0')}
                    </span>
                  </div>
                  <p className="text-slate-300 text-xs leading-relaxed font-medium group-hover:text-white transition-colors">
                    {seg.text}
                  </p>
                </div>
              ))}
              <div ref={transcriptEndRef} />
            </div>

            <div className="p-4 bg-slate-950/50 border-t border-white/5">
              <div className="w-full h-1 bg-slate-800 rounded-full overflow-hidden">
                <div className={`h-full bg-emerald-500 transition-all duration-1000 ${isProcessing ? 'animate-pulse' : ''}`} style={{ width: `${progress}%` }} />
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { GoogleGenAI, Type } from '@google/genai';
import { blobToBase64, audioBufferToWav, downsampleAudioBuffer } from './utils/audioUtils';
import { generateSRT } from './utils/timeFormatter';
import { ProcessingState, CaptionSegment, AnalyticsData, ModelMetric } from './types';

// Neural Model Pool for Failover - Hierarchical order
const MODEL_POOL = [
  { id: 'gemini-3-flash-preview', label: 'Flash 3.0', description: 'Optimal Balanced Core' },
  { id: 'gemini-2.5-flash-native-audio-preview-12-2025', label: 'Audio Native 2.5', description: 'Waveform Specialist' },
  { id: 'gemini-3-pro-preview', label: 'Pro 3.0', description: 'Advanced Reasoning Logic' },
  { id: 'gemini-flash-lite-latest', label: 'Flash Lite', description: 'High-Throughput Fallback' }
];

const CHUNK_DURATION = 300; // 5-minute segments
const REQUEST_GAP = 5000; // 5s gap between batches to prevent 429

const INITIAL_ANALYTICS: AnalyticsData = {
  totalRequests: 0,
  successfulRequests: 0,
  failoverEvents: 0,
  startTime: null,
  endTime: null,
  modelMetrics: MODEL_POOL.reduce((acc, model) => {
    acc[model.id] = { success: 0, fail: 0, avgLatency: 0, totalLatency: 0 };
    return acc;
  }, {} as Record<string, ModelMetric>)
};

const App: React.FC = () => {
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [videoFile, setVideoFile] = useState<File | null>(null);
  const [status, setStatus] = useState<ProcessingState>({
    status: 'idle',
    message: 'Multi-Engine System Ready.'
  });
  const [segments, setSegments] = useState<CaptionSegment[]>([]);
  const [progress, setProgress] = useState(0);
  const [isProcessing, setIsProcessing] = useState(false);
  const [activeModelIndex, setActiveModelIndex] = useState(0);
  const [cooldown, setCooldown] = useState(0);
  const [analytics, setAnalytics] = useState<AnalyticsData>(INITIAL_ANALYTICS);

  const transcriptEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    transcriptEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [segments]);

  useEffect(() => {
    if (cooldown > 0) {
      const timer = setTimeout(() => setCooldown(cooldown - 1), 1000);
      return () => clearTimeout(timer);
    }
  }, [cooldown]);

  const updateAnalytics = (modelId: string, latency: number, success: boolean, failover: boolean = false) => {
    setAnalytics(prev => {
      const modelMetric = prev.modelMetrics[modelId];
      const newSuccess = modelMetric.success + (success ? 1 : 0);
      const newFail = modelMetric.fail + (success ? 0 : 1);
      const newTotalLatency = modelMetric.totalLatency + latency;

      return {
        ...prev,
        totalRequests: prev.totalRequests + 1,
        successfulRequests: prev.successfulRequests + (success ? 1 : 0),
        failoverEvents: prev.failoverEvents + (failover ? 1 : 0),
        modelMetrics: {
          ...prev.modelMetrics,
          [modelId]: {
            success: newSuccess,
            fail: newFail,
            totalLatency: newTotalLatency,
            avgLatency: newTotalLatency / (newSuccess + newFail)
          }
        }
      };
    });
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      setVideoFile(file);
      setVideoUrl(URL.createObjectURL(file));
      setSegments([]);
      setProgress(0);
      setAnalytics(INITIAL_ANALYTICS);
      setStatus({ status: 'idle', message: 'Video Imported. Engines Warm.' });
    }
  };

  const processBatchWithFailover = async (
    audioBuffer: AudioBuffer, 
    offset: number, 
    batchIndex: number, 
    poolIndex: number = 0,
    retryCount: number = 0
  ): Promise<boolean> => {
    if (poolIndex >= MODEL_POOL.length) {
      return false;
    }

    const currentModel = MODEL_POOL[poolIndex];
    setActiveModelIndex(poolIndex);
    const requestStart = performance.now();

    try {
      // Create a new GoogleGenAI instance right before making an API call to ensure it always uses the most up-to-date API key.
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const optimizedBuffer = await downsampleAudioBuffer(audioBuffer, 16000);
      const wavBlob = audioBufferToWav(optimizedBuffer);
      const base64Data = await blobToBase64(wavBlob);

      setStatus({ 
        status: 'streaming', 
        message: `Analyzing Batch ${batchIndex + 1} with ${currentModel.label}...` 
      });

      const response = await ai.models.generateContent({
        model: currentModel.id,
        contents: [{
          parts: [
            { inlineData: { mimeType: 'audio/wav', data: base64Data } },
            { text: "Precisely transcribe and translate this audio into natural English. Return a JSON array of objects with: start (float seconds), end (float seconds), text (English string)." }
          ]
        }],
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                start: { type: Type.NUMBER },
                end: { type: Type.NUMBER },
                text: { type: Type.STRING }
              },
              required: ['start', 'end', 'text']
            }
          }
        }
      });

      const latency = performance.now() - requestStart;
      updateAnalytics(currentModel.id, latency, true);

      const data = JSON.parse(response.text || "[]");
      const adjustedSegments = data.map((s: any, i: number) => ({
        id: Date.now() + Math.random() + i,
        start_seconds: s.start + offset,
        end_seconds: s.end + offset,
        text: s.text
      }));

      setSegments(prev => {
        const next = [...prev, ...adjustedSegments].sort((a, b) => a.start_seconds - b.start_seconds);
        return next;
      });

      return true;
    } catch (error: any) {
      const latency = performance.now() - requestStart;
      const isQuota = error.message?.includes("429") || error.message?.includes("RESOURCE_EXHAUSTED");

      updateAnalytics(currentModel.id, latency, false, isQuota);

      if (isQuota && poolIndex < MODEL_POOL.length - 1) {
        setStatus({ status: 'connecting', message: `Quota Over. Switching to ${MODEL_POOL[poolIndex + 1].label}...` });
        setCooldown(10);
        await new Promise(r => setTimeout(r, 10000));
        return processBatchWithFailover(audioBuffer, offset, batchIndex, poolIndex + 1, 0);
      } else if (retryCount < 2) {
        setStatus({ status: 'connecting', message: `Sync Failure. Retrying Core ${currentModel.label}...` });
        await new Promise(r => setTimeout(r, 5000));
        return processBatchWithFailover(audioBuffer, offset, batchIndex, poolIndex, retryCount + 1);
      }

      return false;
    }
  };

  const startProcessing = async () => {
    if (!videoFile || isProcessing) return;

    try {
      setIsProcessing(true);
      setAnalytics(prev => ({ ...prev, startTime: Date.now(), endTime: null }));
      setStatus({ status: 'connecting', message: 'Extracting High-Fidelity Audio...' });

      const arrayBuffer = await videoFile.arrayBuffer();
      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
      const decodedBuffer = await audioCtx.decodeAudioData(arrayBuffer);

      const duration = decodedBuffer.duration;
      const numChunks = Math.ceil(duration / CHUNK_DURATION);

      for (let i = 0; i < numChunks; i++) {
        const start = i * CHUNK_DURATION;
        const end = Math.min(start + CHUNK_DURATION, duration);
        const frameStart = Math.floor(start * decodedBuffer.sampleRate);
        const frameEnd = Math.floor(end * decodedBuffer.sampleRate);

        const chunkBuffer = audioCtx.createBuffer(1, frameEnd - frameStart, decodedBuffer.sampleRate);
        chunkBuffer.copyToChannel(decodedBuffer.getChannelData(0).subarray(frameStart, frameEnd), 0);

        const success = await processBatchWithFailover(chunkBuffer, start, i, 0);

        if (!success) throw new Error("All Neural Cores reported exhaustion. Try again in 60s.");

        setProgress(Math.round(((i + 1) / numChunks) * 100));

        if (i < numChunks - 1) {
          setStatus({ status: 'connecting', message: 'Waiting for Quota Reset (5s)...' });
          await new Promise(r => setTimeout(r, REQUEST_GAP));
        }
      }

      setAnalytics(prev => ({ ...prev, endTime: Date.now() }));
      setStatus({ status: 'completed', message: 'All Segments Synced & Translated.' });
      setIsProcessing(false);
    } catch (error: any) {
      setIsProcessing(false);
      setAnalytics(prev => ({ ...prev, endTime: Date.now() }));
      setStatus({ status: 'error', message: error.message });
    }
  };

  const downloadSRT = () => {
    const srt = generateSRT(segments);
    const blob = new Blob([srt], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `PhilipAI_Captions.srt`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
  };

  const globalSuccessRate = useMemo(() => {
    if (analytics.totalRequests === 0) return 0;
    return Math.round((analytics.successfulRequests / analytics.totalRequests) * 100);
  }, [analytics]);

  const totalTimeElapsed = useMemo(() => {
    if (!analytics.startTime) return '0s';
    const end = analytics.endTime || Date.now();
    const diff = (end - analytics.startTime) / 1000;
    return diff < 60 ? `${diff.toFixed(1)}s` : `${Math.floor(diff / 60)}m ${Math.floor(diff % 60)}s`;
  }, [analytics]);

  return (
    <div className="min-h-screen p-4 md:p-10 flex flex-col gap-8 max-w-7xl mx-auto">
      {/* Header / Engine Status */}
      <header className="flex flex-col lg:flex-row items-stretch gap-6">
        <div className="flex-1 glass-panel p-8 rounded-[2.5rem] flex items-center gap-6 shadow-xl ring-1 ring-white/5">
          <div className="w-16 h-16 bg-emerald-500 rounded-2xl flex items-center justify-center shadow-[0_0_30px_rgba(16,185,129,0.2)]">
            <svg className="w-10 h-10 text-slate-950" fill="currentColor" viewBox="0 0 24 24">
              <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 14h-2v-2h2v2zm0-4h-2V7h2v5z"/>
            </svg>
          </div>
          <div>
            <h1 className="text-4xl font-black tracking-tighter text-white">Philip<span className="text-emerald-500">AI</span></h1>
            <p className="text-[10px] font-black uppercase tracking-[0.4em] text-slate-500 mt-1">Intelligence Pipeline</p>
          </div>
        </div>

        <div className="flex-[2] glass-panel p-6 rounded-[2.5rem] flex flex-wrap items-center justify-around gap-4 shadow-xl ring-1 ring-white/5">
          {MODEL_POOL.map((model, idx) => (
            <div key={model.id} className={`flex items-center gap-3 px-4 py-2 rounded-xl border transition-all ${
              activeModelIndex === idx && isProcessing ? 'bg-emerald-500/10 border-emerald-500/50 shadow-lg shadow-emerald-500/10 scale-105' : 'bg-slate-900/40 border-white/5 opacity-40'
            }`}>
              <div className={`w-2 h-2 rounded-full ${activeModelIndex === idx && isProcessing ? 'bg-emerald-500 animate-pulse' : 'bg-slate-600'}`} />
              <div>
                <p className={`text-[10px] font-black uppercase ${activeModelIndex === idx && isProcessing ? 'text-emerald-500' : 'text-slate-400'}`}>{model.label}</p>
                <div className="flex items-center gap-2">
                   <p className="text-[8px] text-slate-600 truncate max-w-[80px]">{model.description}</p>
                   {analytics.modelMetrics[model.id].success > 0 && (
                     <span className="text-[7px] font-bold text-emerald-500/80">{(analytics.modelMetrics[model.id].avgLatency / 1000).toFixed(1)}s</span>
                   )}
                </div>
              </div>
            </div>
          ))}
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Workspace */}
        <div className="lg:col-span-8 flex flex-col gap-6">
          <div className="aspect-video bg-black rounded-[3rem] overflow-hidden border border-white/5 shadow-2xl relative ring-1 ring-white/10 group">
            {videoUrl ? (
              <video src={videoUrl} controls className="w-full h-full object-contain" />
            ) : (
              <label className="absolute inset-0 flex flex-col items-center justify-center cursor-pointer hover:bg-slate-900/50 transition-all">
                <div className="w-20 h-20 bg-slate-900 rounded-[2rem] flex items-center justify-center mb-4 border border-white/10 group-hover:border-emerald-500/50 transition-all duration-500">
                  <svg className="w-8 h-8 text-slate-500 group-hover:text-emerald-500 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg>
                </div>
                <span className="text-slate-500 font-bold uppercase tracking-widest text-xs">Import Local Source</span>
                <input type="file" className="hidden" accept="video/*" onChange={handleFileChange} />
              </label>
            )}

            {isProcessing && (
              <div className="absolute top-6 right-6 px-4 py-2 bg-slate-950/80 backdrop-blur-md rounded-xl border border-white/10 text-[10px] font-black text-emerald-500 flex items-center gap-2 shadow-xl">
                <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-ping" />
                NEURAL LINK: {progress}%
              </div>
            )}
          </div>

          {/* Controls & Mini Stats */}
          <div className="flex flex-col md:flex-row gap-6">
            <div className="flex-1 glass-panel p-10 rounded-[3rem] flex flex-col md:flex-row items-center justify-between gap-8 shadow-xl">
              <div className="space-y-1">
                <span className="text-emerald-500 text-[10px] font-black uppercase tracking-widest">Processing Core</span>
                <h2 className="text-2xl font-bold text-white tracking-tight">Transcription</h2>
                <p className="text-slate-500 text-sm">Target: English SRT Format.</p>
              </div>
              <div className="flex gap-4 w-full md:w-auto">
                <button 
                  onClick={startProcessing}
                  disabled={!videoFile || isProcessing}
                  className="flex-1 md:flex-none bg-emerald-500 hover:bg-emerald-400 disabled:opacity-20 text-slate-950 font-black px-12 py-5 rounded-2xl transition-all shadow-[0_15px_40px_-10px_rgba(16,185,129,0.3)] active:scale-95"
                >
                  {isProcessing ? `Processing...` : 'Run Pipeline'}
                </button>
                <button 
                  onClick={downloadSRT}
                  disabled={segments.length === 0}
                  className="flex-1 md:flex-none bg-slate-800 hover:bg-slate-700 disabled:opacity-20 text-white font-bold px-10 py-5 rounded-2xl border border-white/10 transition-all"
                >
                  Export SRT
                </button>
              </div>
            </div>

            <div className="md:w-64 glass-panel p-8 rounded-[3rem] flex flex-col justify-center items-center gap-2 shadow-xl border border-emerald-500/20">
               <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Health Score</span>
               <div className="text-4xl font-black text-emerald-500">{globalSuccessRate}%</div>
               <div className="w-full bg-slate-900 h-1 rounded-full overflow-hidden mt-2">
                 <div className="bg-emerald-500 h-full transition-all duration-700" style={{ width: `${globalSuccessRate}%` }} />
               </div>
            </div>
          </div>

          <div className="text-center px-10">
            <p className="text-[10px] text-slate-600 font-black uppercase tracking-[0.4em] animate-pulse">
              {status.message} {cooldown > 0 && `(Cooling ${cooldown}s)`}
            </p>
          </div>
        </div>

        {/* Sidebar Diagnostics & Stream */}
        <div className="lg:col-span-4 flex flex-col gap-6">
          {/* Diagnostics Panel */}
          <div className="glass-panel rounded-[2.5rem] p-6 shadow-xl ring-1 ring-white/10">
            <h3 className="text-[10px] font-black uppercase tracking-widest text-slate-500 mb-4 flex items-center gap-2">
              <svg className="w-3 h-3 text-emerald-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" /></svg>
              Neural Diagnostics
            </h3>
            <div className="grid grid-cols-2 gap-4">
              <div className="bg-slate-900/50 p-4 rounded-2xl border border-white/5">
                <p className="text-[8px] font-black text-slate-600 uppercase">Requests</p>
                <p className="text-lg font-bold text-white">{analytics.totalRequests}</p>
              </div>
              <div className="bg-slate-900/50 p-4 rounded-2xl border border-white/5">
                <p className="text-[8px] font-black text-slate-600 uppercase">Latency Avg</p>
                <p className="text-lg font-bold text-white">
                  {/* Fix: Explicitly cast to ModelMetric to resolve property 'totalLatency' not existing on unknown type errors. */}
                  {(Object.values(analytics.modelMetrics).reduce((acc: number, curr) => acc + (curr as ModelMetric).totalLatency, 0) / (analytics.totalRequests || 1) / 1000).toFixed(2)}s
                </p>
              </div>
              <div className="bg-slate-900/50 p-4 rounded-2xl border border-white/5">
                <p className="text-[8px] font-black text-slate-600 uppercase">Failovers</p>
                <p className="text-lg font-bold text-emerald-500">{analytics.failoverEvents}</p>
              </div>
              <div className="bg-slate-900/50 p-4 rounded-2xl border border-white/5">
                <p className="text-[8px] font-black text-slate-600 uppercase">Elapsed</p>
                <p className="text-lg font-bold text-white">{totalTimeElapsed}</p>
              </div>
            </div>
          </div>

          {/* Stream Panel */}
          <div className="glass-panel rounded-[3rem] flex-1 flex flex-col shadow-2xl overflow-hidden ring-1 ring-white/10 min-h-[400px]">
            <div className="p-8 border-b border-white/5 bg-slate-950/20">
              <h3 className="text-xs font-black uppercase tracking-widest text-white flex items-center justify-between">
                Output Stream
                <span className="text-emerald-500 bg-emerald-500/10 px-3 py-1 rounded-lg text-[9px]">{segments.length} BLOCKS</span>
              </h3>
            </div>

            <div className="flex-1 overflow-y-auto p-6 space-y-4 custom-scrollbar">
              {segments.length === 0 && !isProcessing && (
                <div className="h-full flex flex-col items-center justify-center text-center opacity-20 italic text-xs space-y-2">
                  <div className="w-12 h-12 border-2 border-slate-700 border-dashed rounded-full mb-2" />
                  <p>System Idle - Stream Empty</p>
                </div>
              )}
              {segments.map((seg, idx) => (
                <div key={seg.id} className="bg-slate-800/30 p-5 rounded-2xl border border-white/5 hover:border-emerald-500/30 transition-all group animate-in fade-in slide-in-from-bottom-2 duration-300">
                  <div className="flex justify-between items-center mb-2">
                    <span className="text-[9px] font-black text-slate-600 uppercase">Block {idx + 1}</span>
                    <span className="text-[9px] font-mono text-emerald-500 bg-emerald-500/5 px-2 py-1 rounded-md">
                      {Math.floor(seg.start_seconds / 60)}:{(seg.start_seconds % 60).toFixed(1).padStart(4, '0')}
                    </span>
                  </div>
                  <p className="text-slate-300 text-xs leading-relaxed font-medium group-hover:text-white transition-colors">
                    {seg.text}
                  </p>
                </div>
              ))}
              <div ref={transcriptEndRef} />
            </div>

            <div className="p-4 bg-slate-950/50 border-t border-white/5">
              <div className="w-full h-1 bg-slate-800 rounded-full overflow-hidden">
                <div className={`h-full bg-emerald-500 transition-all duration-1000 ${isProcessing ? 'animate-pulse' : ''}`} style={{ width: `${progress}%` }} />
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { GoogleGenAI, Type } from '@google/genai';
import { blobToBase64, audioBufferToWav, downsampleAudioBuffer } from './utils/audioUtils';
import { generateSRT } from './utils/timeFormatter';
import { ProcessingState, CaptionSegment, AnalyticsData, ModelMetric } from './types';

// Neural Model Pool for Failover - Hierarchical order
const MODEL_POOL = [
  { id: 'gemini-3-flash-preview', label: 'Flash 3.0', description: 'Optimal Balanced Core' },
  { id: 'gemini-2.5-flash-native-audio-preview-12-2025', label: 'Audio Native 2.5', description: 'Waveform Specialist' },
  { id: 'gemini-3-pro-preview', label: 'Pro 3.0', description: 'Advanced Reasoning Logic' },
  { id: 'gemini-flash-lite-latest', label: 'Flash Lite', description: 'High-Throughput Fallback' }
];

const CHUNK_DURATION = 300; // 5-minute segments
const REQUEST_GAP = 5000; // 5s gap between batches to prevent 429

const INITIAL_ANALYTICS: AnalyticsData = {
  totalRequests: 0,
  successfulRequests: 0,
  failoverEvents: 0,
  startTime: null,
  endTime: null,
  modelMetrics: MODEL_POOL.reduce((acc, model) => {
    acc[model.id] = { success: 0, fail: 0, avgLatency: 0, totalLatency: 0 };
    return acc;
  }, {} as Record<string, ModelMetric>)
};

interface Incident {
  time: string;
  model: string;
  type: string;
  detail: string;
}

const App: React.FC = () => {
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [videoFile, setVideoFile] = useState<File | null>(null);
  const [status, setStatus] = useState<ProcessingState>({
    status: 'idle',
    message: 'Multi-Engine System Ready.'
  });
  const [segments, setSegments] = useState<CaptionSegment[]>([]);
  const [progress, setProgress] = useState(0);
  const [isProcessing, setIsProcessing] = useState(false);
  const [activeModelIndex, setActiveModelIndex] = useState(0);
  const [cooldown, setCooldown] = useState(0);
  const [analytics, setAnalytics] = useState<AnalyticsData>(INITIAL_ANALYTICS);
  const [incidents, setIncidents] = useState<Incident[]>([]);

  const transcriptEndRef = useRef<HTMLDivElement>(null);
  const incidentEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    transcriptEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [segments]);

  useEffect(() => {
    if (cooldown > 0) {
      const timer = setTimeout(() => setCooldown(cooldown - 1), 1000);
      return () => clearTimeout(timer);
    }
  }, [cooldown]);

  const updateAnalytics = (modelId: string, latency: number, success: boolean, failover: boolean = false) => {
    setAnalytics(prev => {
      const modelMetric = prev.modelMetrics[modelId];
      const newSuccess = modelMetric.success + (success ? 1 : 0);
      const newFail = modelMetric.fail + (success ? 0 : 1);
      const newTotalLatency = modelMetric.totalLatency + latency;

      return {
        ...prev,
        totalRequests: prev.totalRequests + 1,
        successfulRequests: prev.successfulRequests + (success ? 1 : 0),
        failoverEvents: prev.failoverEvents + (failover ? 1 : 0),
        modelMetrics: {
          ...prev.modelMetrics,
          [modelId]: {
            success: newSuccess,
            fail: newFail,
            totalLatency: newTotalLatency,
            avgLatency: newTotalLatency / (newSuccess + newFail)
          }
        }
      };
    });
  };

  const logIncident = (model: string, type: string, detail: string) => {
    const newIncident: Incident = {
      time: new Date().toLocaleTimeString([], { hour12: false, hour: '2-digit', minute: '2-digit', second: '2-digit' }),
      model,
      type,
      detail
    };
    setIncidents(prev => [newIncident, ...prev].slice(0, 50));
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      setVideoFile(file);
      setVideoUrl(URL.createObjectURL(file));
      setSegments([]);
      setProgress(0);
      setIncidents([]);
      setAnalytics(INITIAL_ANALYTICS);
      setStatus({ status: 'idle', message: 'Video Imported. Engines Warm.' });
    }
  };

  const processBatchWithFailover = async (
    audioBuffer: AudioBuffer, 
    offset: number, 
    batchIndex: number, 
    poolIndex: number = 0,
    retryCount: number = 0
  ): Promise<boolean> => {
    if (poolIndex >= MODEL_POOL.length) {
      return false;
    }

    const currentModel = MODEL_POOL[poolIndex];
    setActiveModelIndex(poolIndex);
    const requestStart = performance.now();

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const optimizedBuffer = await downsampleAudioBuffer(audioBuffer, 16000);
      const wavBlob = audioBufferToWav(optimizedBuffer);
      const base64Data = await blobToBase64(wavBlob);

      setStatus({ 
        status: 'streaming', 
        message: `Analyzing Batch ${batchIndex + 1} with ${currentModel.label}...` 
      });

      const response = await ai.models.generateContent({
        model: currentModel.id,
        contents: [{
          parts: [
            { inlineData: { mimeType: 'audio/wav', data: base64Data } },
            { text: "Precisely transcribe and translate this audio into natural English. Return a JSON array of objects with: start (float seconds), end (float seconds), text (English string)." }
          ]
        }],
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                start: { type: Type.NUMBER },
                end: { type: Type.NUMBER },
                text: { type: Type.STRING }
              },
              required: ['start', 'end', 'text']
            }
          }
        }
      });

      const latency = performance.now() - requestStart;
      updateAnalytics(currentModel.id, latency, true);

      const data = JSON.parse(response.text || "[]");
      const adjustedSegments = data.map((s: any, i: number) => ({
        id: Date.now() + Math.random() + i,
        start_seconds: s.start + offset,
        end_seconds: s.end + offset,
        text: s.text
      }));

      setSegments(prev => {
        const next = [...prev, ...adjustedSegments].sort((a, b) => a.start_seconds - b.start_seconds);
        return next;
      });

      return true;
    } catch (error: any) {
      const latency = performance.now() - requestStart;
      const errMsg = error.message || String(error);

      let errorCategory = "Execution Error";
      let detail = errMsg;

      if (errMsg.includes("429") || errMsg.includes("RESOURCE_EXHAUSTED")) {
        errorCategory = "Quota Exceeded";
        detail = "API rate limit reached for this project/model.";
      } else if (errMsg.includes("400") || errMsg.includes("INVALID_ARGUMENT")) {
        errorCategory = "Payload Refusal";
        detail = "The model rejected the audio format or prompt structure.";
      } else if (errMsg.includes("fetch") || errMsg.includes("NetworkError")) {
        errorCategory = "Connectivity Drop";
        detail = "Lost connection to Google Neural Servers.";
      } else if (errMsg.includes("403") || errMsg.includes("PERMISSION_DENIED")) {
        errorCategory = "Access Denied";
        detail = "API Key lacks permissions for this model.";
      }

      logIncident(currentModel.label, errorCategory, errMsg);
      updateAnalytics(currentModel.id, latency, false, errorCategory === "Quota Exceeded");

      if (errorCategory === "Quota Exceeded" && poolIndex < MODEL_POOL.length - 1) {
        setStatus({ status: 'connecting', message: `[${currentModel.label}] ${errorCategory}. Failover to ${MODEL_POOL[poolIndex + 1].label}...` });
        setCooldown(10);
        await new Promise(r => setTimeout(r, 10000));
        return processBatchWithFailover(audioBuffer, offset, batchIndex, poolIndex + 1, 0);
      } else if (retryCount < 2) {
        setStatus({ status: 'connecting', message: `[${currentModel.label}] ${errorCategory}. Retry ${retryCount + 1}/2...` });
        await new Promise(r => setTimeout(r, 5000));
        return processBatchWithFailover(audioBuffer, offset, batchIndex, poolIndex, retryCount + 1);
      }

      setStatus({ status: 'error', message: `Pipeline Failure: ${currentModel.label} encountered ${errorCategory}.` });
      return false;
    }
  };

  const startProcessing = async () => {
    if (!videoFile || isProcessing) return;

    try {
      setIsProcessing(true);
      setAnalytics(prev => ({ ...prev, startTime: Date.now(), endTime: null }));
      setStatus({ status: 'connecting', message: 'Extracting High-Fidelity Audio...' });

      const arrayBuffer = await videoFile.arrayBuffer();
      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
      const decodedBuffer = await audioCtx.decodeAudioData(arrayBuffer);

      const duration = decodedBuffer.duration;
      const numChunks = Math.ceil(duration / CHUNK_DURATION);

      for (let i = 0; i < numChunks; i++) {
        const start = i * CHUNK_DURATION;
        const end = Math.min(start + CHUNK_DURATION, duration);
        const frameStart = Math.floor(start * decodedBuffer.sampleRate);
        const frameEnd = Math.floor(end * decodedBuffer.sampleRate);

        const chunkBuffer = audioCtx.createBuffer(1, frameEnd - frameStart, decodedBuffer.sampleRate);
        chunkBuffer.copyToChannel(decodedBuffer.getChannelData(0).subarray(frameStart, frameEnd), 0);

        const success = await processBatchWithFailover(chunkBuffer, start, i, 0);

        if (!success) throw new Error("Critical Failure: All Neural Cores exhausted available capacity.");

        setProgress(Math.round(((i + 1) / numChunks) * 100));

        if (i < numChunks - 1) {
          setStatus({ status: 'connecting', message: 'Waiting for Sync Buffer (5s)...' });
          await new Promise(r => setTimeout(r, REQUEST_GAP));
        }
      }

      setAnalytics(prev => ({ ...prev, endTime: Date.now() }));
      setStatus({ status: 'completed', message: 'All Segments Synced & Translated.' });
      setIsProcessing(false);
    } catch (error: any) {
      setIsProcessing(false);
      setAnalytics(prev => ({ ...prev, endTime: Date.now() }));
      setStatus({ status: 'error', message: error.message });
      logIncident("Global Pipeline", "Critical Stop", error.message);
    }
  };

  const downloadSRT = () => {
    const srt = generateSRT(segments);
    const blob = new Blob([srt], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `PhilipAI_Captions.srt`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
  };

  const globalSuccessRate = useMemo(() => {
    if (analytics.totalRequests === 0) return 0;
    return Math.round((analytics.successfulRequests / analytics.totalRequests) * 100);
  }, [analytics]);

  const totalTimeElapsed = useMemo(() => {
    if (!analytics.startTime) return '0s';
    const end = analytics.endTime || Date.now();
    const diff = (end - analytics.startTime) / 1000;
    return diff < 60 ? `${diff.toFixed(1)}s` : `${Math.floor(diff / 60)}m ${Math.floor(diff % 60)}s`;
  }, [analytics]);

  return (
    <div className="min-h-screen p-4 md:p-10 flex flex-col gap-8 max-w-7xl mx-auto">
      {/* Header / Engine Status */}
      <header className="flex flex-col lg:flex-row items-stretch gap-6">
        <div className="flex-1 glass-panel p-8 rounded-[2.5rem] flex items-center gap-6 shadow-xl ring-1 ring-white/5">
          <div className="w-16 h-16 bg-emerald-500 rounded-2xl flex items-center justify-center shadow-[0_0_30px_rgba(16,185,129,0.2)]">
            <svg className="w-10 h-10 text-slate-950" fill="currentColor" viewBox="0 0 24 24">
              <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 14h-2v-2h2v2zm0-4h-2V7h2v5z"/>
            </svg>
          </div>
          <div>
            <h1 className="text-4xl font-black tracking-tighter text-white">Philip<span className="text-emerald-500">AI</span></h1>
            <p className="text-[10px] font-black uppercase tracking-[0.4em] text-slate-500 mt-1">Intelligence Pipeline</p>
          </div>
        </div>

        <div className="flex-[2] glass-panel p-6 rounded-[2.5rem] flex flex-wrap items-center justify-around gap-4 shadow-xl ring-1 ring-white/5">
          {MODEL_POOL.map((model, idx) => {
            const metrics = analytics.modelMetrics[model.id];
            const failRate = metrics.success + metrics.fail > 0 ? (metrics.fail / (metrics.success + metrics.fail)) : 0;
            return (
              <div key={model.id} className={`flex items-center gap-3 px-4 py-2 rounded-xl border transition-all ${
                activeModelIndex === idx && isProcessing ? 'bg-emerald-500/10 border-emerald-500/50 shadow-lg shadow-emerald-500/10 scale-105' : 'bg-slate-900/40 border-white/5 opacity-40'
              }`}>
                <div className={`w-2 h-2 rounded-full ${
                  activeModelIndex === idx && isProcessing ? 'bg-emerald-500 animate-pulse' : 
                  failRate > 0.5 ? 'bg-red-500' : 'bg-slate-600'
                }`} />
                <div>
                  <p className={`text-[10px] font-black uppercase ${activeModelIndex === idx && isProcessing ? 'text-emerald-500' : 'text-slate-400'}`}>{model.label}</p>
                  <div className="flex items-center gap-2">
                     <p className="text-[8px] text-slate-600 truncate max-w-[80px]">{model.description}</p>
                     {metrics.success > 0 && (
                       <span className="text-[7px] font-bold text-emerald-500/80">{(metrics.avgLatency / 1000).toFixed(1)}s</span>
                     )}
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Workspace */}
        <div className="lg:col-span-8 flex flex-col gap-6">
          <div className="aspect-video bg-black rounded-[3rem] overflow-hidden border border-white/5 shadow-2xl relative ring-1 ring-white/10 group">
            {videoUrl ? (
              <video src={videoUrl} controls className="w-full h-full object-contain" />
            ) : (
              <label className="absolute inset-0 flex flex-col items-center justify-center cursor-pointer hover:bg-slate-900/50 transition-all">
                <div className="w-20 h-20 bg-slate-900 rounded-[2rem] flex items-center justify-center mb-4 border border-white/10 group-hover:border-emerald-500/50 transition-all duration-500">
                  <svg className="w-8 h-8 text-slate-500 group-hover:text-emerald-500 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg>
                </div>
                <span className="text-slate-500 font-bold uppercase tracking-widest text-xs">Import Local Source</span>
                <input type="file" className="hidden" accept="video/*" onChange={handleFileChange} />
              </label>
            )}

            {isProcessing && (
              <div className="absolute top-6 right-6 px-4 py-2 bg-slate-950/80 backdrop-blur-md rounded-xl border border-white/10 text-[10px] font-black text-emerald-500 flex items-center gap-2 shadow-xl">
                <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-ping" />
                NEURAL LINK: {progress}%
              </div>
            )}
          </div>

          {/* Controls & Mini Stats */}
          <div className="flex flex-col md:flex-row gap-6">
            <div className="flex-1 glass-panel p-10 rounded-[3rem] flex flex-col md:flex-row items-center justify-between gap-8 shadow-xl">
              <div className="space-y-1">
                <span className="text-emerald-500 text-[10px] font-black uppercase tracking-widest">Processing Core</span>
                <h2 className="text-2xl font-bold text-white tracking-tight">Transcription</h2>
                <p className="text-slate-500 text-sm">Target: English SRT Format.</p>
              </div>
              <div className="flex gap-4 w-full md:w-auto">
                <button 
                  onClick={startProcessing}
                  disabled={!videoFile || isProcessing}
                  className="flex-1 md:flex-none bg-emerald-500 hover:bg-emerald-400 disabled:opacity-20 text-slate-950 font-black px-12 py-5 rounded-2xl transition-all shadow-[0_15px_40px_-10px_rgba(16,185,129,0.3)] active:scale-95"
                >
                  {isProcessing ? `Processing...` : 'Run Pipeline'}
                </button>
                <button 
                  onClick={downloadSRT}
                  disabled={segments.length === 0}
                  className="flex-1 md:flex-none bg-slate-800 hover:bg-slate-700 disabled:opacity-20 text-white font-bold px-10 py-5 rounded-2xl border border-white/10 transition-all"
                >
                  Export SRT
                </button>
              </div>
            </div>

            <div className={`md:w-64 glass-panel p-8 rounded-[3rem] flex flex-col justify-center items-center gap-2 shadow-xl border ${status.status === 'error' ? 'border-red-500/20' : 'border-emerald-500/20'}`}>
               <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Health Score</span>
               <div className={`text-4xl font-black ${globalSuccessRate < 50 ? 'text-red-500' : 'text-emerald-500'}`}>{globalSuccessRate}%</div>
               <div className="w-full bg-slate-900 h-1 rounded-full overflow-hidden mt-2">
                 <div className={`${globalSuccessRate < 50 ? 'bg-red-500' : 'bg-emerald-500'} h-full transition-all duration-700`} style={{ width: `${globalSuccessRate}%` }} />
               </div>
            </div>
          </div>

          <div className="text-center px-10">
            <p className={`text-[10px] font-black uppercase tracking-[0.4em] ${status.status === 'error' ? 'text-red-500' : 'text-slate-600 animate-pulse'}`}>
              {status.message} {cooldown > 0 && `(Cooling ${cooldown}s)`}
            </p>
          </div>
        </div>

        {/* Sidebar Diagnostics & Stream */}
        <div className="lg:col-span-4 flex flex-col gap-6 h-full max-h-[1200px]">
          {/* Diagnostics Panel */}
          <div className="glass-panel rounded-[2.5rem] p-6 shadow-xl ring-1 ring-white/10">
            <h3 className="text-[10px] font-black uppercase tracking-widest text-slate-500 mb-4 flex items-center gap-2">
              <svg className="w-3 h-3 text-emerald-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" /></svg>
              Neural Diagnostics
            </h3>
            <div className="grid grid-cols-2 gap-4">
              <div className="bg-slate-900/50 p-4 rounded-2xl border border-white/5">
                <p className="text-[8px] font-black text-slate-600 uppercase">Requests</p>
                <p className="text-lg font-bold text-white">{analytics.totalRequests}</p>
              </div>
              <div className="bg-slate-900/50 p-4 rounded-2xl border border-white/5">
                <p className="text-[8px] font-black text-slate-600 uppercase">Latency Avg</p>
                <p className="text-lg font-bold text-white">
                  {(Object.values(analytics.modelMetrics).reduce((acc: number, curr) => acc + (curr as ModelMetric).totalLatency, 0) / (analytics.totalRequests || 1) / 1000).toFixed(2)}s
                </p>
              </div>
              <div className="bg-slate-900/50 p-4 rounded-2xl border border-white/5">
                <p className="text-[8px] font-black text-slate-600 uppercase">Failovers</p>
                <p className="text-lg font-bold text-emerald-500">{analytics.failoverEvents}</p>
              </div>
              <div className="bg-slate-900/50 p-4 rounded-2xl border border-white/5">
                <p className="text-[8px] font-black text-slate-600 uppercase">Elapsed</p>
                <p className="text-lg font-bold text-white">{totalTimeElapsed}</p>
              </div>
            </div>

            {/* Incident Log */}
            {incidents.length > 0 && (
              <div className="mt-6 border-t border-white/5 pt-4">
                 <h4 className="text-[9px] font-black text-red-500 uppercase tracking-widest mb-3">Incident Log</h4>
                 <div className="space-y-2 max-h-32 overflow-y-auto custom-scrollbar">
                    {incidents.map((inc, i) => (
                      <div key={i} className="text-[9px] bg-red-500/5 border border-red-500/10 p-2 rounded-lg flex flex-col gap-1">
                        <div className="flex justify-between font-black">
                          <span className="text-red-400">{inc.type}</span>
                          <span className="text-slate-600 font-mono">{inc.time}</span>
                        </div>
                        <p className="text-slate-500 leading-tight">[{inc.model}] {inc.detail.substring(0, 80)}...</p>
                      </div>
                    ))}
                 </div>
              </div>
            )}
          </div>

          {/* Stream Panel */}
          <div className="glass-panel rounded-[3rem] flex-1 flex flex-col shadow-2xl overflow-hidden ring-1 ring-white/10 min-h-[400px]">
            <div className="p-8 border-b border-white/5 bg-slate-950/20">
              <h3 className="text-xs font-black uppercase tracking-widest text-white flex items-center justify-between">
                Output Stream
                <span className="text-emerald-500 bg-emerald-500/10 px-3 py-1 rounded-lg text-[9px]">{segments.length} BLOCKS</span>
              </h3>
            </div>

            <div className="flex-1 overflow-y-auto p-6 space-y-4 custom-scrollbar">
              {segments.length === 0 && !isProcessing && (
                <div className="h-full flex flex-col items-center justify-center text-center opacity-20 italic text-xs space-y-2">
                  <div className="w-12 h-12 border-2 border-slate-700 border-dashed rounded-full mb-2" />
                  <p>System Idle - Stream Empty</p>
                </div>
              )}
              {segments.map((seg, idx) => (
                <div key={seg.id} className="bg-slate-800/30 p-5 rounded-2xl border border-white/5 hover:border-emerald-500/30 transition-all group animate-in fade-in slide-in-from-bottom-2 duration-300">
                  <div className="flex justify-between items-center mb-2">
                    <span className="text-[9px] font-black text-slate-600 uppercase">Block {idx + 1}</span>
                    <span className="text-[9px] font-mono text-emerald-500 bg-emerald-500/5 px-2 py-1 rounded-md">
                      {Math.floor(seg.start_seconds / 60)}:{(seg.start_seconds % 60).toFixed(1).padStart(4, '0')}
                    </span>
                  </div>
                  <p className="text-slate-300 text-xs leading-relaxed font-medium group-hover:text-white transition-colors">
                    {seg.text}
                  </p>
                </div>
              ))}
              <div ref={transcriptEndRef} />
            </div>

            <div className="p-4 bg-slate-950/50 border-t border-white/5">
              <div className="w-full h-1 bg-slate-800 rounded-full overflow-hidden">
                <div className={`h-full bg-emerald-500 transition-all duration-1000 ${isProcessing ? 'animate-pulse' : ''}`} style={{ width: `${progress}%` }} />
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { GoogleGenAI, Type } from '@google/genai';
import { blobToBase64, audioBufferToWav, downsampleAudioBuffer } from './utils/audioUtils';
import { generateSRT } from './utils/timeFormatter';
import { ProcessingState, CaptionSegment, AnalyticsData, ModelMetric } from './types';

// Neural Model Pool for Failover - Hierarchical order
const MODEL_POOL = [
  { id: 'gemini-3-flash-preview', label: 'Flash 3.0', description: 'Optimal Balanced Core' },
  { id: 'gemini-2.5-flash-native-audio-preview-12-2025', label: 'Audio Native 2.5', description: 'Waveform Specialist' },
  { id: 'gemini-3-pro-preview', label: 'Pro 3.0', description: 'Advanced Reasoning Logic' },
  { id: 'gemini-flash-lite-latest', label: 'Flash Lite', description: 'High-Throughput Fallback' }
];

const CHUNK_DURATION = 300; // 5-minute segments
const REQUEST_GAP = 5000; // 5s gap between batches to prevent 429

const INITIAL_ANALYTICS: AnalyticsData = {
  totalRequests: 0,
  successfulRequests: 0,
  failoverEvents: 0,
  startTime: null,
  endTime: null,
  modelMetrics: MODEL_POOL.reduce((acc, model) => {
    acc[model.id] = { success: 0, fail: 0, avgLatency: 0, totalLatency: 0 };
    return acc;
  }, {} as Record<string, ModelMetric>)
};

interface Incident {
  time: string;
  model: string;
  type: string;
  detail: string;
  severity: 'warning' | 'critical';
}

const App: React.FC = () => {
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [videoFile, setVideoFile] = useState<File | null>(null);
  const [status, setStatus] = useState<ProcessingState>({
    status: 'idle',
    message: 'Multi-Engine System Ready.'
  });
  const [segments, setSegments] = useState<CaptionSegment[]>([]);
  const [progress, setProgress] = useState(0);
  const [isProcessing, setIsProcessing] = useState(false);
  const [activeModelIndex, setActiveModelIndex] = useState(0);
  const [cooldown, setCooldown] = useState(0);
  const [analytics, setAnalytics] = useState<AnalyticsData>(INITIAL_ANALYTICS);
  const [incidents, setIncidents] = useState<Incident[]>([]);
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  const transcriptEndRef = useRef<HTMLDivElement>(null);

  // Network listener
  useEffect(() => {
    const handleStatusChange = () => setIsOnline(navigator.onLine);
    window.addEventListener('online', handleStatusChange);
    window.addEventListener('offline', handleStatusChange);
    return () => {
      window.removeEventListener('online', handleStatusChange);
      window.removeEventListener('offline', handleStatusChange);
    };
  }, []);

  useEffect(() => {
    transcriptEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [segments]);

  useEffect(() => {
    if (cooldown > 0) {
      const timer = setTimeout(() => setCooldown(cooldown - 1), 1000);
      return () => clearTimeout(timer);
    }
  }, [cooldown]);

  const updateAnalytics = (modelId: string, latency: number, success: boolean, failover: boolean = false) => {
    setAnalytics(prev => {
      const modelMetric = prev.modelMetrics[modelId];
      const newSuccess = modelMetric.success + (success ? 1 : 0);
      const newFail = modelMetric.fail + (success ? 0 : 1);
      const newTotalLatency = modelMetric.totalLatency + latency;

      return {
        ...prev,
        totalRequests: prev.totalRequests + 1,
        successfulRequests: prev.successfulRequests + (success ? 1 : 0),
        failoverEvents: prev.failoverEvents + (failover ? 1 : 0),
        modelMetrics: {
          ...prev.modelMetrics,
          [modelId]: {
            success: newSuccess,
            fail: newFail,
            totalLatency: newTotalLatency,
            avgLatency: newTotalLatency / (newSuccess + newFail || 1)
          }
        }
      };
    });
  };

  const logIncident = (model: string, type: string, detail: string, severity: 'warning' | 'critical' = 'warning') => {
    const newIncident: Incident = {
      time: new Date().toLocaleTimeString([], { hour12: false, hour: '2-digit', minute: '2-digit', second: '2-digit' }),
      model,
      type,
      detail,
      severity
    };
    setIncidents(prev => [newIncident, ...prev].slice(0, 30));
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      setVideoFile(file);
      setVideoUrl(URL.createObjectURL(file));
      setSegments([]);
      setProgress(0);
      setIncidents([]);
      setAnalytics(INITIAL_ANALYTICS);
      setStatus({ status: 'idle', message: 'Video Imported. Engines Warm.' });
    }
  };

  const processBatchWithFailover = async (
    audioBuffer: AudioBuffer, 
    offset: number, 
    batchIndex: number, 
    poolIndex: number = 0,
    retryCount: number = 0
  ): Promise<boolean> => {
    if (poolIndex >= MODEL_POOL.length) return false;
    if (!navigator.onLine) {
      setStatus({ status: 'error', message: 'Network Connection Lost. Pausing Pipeline.' });
      logIncident("Network", "Connectivity", "Offline state detected during batch process.", "critical");
      return false;
    }

    const currentModel = MODEL_POOL[poolIndex];
    setActiveModelIndex(poolIndex);
    const requestStart = performance.now();

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const optimizedBuffer = await downsampleAudioBuffer(audioBuffer, 16000);
      const wavBlob = audioBufferToWav(optimizedBuffer);
      const base64Data = await blobToBase64(wavBlob);

      setStatus({ 
        status: 'streaming', 
        message: `Batch ${batchIndex + 1} -> Analyzing with ${currentModel.label}...` 
      });

      const response = await ai.models.generateContent({
        model: currentModel.id,
        contents: [{
          parts: [
            { inlineData: { mimeType: 'audio/wav', data: base64Data } },
            { text: "Precisely transcribe and translate this audio into natural English. Return a JSON array of objects with: start (float seconds), end (float seconds), text (English string)." }
          ]
        }],
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                start: { type: Type.NUMBER },
                end: { type: Type.NUMBER },
                text: { type: Type.STRING }
              },
              required: ['start', 'end', 'text']
            }
          }
        }
      });

      const latency = performance.now() - requestStart;
      updateAnalytics(currentModel.id, latency, true);

      const data = JSON.parse(response.text || "[]");
      const adjustedSegments = data.map((s: any, i: number) => ({
        id: Date.now() + Math.random() + i,
        start_seconds: s.start + offset,
        end_seconds: s.end + offset,
        text: s.text
      }));

      setSegments(prev => [...prev, ...adjustedSegments].sort((a, b) => a.start_seconds - b.start_seconds));
      return true;
    } catch (error: any) {
      const latency = performance.now() - requestStart;
      const errMsg = error.message || String(error);

      let errorCategory = "Execution Error";
      let severity: 'warning' | 'critical' = 'warning';

      if (errMsg.includes("429") || errMsg.includes("RESOURCE_EXHAUSTED")) {
        errorCategory = "Quota Exceeded";
      } else if (errMsg.includes("400") || errMsg.includes("INVALID_ARGUMENT")) {
        errorCategory = "Payload Refusal";
        severity = 'critical';
      } else if (errMsg.includes("fetch") || errMsg.includes("NetworkError")) {
        errorCategory = "Connectivity Drop";
      } else if (errMsg.includes("403") || errMsg.includes("PERMISSION_DENIED")) {
        errorCategory = "Access Denied";
        severity = 'critical';
      } else if (errMsg.includes("500") || errMsg.includes("INTERNAL")) {
        errorCategory = "Neural Core Fault";
      }

      logIncident(currentModel.label, errorCategory, errMsg, severity);
      updateAnalytics(currentModel.id, latency, false, errorCategory === "Quota Exceeded");

      if (errorCategory === "Quota Exceeded" && poolIndex < MODEL_POOL.length - 1) {
        setStatus({ status: 'connecting', message: `Failover: Switching to ${MODEL_POOL[poolIndex + 1].label}...` });
        setCooldown(10);
        await new Promise(r => setTimeout(r, 10000));
        return processBatchWithFailover(audioBuffer, offset, batchIndex, poolIndex + 1, 0);
      } else if (retryCount < 2 && severity === 'warning') {
        setStatus({ status: 'connecting', message: `Transient Error. Retrying ${currentModel.label} (${retryCount + 1}/2)...` });
        await new Promise(r => setTimeout(r, 5000));
        return processBatchWithFailover(audioBuffer, offset, batchIndex, poolIndex, retryCount + 1);
      }

      setStatus({ status: 'error', message: `Batch ${batchIndex + 1} Failed: ${errorCategory}. Check logs.` });
      return false;
    }
  };

  const startProcessing = async () => {
    if (!videoFile || isProcessing) return;

    try {
      setIsProcessing(true);
      setAnalytics(prev => ({ ...prev, startTime: Date.now(), endTime: null }));
      setStatus({ status: 'connecting', message: 'Decompressing Video Stream...' });

      const arrayBuffer = await videoFile.arrayBuffer();
      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
      const decodedBuffer = await audioCtx.decodeAudioData(arrayBuffer);

      const duration = decodedBuffer.duration;
      const numChunks = Math.ceil(duration / CHUNK_DURATION);

      for (let i = 0; i < numChunks; i++) {
        const start = i * CHUNK_DURATION;
        const end = Math.min(start + CHUNK_DURATION, duration);
        const frameStart = Math.floor(start * decodedBuffer.sampleRate);
        const frameEnd = Math.floor(end * decodedBuffer.sampleRate);

        const chunkBuffer = audioCtx.createBuffer(1, frameEnd - frameStart, decodedBuffer.sampleRate);
        chunkBuffer.copyToChannel(decodedBuffer.getChannelData(0).subarray(frameStart, frameEnd), 0);

        const success = await processBatchWithFailover(chunkBuffer, start, i, 0);
        if (!success) throw new Error("Neural Pipeline Collasped. Multiple engine failures detected.");

        setProgress(Math.round(((i + 1) / numChunks) * 100));
        if (i < numChunks - 1) await new Promise(r => setTimeout(r, REQUEST_GAP));
      }

      setAnalytics(prev => ({ ...prev, endTime: Date.now() }));
      setStatus({ status: 'completed', message: 'All Segments Synced & Translated.' });
      setIsProcessing(false);
    } catch (error: any) {
      setIsProcessing(false);
      setAnalytics(prev => ({ ...prev, endTime: Date.now() }));
      setStatus({ status: 'error', message: error.message });
      logIncident("Global Pipeline", "Fatal Error", error.message, "critical");
    }
  };

  const downloadSRT = () => {
    const srt = generateSRT(segments);
    const blob = new Blob([srt], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `PhilipAI_Captions.srt`;
    document.body.appendChild(a); a.click(); document.body.removeChild(a);
  };

  const globalSuccessRate = useMemo(() => {
    if (analytics.totalRequests === 0) return 0;
    return Math.round((analytics.successfulRequests / analytics.totalRequests) * 100);
  }, [analytics]);

  const totalTimeElapsed = useMemo(() => {
    if (!analytics.startTime) return '0s';
    const end = analytics.endTime || Date.now();
    const diff = (end - analytics.startTime) / 1000;
    return diff < 60 ? `${diff.toFixed(1)}s` : `${Math.floor(diff / 60)}m ${Math.floor(diff % 60)}s`;
  }, [analytics]);

  return (
    <div className="min-h-screen p-4 md:p-10 flex flex-col gap-8 max-w-7xl mx-auto selection:bg-emerald-500/30">
      {/* Header */}
      <header className="flex flex-col lg:flex-row items-stretch gap-6">
        <div className="flex-1 glass-panel p-8 rounded-[2.5rem] flex items-center gap-6 shadow-xl ring-1 ring-white/5 group">
          <div className="w-16 h-16 bg-emerald-500 rounded-2xl flex items-center justify-center shadow-[0_0_30px_rgba(16,185,129,0.2)] group-hover:scale-110 transition-transform duration-500">
            <svg className="w-10 h-10 text-slate-950" fill="currentColor" viewBox="0 0 24 24">
              <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 14h-2v-2h2v2zm0-4h-2V7h2v5z"/>
            </svg>
          </div>
          <div>
            <h1 className="text-4xl font-black tracking-tighter text-white">Philip<span className="text-emerald-500">AI</span></h1>
            <p className="text-[10px] font-black uppercase tracking-[0.4em] text-slate-500 mt-1 flex items-center gap-2">
              <span className={`w-1.5 h-1.5 rounded-full ${isOnline ? 'bg-emerald-500' : 'bg-red-500 animate-ping'}`} />
              {isOnline ? 'Pipeline Online' : 'Network Interrupted'}
            </p>
          </div>
        </div>

        <div className="flex-[2] glass-panel p-6 rounded-[2.5rem] flex flex-wrap items-center justify-around gap-4 shadow-xl ring-1 ring-white/5">
          {MODEL_POOL.map((model, idx) => {
            const metrics = analytics.modelMetrics[model.id];
            const failRate = metrics.success + metrics.fail > 0 ? (metrics.fail / (metrics.success + metrics.fail)) : 0;
            return (
              <div key={model.id} className={`flex items-center gap-3 px-4 py-2 rounded-xl border transition-all ${
                activeModelIndex === idx && isProcessing ? 'bg-emerald-500/10 border-emerald-500/50 shadow-lg shadow-emerald-500/10 scale-105' : 'bg-slate-900/40 border-white/5'
              } ${failRate > 0.5 ? 'border-red-500/30' : ''}`}>
                <div className={`w-2 h-2 rounded-full ${
                  activeModelIndex === idx && isProcessing ? 'bg-emerald-500 animate-pulse' : 
                  failRate > 0.8 ? 'bg-red-500' : 
                  failRate > 0.3 ? 'bg-amber-500' : 'bg-slate-600'
                }`} title={`Fail Rate: ${Math.round(failRate * 100)}%`} />
                <div>
                  <p className={`text-[10px] font-black uppercase ${activeModelIndex === idx && isProcessing ? 'text-emerald-500' : 'text-slate-400'}`}>{model.label}</p>
                  <p className="text-[8px] text-slate-600 truncate max-w-[80px]">{model.description}</p>
                </div>
              </div>
            );
          })}
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Workspace */}
        <div className="lg:col-span-8 flex flex-col gap-6">
          <div className="aspect-video bg-black rounded-[3rem] overflow-hidden border border-white/5 shadow-2xl relative ring-1 ring-white/10 group">
            {videoUrl ? (
              <video src={videoUrl} controls className="w-full h-full object-contain" />
            ) : (
              <label className="absolute inset-0 flex flex-col items-center justify-center cursor-pointer hover:bg-slate-900/50 transition-all">
                <div className="w-20 h-20 bg-slate-900 rounded-[2rem] flex items-center justify-center mb-4 border border-white/10 group-hover:border-emerald-500/50 transition-all duration-500">
                  <svg className="w-8 h-8 text-slate-500 group-hover:text-emerald-500 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg>
                </div>
                <span className="text-slate-500 font-bold uppercase tracking-widest text-xs">Import Local Source</span>
                <input type="file" className="hidden" accept="video/*" onChange={handleFileChange} />
              </label>
            )}

            {isProcessing && (
              <div className="absolute top-6 right-6 px-4 py-2 bg-slate-950/80 backdrop-blur-md rounded-xl border border-white/10 text-[10px] font-black text-emerald-500 flex items-center gap-2 shadow-xl">
                <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-ping" />
                NEURAL LINK: {progress}%
              </div>
            )}
          </div>

          <div className="flex flex-col md:flex-row gap-6">
            <div className="flex-1 glass-panel p-10 rounded-[3rem] flex flex-col md:flex-row items-center justify-between gap-8 shadow-xl border border-white/5">
              <div className="space-y-1">
                <span className="text-emerald-500 text-[10px] font-black uppercase tracking-widest">Transcription core</span>
                <h2 className="text-2xl font-bold text-white tracking-tight">Active Pipeline</h2>
                <p className="text-slate-500 text-sm">Target: Precise English SRT.</p>
              </div>
              <div className="flex gap-4 w-full md:w-auto">
                <button 
                  onClick={startProcessing}
                  disabled={!videoFile || isProcessing || !isOnline}
                  className="flex-1 md:flex-none bg-emerald-500 hover:bg-emerald-400 disabled:opacity-20 text-slate-950 font-black px-12 py-5 rounded-2xl transition-all shadow-[0_15px_40px_-10px_rgba(16,185,129,0.3)] active:scale-95"
                >
                  {!isOnline ? 'Waiting for Network' : isProcessing ? `Processing...` : 'Run Pipeline'}
                </button>
                <button 
                  onClick={downloadSRT}
                  disabled={segments.length === 0}
                  className="flex-1 md:flex-none bg-slate-800 hover:bg-slate-700 disabled:opacity-20 text-white font-bold px-10 py-5 rounded-2xl border border-white/10 transition-all"
                >
                  Export SRT
                </button>
              </div>
            </div>

            <div className={`md:w-64 glass-panel p-8 rounded-[3rem] flex flex-col justify-center items-center gap-2 shadow-xl border ${status.status === 'error' ? 'border-red-500/40' : 'border-white/5'}`}>
               <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Health Score</span>
               <div className={`text-4xl font-black ${globalSuccessRate < 40 ? 'text-red-500' : 'text-emerald-500'}`}>{globalSuccessRate}%</div>
               <div className="w-full bg-slate-900 h-1 rounded-full overflow-hidden mt-2">
                 <div className={`${globalSuccessRate < 40 ? 'bg-red-500' : 'bg-emerald-500'} h-full transition-all duration-700`} style={{ width: `${globalSuccessRate}%` }} />
               </div>
            </div>
          </div>

          <div className={`text-center px-10 py-3 rounded-2xl transition-colors ${status.status === 'error' ? 'bg-red-500/5 border border-red-500/10' : ''}`}>
            <p className={`text-[10px] font-black uppercase tracking-[0.4em] ${status.status === 'error' ? 'text-red-500' : 'text-slate-600 animate-pulse'}`}>
              {status.message} {cooldown > 0 && `(Sync Cooling ${cooldown}s)`}
            </p>
          </div>
        </div>

        {/* Sidebar Diagnostics */}
        <div className="lg:col-span-4 flex flex-col gap-6">
          <div className="glass-panel rounded-[2.5rem] p-6 shadow-xl ring-1 ring-white/10 flex flex-col">
            <h3 className="text-[10px] font-black uppercase tracking-widest text-slate-500 mb-4 flex items-center justify-between">
              <span className="flex items-center gap-2">
                <svg className="w-3 h-3 text-emerald-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
                Neural Diagnostics
              </span>
              {incidents.length > 0 && (
                <button onClick={() => setIncidents([])} className="text-red-500/50 hover:text-red-500 transition-colors">CLEAR</button>
              )}
            </h3>
            <div className="grid grid-cols-2 gap-3 mb-6">
              <div className="bg-slate-950/50 p-4 rounded-2xl border border-white/5">
                <p className="text-[8px] font-black text-slate-600 uppercase">Requests</p>
                <p className="text-lg font-bold text-white">{analytics.totalRequests}</p>
              </div>
              <div className="bg-slate-950/50 p-4 rounded-2xl border border-white/5">
                <p className="text-[8px] font-black text-slate-600 uppercase">Latency</p>
                <p className="text-lg font-bold text-white">
                  {(Object.values(analytics.modelMetrics).reduce((acc: number, curr) => acc + (curr as ModelMetric).totalLatency, 0) / (analytics.totalRequests || 1) / 1000).toFixed(2)}s
                </p>
              </div>
            </div>

            <div className="flex-1 max-h-[250px] overflow-y-auto custom-scrollbar space-y-2">
              {incidents.length === 0 ? (
                <div className="text-center py-10 opacity-20 text-[9px] font-black uppercase tracking-widest">No Incidents Reported</div>
              ) : (
                incidents.map((inc, i) => (
                  <div key={i} className={`text-[9px] p-3 rounded-xl border transition-all ${inc.severity === 'critical' ? 'bg-red-500/10 border-red-500/20' : 'bg-slate-900/50 border-white/5'}`}>
                    <div className="flex justify-between items-start mb-1">
                      <span className={`font-black ${inc.severity === 'critical' ? 'text-red-400' : 'text-amber-500'}`}>{inc.type}</span>
                      <span className="text-slate-600 font-mono text-[8px]">{inc.time}</span>
                    </div>
                    <p className="text-slate-400 leading-tight">[{inc.model}] {inc.detail}</p>
                  </div>
                ))
              )}
            </div>
          </div>

          {/* Stream Output */}
          <div className="glass-panel rounded-[3rem] flex-1 flex flex-col shadow-2xl overflow-hidden ring-1 ring-white/10 min-h-[400px]">
            <div className="p-8 border-b border-white/5 bg-slate-950/20 flex items-center justify-between">
              <h3 className="text-xs font-black uppercase tracking-widest text-white">Output Stream</h3>
              <span className="text-emerald-500 bg-emerald-500/10 px-3 py-1 rounded-lg text-[9px] font-black">{segments.length} UNITS</span>
            </div>

            <div className="flex-1 overflow-y-auto p-6 space-y-4 custom-scrollbar">
              {segments.length === 0 && (
                <div className="h-full flex flex-col items-center justify-center text-center opacity-10 italic text-xs space-y-3 py-20">
                  <div className="w-12 h-12 border-2 border-slate-700 border-dashed rounded-full animate-spin-slow" />
                  <p className="font-black uppercase tracking-widest">Stream Idle</p>
                </div>
              )}
              {segments.map((seg, idx) => (
                <div key={seg.id} className="bg-slate-900/40 p-5 rounded-2xl border border-white/5 hover:border-emerald-500/30 transition-all group animate-in fade-in slide-in-from-bottom-2 duration-300">
                  <div className="flex justify-between items-center mb-2">
                    <span className="text-[9px] font-black text-slate-700 uppercase">Unit {String(idx + 1).padStart(3, '0')}</span>
                    <span className="text-[9px] font-mono text-emerald-500 bg-emerald-500/5 px-2 py-1 rounded-md">
                      {Math.floor(seg.start_seconds / 60)}:{(seg.start_seconds % 60).toFixed(1).padStart(4, '0')}
                    </span>
                  </div>
                  <p className="text-slate-300 text-xs leading-relaxed font-medium group-hover:text-white transition-colors">{seg.text}</p>
                </div>
              ))}
              <div ref={transcriptEndRef} />
            </div>

            <div className="p-4 bg-slate-950/50 border-t border-white/5">
              <div className="w-full h-1 bg-slate-800 rounded-full overflow-hidden">
                <div className={`h-full bg-emerald-500 transition-all duration-1000 ${isProcessing ? 'animate-pulse' : ''}`} style={{ width: `${progress}%` }} />
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { GoogleGenAI, Type } from '@google/genai';
import { blobToBase64, audioBufferToWav, downsampleAudioBuffer } from './utils/audioUtils';
import { generateSRT } from './utils/timeFormatter';
import { ProcessingState, CaptionSegment, AnalyticsData, ModelMetric } from './types';

// Neural Model Pool for Failover - Hierarchical order
const MODEL_POOL = [
  { id: 'gemini-3-flash-preview', label: 'Flash 3.0', description: 'Optimal Balanced Core' },
  { id: 'gemini-2.5-flash-native-audio-preview-12-2025', label: 'Audio Native 2.5', description: 'Waveform Specialist' },
  { id: 'gemini-3-pro-preview', label: 'Pro 3.0', description: 'Advanced Reasoning Logic' },
  { id: 'gemini-flash-lite-latest', label: 'Flash Lite', description: 'High-Throughput Fallback' }
];

const CHUNK_DURATION = 300; // 5-minute segments
const REQUEST_GAP = 5000; // 5s gap between batches to prevent 429

const INITIAL_ANALYTICS: AnalyticsData = {
  totalRequests: 0,
  successfulRequests: 0,
  failoverEvents: 0,
  startTime: null,
  endTime: null,
  modelMetrics: MODEL_POOL.reduce((acc, model) => {
    acc[model.id] = { success: 0, fail: 0, avgLatency: 0, totalLatency: 0 };
    return acc;
  }, {} as Record<string, ModelMetric>)
};

interface Incident {
  time: string;
  model: string;
  type: string;
  detail: string;
  severity: 'warning' | 'critical';
}

const App: React.FC = () => {
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [videoFile, setVideoFile] = useState<File | null>(null);
  const [status, setStatus] = useState<ProcessingState>({
    status: 'idle',
    message: 'Multi-Engine System Ready.'
  });
  const [segments, setSegments] = useState<CaptionSegment[]>([]);
  const [progress, setProgress] = useState(0);
  const [isProcessing, setIsProcessing] = useState(false);
  const [activeModelIndex, setActiveModelIndex] = useState(0);
  const [cooldown, setCooldown] = useState(0);
  const [analytics, setAnalytics] = useState<AnalyticsData>(INITIAL_ANALYTICS);
  const [incidents, setIncidents] = useState<Incident[]>([]);
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  const transcriptEndRef = useRef<HTMLDivElement>(null);

  // Network listener
  useEffect(() => {
    const handleStatusChange = () => setIsOnline(navigator.onLine);
    window.addEventListener('online', handleStatusChange);
    window.addEventListener('offline', handleStatusChange);
    return () => {
      window.removeEventListener('online', handleStatusChange);
      window.removeEventListener('offline', handleStatusChange);
    };
  }, []);

  useEffect(() => {
    transcriptEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [segments]);

  useEffect(() => {
    if (cooldown > 0) {
      const timer = setTimeout(() => setCooldown(cooldown - 1), 1000);
      return () => clearTimeout(timer);
    }
  }, [cooldown]);

  const updateAnalytics = (modelId: string, latency: number, success: boolean, failover: boolean = false) => {
    setAnalytics(prev => {
      const modelMetric = prev.modelMetrics[modelId];
      const newSuccess = modelMetric.success + (success ? 1 : 0);
      const newFail = modelMetric.fail + (success ? 0 : 1);
      const newTotalLatency = modelMetric.totalLatency + latency;

      return {
        ...prev,
        totalRequests: prev.totalRequests + 1,
        successfulRequests: prev.successfulRequests + (success ? 1 : 0),
        failoverEvents: prev.failoverEvents + (failover ? 1 : 0),
        modelMetrics: {
          ...prev.modelMetrics,
          [modelId]: {
            success: newSuccess,
            fail: newFail,
            totalLatency: newTotalLatency,
            avgLatency: newTotalLatency / (newSuccess + newFail || 1)
          }
        }
      };
    });
  };

  const logIncident = (model: string, type: string, detail: string, severity: 'warning' | 'critical' = 'warning') => {
    const newIncident: Incident = {
      time: new Date().toLocaleTimeString([], { hour12: false, hour: '2-digit', minute: '2-digit', second: '2-digit' }),
      model,
      type,
      detail,
      severity
    };
    setIncidents(prev => [newIncident, ...prev].slice(0, 30));
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      setVideoFile(file);
      setVideoUrl(URL.createObjectURL(file));
      setSegments([]);
      setProgress(0);
      setIncidents([]);
      setAnalytics(INITIAL_ANALYTICS);
      setStatus({ status: 'idle', message: 'Video Imported. Engines Warm.' });
    }
  };

  const processBatchWithFailover = async (
    audioBuffer: AudioBuffer, 
    offset: number, 
    batchIndex: number, 
    poolIndex: number = 0,
    retryCount: number = 0
  ): Promise<boolean> => {
    if (poolIndex >= MODEL_POOL.length) return false;
    if (!navigator.onLine) {
      setStatus({ status: 'error', message: 'Network Connection Lost. Pausing Pipeline.' });
      logIncident("Network", "Connectivity", "Offline state detected during batch process.", "critical");
      return false;
    }

    const currentModel = MODEL_POOL[poolIndex];
    setActiveModelIndex(poolIndex);
    const requestStart = performance.now();

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const optimizedBuffer = await downsampleAudioBuffer(audioBuffer, 16000);
      const wavBlob = audioBufferToWav(optimizedBuffer);
      const base64Data = await blobToBase64(wavBlob);

      setStatus({ 
        status: 'streaming', 
        message: `Batch ${batchIndex + 1} -> Analyzing with ${currentModel.label}...` 
      });

      const response = await ai.models.generateContent({
        model: currentModel.id,
        contents: [{
          parts: [
            { inlineData: { mimeType: 'audio/wav', data: base64Data } },
            { text: "Precisely transcribe and translate this audio into natural English. Return a JSON array of objects with: start (float seconds), end (float seconds), text (English string)." }
          ]
        }],
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                start: { type: Type.NUMBER },
                end: { type: Type.NUMBER },
                text: { type: Type.STRING }
              },
              required: ['start', 'end', 'text']
            }
          }
        }
      });

      const latency = performance.now() - requestStart;
      updateAnalytics(currentModel.id, latency, true);

      const data = JSON.parse(response.text || "[]");
      const adjustedSegments = data.map((s: any, i: number) => ({
        id: Date.now() + Math.random() + i,
        start_seconds: s.start + offset,
        end_seconds: s.end + offset,
        text: s.text
      }));

      setSegments(prev => [...prev, ...adjustedSegments].sort((a, b) => a.start_seconds - b.start_seconds));
      return true;
    } catch (error: any) {
      const latency = performance.now() - requestStart;
      const errMsg = error.message || String(error);

      let errorCategory = "Execution Error";
      let severity: 'warning' | 'critical' = 'warning';

      if (errMsg.includes("429") || errMsg.includes("RESOURCE_EXHAUSTED")) {
        errorCategory = "Quota Exceeded";
      } else if (errMsg.includes("400") || errMsg.includes("INVALID_ARGUMENT")) {
        errorCategory = "Payload Refusal";
        severity = 'critical';
      } else if (errMsg.includes("fetch") || errMsg.includes("NetworkError")) {
        errorCategory = "Connectivity Drop";
      } else if (errMsg.includes("403") || errMsg.includes("PERMISSION_DENIED")) {
        errorCategory = "Access Denied";
        severity = 'critical';
      } else if (errMsg.includes("500") || errMsg.includes("INTERNAL")) {
        errorCategory = "Neural Core Fault";
      }

      logIncident(currentModel.label, errorCategory, errMsg, severity);
      updateAnalytics(currentModel.id, latency, false, errorCategory === "Quota Exceeded");

      if (errorCategory === "Quota Exceeded" && poolIndex < MODEL_POOL.length - 1) {
        setStatus({ status: 'connecting', message: `Failover: Switching to ${MODEL_POOL[poolIndex + 1].label}...` });
        setCooldown(10);
        await new Promise(r => setTimeout(r, 10000));
        return processBatchWithFailover(audioBuffer, offset, batchIndex, poolIndex + 1, 0);
      } else if (retryCount < 2 && severity === 'warning') {
        setStatus({ status: 'connecting', message: `Transient Error. Retrying ${currentModel.label} (${retryCount + 1}/2)...` });
        await new Promise(r => setTimeout(r, 5000));
        return processBatchWithFailover(audioBuffer, offset, batchIndex, poolIndex, retryCount + 1);
      }

      setStatus({ status: 'error', message: `Batch ${batchIndex + 1} Failed: ${errorCategory}. Check logs.` });
      return false;
    }
  };

  const startProcessing = async () => {
    if (!videoFile || isProcessing) return;

    try {
      setIsProcessing(true);
      setAnalytics(prev => ({ ...prev, startTime: Date.now(), endTime: null }));
      setStatus({ status: 'connecting', message: 'Decompressing Video Stream...' });

      const arrayBuffer = await videoFile.arrayBuffer();
      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
      const decodedBuffer = await audioCtx.decodeAudioData(arrayBuffer);

      const duration = decodedBuffer.duration;
      const numChunks = Math.ceil(duration / CHUNK_DURATION);

      for (let i = 0; i < numChunks; i++) {
        const start = i * CHUNK_DURATION;
        const end = Math.min(start + CHUNK_DURATION, duration);
        const frameStart = Math.floor(start * decodedBuffer.sampleRate);
        const frameEnd = Math.floor(end * decodedBuffer.sampleRate);

        const chunkBuffer = audioCtx.createBuffer(1, frameEnd - frameStart, decodedBuffer.sampleRate);
        chunkBuffer.copyToChannel(decodedBuffer.getChannelData(0).subarray(frameStart, frameEnd), 0);

        const success = await processBatchWithFailover(chunkBuffer, start, i, 0);
        if (!success) throw new Error("Neural Pipeline Collasped. Multiple engine failures detected.");

        setProgress(Math.round(((i + 1) / numChunks) * 100));
        if (i < numChunks - 1) await new Promise(r => setTimeout(r, REQUEST_GAP));
      }

      setAnalytics(prev => ({ ...prev, endTime: Date.now() }));
      setStatus({ status: 'completed', message: 'All Segments Synced & Translated.' });
      setIsProcessing(false);
    } catch (error: any) {
      setIsProcessing(false);
      setAnalytics(prev => ({ ...prev, endTime: Date.now() }));
      setStatus({ status: 'error', message: error.message });
      logIncident("Global Pipeline", "Fatal Error", error.message, "critical");
    }
  };

  const downloadSRT = () => {
    const srt = generateSRT(segments);
    const blob = new Blob([srt], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `PhilipAI_Captions.srt`;
    document.body.appendChild(a); a.click(); document.body.removeChild(a);
  };

  const globalSuccessRate = useMemo(() => {
    if (analytics.totalRequests === 0) return 0;
    return Math.round((analytics.successfulRequests / analytics.totalRequests) * 100);
  }, [analytics]);

  // Fix: Narrow startTime to a number using a local variable to prevent 'null' in arithmetic operations.
  const totalTimeElapsed = useMemo(() => {
    const start = analytics.startTime;
    if (!start) return '0s';
    const end = analytics.endTime || Date.now();
    const diff = (end - start) / 1000;
    return diff < 60 ? `${diff.toFixed(1)}s` : `${Math.floor(diff / 60)}m ${Math.floor(diff % 60)}s`;
  }, [analytics.startTime, analytics.endTime]);

  // Fix: Extract logic for average latency to avoid complex inline JSX arithmetic and improve type safety.
  const averageLatencyDisplay = useMemo(() => {
    const totalLatency = Object.values(analytics.modelMetrics).reduce(
      (acc: number, curr) => acc + (curr as ModelMetric).totalLatency,
      0
    );
    const requests = analytics.totalRequests || 1;
    return (totalLatency / requests / 1000).toFixed(2);
  }, [analytics.modelMetrics, analytics.totalRequests]);

  return (
    <div className="min-h-screen p-4 md:p-10 flex flex-col gap-8 max-w-7xl mx-auto selection:bg-emerald-500/30">
      {/* Header */}
      <header className="flex flex-col lg:flex-row items-stretch gap-6">
        <div className="flex-1 glass-panel p-8 rounded-[2.5rem] flex items-center gap-6 shadow-xl ring-1 ring-white/5 group">
          <div className="w-16 h-16 bg-emerald-500 rounded-2xl flex items-center justify-center shadow-[0_0_30px_rgba(16,185,129,0.2)] group-hover:scale-110 transition-transform duration-500">
            <svg className="w-10 h-10 text-slate-950" fill="currentColor" viewBox="0 0 24 24">
              <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 14h-2v-2h2v2zm0-4h-2V7h2v5z"/>
            </svg>
          </div>
          <div>
            <h1 className="text-4xl font-black tracking-tighter text-white">Philip<span className="text-emerald-500">AI</span></h1>
            <p className="text-[10px] font-black uppercase tracking-[0.4em] text-slate-500 mt-1 flex items-center gap-2">
              <span className={`w-1.5 h-1.5 rounded-full ${isOnline ? 'bg-emerald-500' : 'bg-red-500 animate-ping'}`} />
              {isOnline ? 'Pipeline Online' : 'Network Interrupted'}
            </p>
          </div>
        </div>

        <div className="flex-[2] glass-panel p-6 rounded-[2.5rem] flex flex-wrap items-center justify-around gap-4 shadow-xl ring-1 ring-white/5">
          {MODEL_POOL.map((model, idx) => {
            const metrics = analytics.modelMetrics[model.id];
            const failRate = metrics.success + metrics.fail > 0 ? (metrics.fail / (metrics.success + metrics.fail)) : 0;
            return (
              <div key={model.id} className={`flex items-center gap-3 px-4 py-2 rounded-xl border transition-all ${
                activeModelIndex === idx && isProcessing ? 'bg-emerald-500/10 border-emerald-500/50 shadow-lg shadow-emerald-500/10 scale-105' : 'bg-slate-900/40 border-white/5'
              } ${failRate > 0.5 ? 'border-red-500/30' : ''}`}>
                <div className={`w-2 h-2 rounded-full ${
                  activeModelIndex === idx && isProcessing ? 'bg-emerald-500 animate-pulse' : 
                  failRate > 0.8 ? 'bg-red-500' : 
                  failRate > 0.3 ? 'bg-amber-500' : 'bg-slate-600'
                }`} title={`Fail Rate: ${Math.round(failRate * 100)}%`} />
                <div>
                  <p className={`text-[10px] font-black uppercase ${activeModelIndex === idx && isProcessing ? 'text-emerald-500' : 'text-slate-400'}`}>{model.label}</p>
                  <p className="text-[8px] text-slate-600 truncate max-w-[80px]">{model.description}</p>
                </div>
              </div>
            );
          })}
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Workspace */}
        <div className="lg:col-span-8 flex flex-col gap-6">
          <div className="aspect-video bg-black rounded-[3rem] overflow-hidden border border-white/5 shadow-2xl relative ring-1 ring-white/10 group">
            {videoUrl ? (
              <video src={videoUrl} controls className="w-full h-full object-contain" />
            ) : (
              <label className="absolute inset-0 flex flex-col items-center justify-center cursor-pointer hover:bg-slate-900/50 transition-all">
                <div className="w-20 h-20 bg-slate-900 rounded-[2rem] flex items-center justify-center mb-4 border border-white/10 group-hover:border-emerald-500/50 transition-all duration-500">
                  <svg className="w-8 h-8 text-slate-500 group-hover:text-emerald-500 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg>
                </div>
                <span className="text-slate-500 font-bold uppercase tracking-widest text-xs">Import Local Source</span>
                <input type="file" className="hidden" accept="video/*" onChange={handleFileChange} />
              </label>
            )}

            {isProcessing && (
              <div className="absolute top-6 right-6 px-4 py-2 bg-slate-950/80 backdrop-blur-md rounded-xl border border-white/10 text-[10px] font-black text-emerald-500 flex items-center gap-2 shadow-xl">
                <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-ping" />
                NEURAL LINK: {progress}%
              </div>
            )}
          </div>

          <div className="flex flex-col md:flex-row gap-6">
            <div className="flex-1 glass-panel p-10 rounded-[3rem] flex flex-col md:flex-row items-center justify-between gap-8 shadow-xl border border-white/5">
              <div className="space-y-1">
                <span className="text-emerald-500 text-[10px] font-black uppercase tracking-widest">Transcription core</span>
                <h2 className="text-2xl font-bold text-white tracking-tight">Active Pipeline</h2>
                <p className="text-slate-500 text-sm">Target: Precise English SRT.</p>
              </div>
              <div className="flex gap-4 w-full md:w-auto">
                <button 
                  onClick={startProcessing}
                  disabled={!videoFile || isProcessing || !isOnline}
                  className="flex-1 md:flex-none bg-emerald-500 hover:bg-emerald-400 disabled:opacity-20 text-slate-950 font-black px-12 py-5 rounded-2xl transition-all shadow-[0_15px_40px_-10px_rgba(16,185,129,0.3)] active:scale-95"
                >
                  {!isOnline ? 'Waiting for Network' : isProcessing ? `Processing...` : 'Run Pipeline'}
                </button>
                <button 
                  onClick={downloadSRT}
                  disabled={segments.length === 0}
                  className="flex-1 md:flex-none bg-slate-800 hover:bg-slate-700 disabled:opacity-20 text-white font-bold px-10 py-5 rounded-2xl border border-white/10 transition-all"
                >
                  Export SRT
                </button>
              </div>
            </div>

            <div className={`md:w-64 glass-panel p-8 rounded-[3rem] flex flex-col justify-center items-center gap-2 shadow-xl border ${status.status === 'error' ? 'border-red-500/40' : 'border-white/5'}`}>
               <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Health Score</span>
               <div className={`text-4xl font-black ${globalSuccessRate < 40 ? 'text-red-500' : 'text-emerald-500'}`}>{globalSuccessRate}%</div>
               <div className="w-full bg-slate-900 h-1 rounded-full overflow-hidden mt-2">
                 <div className={`${globalSuccessRate < 40 ? 'bg-red-500' : 'bg-emerald-500'} h-full transition-all duration-700`} style={{ width: `${globalSuccessRate}%` }} />
               </div>
            </div>
          </div>

          <div className={`text-center px-10 py-3 rounded-2xl transition-colors ${status.status === 'error' ? 'bg-red-500/5 border border-red-500/10' : ''}`}>
            <p className={`text-[10px] font-black uppercase tracking-[0.4em] ${status.status === 'error' ? 'text-red-500' : 'text-slate-600 animate-pulse'}`}>
              {status.message} {cooldown > 0 && `(Sync Cooling ${cooldown}s)`}
            </p>
          </div>
        </div>

        {/* Sidebar Diagnostics */}
        <div className="lg:col-span-4 flex flex-col gap-6">
          <div className="glass-panel rounded-[2.5rem] p-6 shadow-xl ring-1 ring-white/10 flex flex-col">
            <h3 className="text-[10px] font-black uppercase tracking-widest text-slate-500 mb-4 flex items-center justify-between">
              <span className="flex items-center gap-2">
                <svg className="w-3 h-3 text-emerald-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
                Neural Diagnostics
              </span>
              {incidents.length > 0 && (
                <button onClick={() => setIncidents([])} className="text-red-500/50 hover:text-red-500 transition-colors">CLEAR</button>
              )}
            </h3>
            <div className="grid grid-cols-2 gap-3 mb-6">
              <div className="bg-slate-950/50 p-4 rounded-2xl border border-white/5">
                <p className="text-[8px] font-black text-slate-600 uppercase">Requests</p>
                <p className="text-lg font-bold text-white">{analytics.totalRequests}</p>
              </div>
              <div className="bg-slate-950/50 p-4 rounded-2xl border border-white/5">
                <p className="text-[8px] font-black text-slate-600 uppercase">Latency</p>
                <p className="text-lg font-bold text-white">
                  {averageLatencyDisplay}s
                </p>
              </div>
            </div>

            <div className="flex-1 max-h-[250px] overflow-y-auto custom-scrollbar space-y-2">
              {incidents.length === 0 ? (
                <div className="text-center py-10 opacity-20 text-[9px] font-black uppercase tracking-widest">No Incidents Reported</div>
              ) : (
                incidents.map((inc, i) => (
                  <div key={i} className={`text-[9px] p-3 rounded-xl border transition-all ${inc.severity === 'critical' ? 'bg-red-500/10 border-red-500/20' : 'bg-slate-900/50 border-white/5'}`}>
                    <div className="flex justify-between items-start mb-1">
                      <span className={`font-black ${inc.severity === 'critical' ? 'text-red-400' : 'text-amber-500'}`}>{inc.type}</span>
                      <span className="text-slate-600 font-mono text-[8px]">{inc.time}</span>
                    </div>
                    <p className="text-slate-400 leading-tight">[{inc.model}] {inc.detail}</p>
                  </div>
                ))
              )}
            </div>
          </div>

          {/* Stream Output */}
          <div className="glass-panel rounded-[3rem] flex-1 flex flex-col shadow-2xl overflow-hidden ring-1 ring-white/10 min-h-[400px]">
            <div className="p-8 border-b border-white/5 bg-slate-950/20 flex items-center justify-between">
              <h3 className="text-xs font-black uppercase tracking-widest text-white">Output Stream</h3>
              <span className="text-emerald-500 bg-emerald-500/10 px-3 py-1 rounded-lg text-[9px] font-black">{segments.length} UNITS</span>
            </div>

            <div className="flex-1 overflow-y-auto p-6 space-y-4 custom-scrollbar">
              {segments.length === 0 && (
                <div className="h-full flex flex-col items-center justify-center text-center opacity-10 italic text-xs space-y-3 py-20">
                  <div className="w-12 h-12 border-2 border-slate-700 border-dashed rounded-full animate-spin-slow" />
                  <p className="font-black uppercase tracking-widest">Stream Idle</p>
                </div>
              )}
              {segments.map((seg, idx) => (
                <div key={seg.id} className="bg-slate-900/40 p-5 rounded-2xl border border-white/5 hover:border-emerald-500/30 transition-all group animate-in fade-in slide-in-from-bottom-2 duration-300">
                  <div className="flex justify-between items-center mb-2">
                    <span className="text-[9px] font-black text-slate-700 uppercase">Unit {String(idx + 1).padStart(3, '0')}</span>
                    <span className="text-[9px] font-mono text-emerald-500 bg-emerald-500/5 px-2 py-1 rounded-md">
                      {Math.floor(seg.start_seconds / 60)}:{(seg.start_seconds % 60).toFixed(1).padStart(4, '0')}
                    </span>
                  </div>
                  <p className="text-slate-300 text-xs leading-relaxed font-medium group-hover:text-white transition-colors">{seg.text}</p>
                </div>
              ))}
              <div ref={transcriptEndRef} />
            </div>

            <div className="p-4 bg-slate-950/50 border-t border-white/5">
              <div className="w-full h-1 bg-slate-800 rounded-full overflow-hidden">
                <div className={`h-full bg-emerald-500 transition-all duration-1000 ${isProcessing ? 'animate-pulse' : ''}`} style={{ width: `${progress}%` }} />
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;

export type ProcessingEngine = 'titan' | 'silentwave' | 'globallink';

export interface CaptionSegment {
  id: number;
  start_seconds: number;
  end_seconds: number;
  text: string;
}

export interface ProcessingState {
  status: 'idle' | 'connecting' | 'streaming' | 'completed' | 'error';
  message: string;
}

export interface ModelMetric {
  success: number;
  fail: number;
  avgLatency: number;
  totalLatency: number;
}

export interface AnalyticsData {
  totalRequests: number;
  successfulRequests: number;
  failoverEvents: number;
  startTime: number | null;
  endTime: number | null;
  modelMetrics: Record<string, ModelMetric>;
}

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { GoogleGenAI, Type } from '@google/genai';
import { blobToBase64, audioBufferToWav, downsampleAudioBuffer } from './utils/audioUtils';
import { generateSRT } from './utils/timeFormatter';
import { ProcessingState, CaptionSegment, AnalyticsData, ModelMetric, ProcessingEngine } from './types';

// Neural Model Pool for Failover - Hierarchical order
const MODEL_POOL = [
  { id: 'gemini-3-flash-preview', label: 'Flash 3.0', description: 'Optimal Balanced Core' },
  { id: 'gemini-2.5-flash-native-audio-preview-12-2025', label: 'Audio Native 2.5', description: 'Waveform Specialist' },
  { id: 'gemini-3-pro-preview', label: 'Pro 3.0', description: 'Advanced Reasoning Logic' },
  { id: 'gemini-flash-lite-latest', label: 'Flash Lite', description: 'High-Throughput Fallback' }
];

const CHUNK_DURATION = 300; // 5-minute segments
const REQUEST_GAP = 5000; // 5s gap between batches to prevent 429

const INITIAL_ANALYTICS: AnalyticsData = {
  totalRequests: 0,
  successfulRequests: 0,
  failoverEvents: 0,
  startTime: null,
  endTime: null,
  modelMetrics: MODEL_POOL.reduce((acc, model) => {
    acc[model.id] = { success: 0, fail: 0, avgLatency: 0, totalLatency: 0 };
    return acc;
  }, {} as Record<string, ModelMetric>)
};

interface Incident {
  time: string;
  model: string;
  type: string;
  detail: string;
  severity: 'warning' | 'critical';
}

const App: React.FC = () => {
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [videoFile, setVideoFile] = useState<File | null>(null);
  const [selectedEngine, setSelectedEngine] = useState<ProcessingEngine>('titan');
  const [status, setStatus] = useState<ProcessingState>({
    status: 'idle',
    message: 'Multi-Engine System Ready.'
  });
  const [segments, setSegments] = useState<CaptionSegment[]>([]);
  const [progress, setProgress] = useState(0);
  const [isProcessing, setIsProcessing] = useState(false);
  const [activeModelIndex, setActiveModelIndex] = useState(0);
  const [cooldown, setCooldown] = useState(0);
  const [analytics, setAnalytics] = useState<AnalyticsData>(INITIAL_ANALYTICS);
  const [incidents, setIncidents] = useState<Incident[]>([]);
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  const transcriptEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleStatusChange = () => setIsOnline(navigator.onLine);
    window.addEventListener('online', handleStatusChange);
    window.addEventListener('offline', handleStatusChange);
    return () => {
      window.removeEventListener('online', handleStatusChange);
      window.removeEventListener('offline', handleStatusChange);
    };
  }, []);

  useEffect(() => {
    transcriptEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [segments]);

  useEffect(() => {
    if (cooldown > 0) {
      const timer = setTimeout(() => setCooldown(cooldown - 1), 1000);
      return () => clearTimeout(timer);
    }
  }, [cooldown]);

  const updateAnalytics = (modelId: string, latency: number, success: boolean, failover: boolean = false) => {
    setAnalytics(prev => {
      const modelMetric = prev.modelMetrics[modelId] || { success: 0, fail: 0, avgLatency: 0, totalLatency: 0 };
      const newSuccess = modelMetric.success + (success ? 1 : 0);
      const newFail = modelMetric.fail + (success ? 0 : 1);
      const newTotalLatency = modelMetric.totalLatency + latency;

      return {
        ...prev,
        totalRequests: prev.totalRequests + 1,
        successfulRequests: prev.successfulRequests + (success ? 1 : 0),
        failoverEvents: prev.failoverEvents + (failover ? 1 : 0),
        modelMetrics: {
          ...prev.modelMetrics,
          [modelId]: {
            success: newSuccess,
            fail: newFail,
            totalLatency: newTotalLatency,
            avgLatency: newTotalLatency / (newSuccess + newFail || 1)
          }
        }
      };
    });
  };

  const logIncident = (model: string, type: string, detail: string, severity: 'warning' | 'critical' = 'warning') => {
    const newIncident: Incident = {
      time: new Date().toLocaleTimeString([], { hour12: false, hour: '2-digit', minute: '2-digit', second: '2-digit' }),
      model,
      type,
      detail,
      severity
    };
    setIncidents(prev => [newIncident, ...prev].slice(0, 30));
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      setVideoFile(file);
      setVideoUrl(URL.createObjectURL(file));
      setSegments([]);
      setProgress(0);
      setIncidents([]);
      setAnalytics(INITIAL_ANALYTICS);
      setStatus({ status: 'idle', message: 'Video Imported. Engines Warm.' });
    }
  };

  const processBatchWithFailover = async (
    audioBuffer: AudioBuffer, 
    offset: number, 
    batchIndex: number, 
    poolIndex: number = 0,
    retryCount: number = 0
  ): Promise<boolean> => {
    if (poolIndex >= MODEL_POOL.length) return false;
    if (!navigator.onLine) return false;

    let targetModelId = MODEL_POOL[poolIndex].id;
    let engineLabel = "Titan Core";
    let systemInstruction = "Precisely transcribe and translate this audio into natural English. Return a JSON array of objects with: start (float seconds), end (float seconds), text (English string).";

    // Engine Specific Customization
    if (selectedEngine === 'silentwave') {
      targetModelId = 'gemini-2.5-flash-native-audio-preview-12-2025';
      engineLabel = "SilentWave (Whisper Mode)";
      systemInstruction = "Acting as a Whisper-class transcription engine, prioritize verbatim acoustic accuracy. Translate any foreign speech into standard English. Output as JSON array: [{start, end, text}].";
    } else if (selectedEngine === 'globallink') {
      targetModelId = poolIndex === 0 ? 'gemini-3-pro-preview' : MODEL_POOL[poolIndex].id;
      engineLabel = "GlobalLink (Meta/Whisper Mode)";
      systemInstruction = "Acting as a high-precision translation engine (SeamlessM4T style), perform deep semantic analysis of the audio. Translate nuanced foreign expressions into equivalent natural English idioms. Output as JSON array: [{start, end, text}].";
    }

    const currentModelLabel = selectedEngine === 'titan' ? MODEL_POOL[poolIndex].label : engineLabel;
    setActiveModelIndex(poolIndex);
    const requestStart = performance.now();

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const optimizedBuffer = await downsampleAudioBuffer(audioBuffer, 16000);
      const wavBlob = audioBufferToWav(optimizedBuffer);
      const base64Data = await blobToBase64(wavBlob);

      setStatus({ 
        status: 'streaming', 
        message: `[${engineLabel}] Processing Batch ${batchIndex + 1}...` 
      });

      const response = await ai.models.generateContent({
        model: targetModelId,
        contents: [{
          parts: [
            { inlineData: { mimeType: 'audio/wav', data: base64Data } },
            { text: systemInstruction }
          ]
        }],
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                start: { type: Type.NUMBER },
                end: { type: Type.NUMBER },
                text: { type: Type.STRING }
              },
              required: ['start', 'end', 'text']
            }
          }
        }
      });

      const latency = performance.now() - requestStart;
      updateAnalytics(targetModelId, latency, true);

      const data = JSON.parse(response.text || "[]");
      const adjustedSegments = data.map((s: any, i: number) => ({
        id: Date.now() + Math.random() + i,
        start_seconds: s.start + offset,
        end_seconds: s.end + offset,
        text: s.text
      }));

      setSegments(prev => [...prev, ...adjustedSegments].sort((a, b) => a.start_seconds - b.start_seconds));
      return true;
    } catch (error: any) {
      const latency = performance.now() - requestStart;
      const errMsg = error.message || String(error);
      const isQuota = errMsg.includes("429") || errMsg.includes("RESOURCE_EXHAUSTED");

      logIncident(currentModelLabel, isQuota ? "Quota" : "Fault", errMsg, isQuota ? 'warning' : 'critical');
      updateAnalytics(targetModelId, latency, false, isQuota);

      if (isQuota && selectedEngine === 'titan' && poolIndex < MODEL_POOL.length - 1) {
        setStatus({ status: 'connecting', message: `Failover Active...` });
        await new Promise(r => setTimeout(r, 10000));
        return processBatchWithFailover(audioBuffer, offset, batchIndex, poolIndex + 1, 0);
      } else if (retryCount < 1) {
        setStatus({ status: 'connecting', message: `Engine Syncing...` });
        await new Promise(r => setTimeout(r, 5000));
        return processBatchWithFailover(audioBuffer, offset, batchIndex, poolIndex, retryCount + 1);
      }

      return false;
    }
  };

  const startProcessing = async () => {
    if (!videoFile || isProcessing) return;

    try {
      setIsProcessing(true);
      setAnalytics(prev => ({ ...prev, startTime: Date.now(), endTime: null }));
      setStatus({ status: 'connecting', message: 'Initiating Neural Link...' });

      const arrayBuffer = await videoFile.arrayBuffer();
      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
      const decodedBuffer = await audioCtx.decodeAudioData(arrayBuffer);

      const duration = decodedBuffer.duration;
      const numChunks = Math.ceil(duration / CHUNK_DURATION);

      for (let i = 0; i < numChunks; i++) {
        const start = i * CHUNK_DURATION;
        const end = Math.min(start + CHUNK_DURATION, duration);
        const frameStart = Math.floor(start * decodedBuffer.sampleRate);
        const frameEnd = Math.floor(end * decodedBuffer.sampleRate);

        const chunkBuffer = audioCtx.createBuffer(1, frameEnd - frameStart, decodedBuffer.sampleRate);
        chunkBuffer.copyToChannel(decodedBuffer.getChannelData(0).subarray(frameStart, frameEnd), 0);

        const success = await processBatchWithFailover(chunkBuffer, start, i, 0);
        if (!success) throw new Error("Total Pipeline Collapse. Try swapping engines.");

        setProgress(Math.round(((i + 1) / numChunks) * 100));
        if (i < numChunks - 1) await new Promise(r => setTimeout(r, REQUEST_GAP));
      }

      setAnalytics(prev => ({ ...prev, endTime: Date.now() }));
      setStatus({ status: 'completed', message: 'Processing Stream Completed.' });
      setIsProcessing(false);
    } catch (error: any) {
      setIsProcessing(false);
      setAnalytics(prev => ({ ...prev, endTime: Date.now() }));
      setStatus({ status: 'error', message: error.message });
      logIncident("Pipeline", "Fatal", error.message, "critical");
    }
  };

  const downloadSRT = () => {
    const srt = generateSRT(segments);
    const blob = new Blob([srt], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `PhilipAI_Captions.srt`;
    document.body.appendChild(a); a.click(); document.body.removeChild(a);
  };

  const globalSuccessRate = useMemo(() => {
    if (analytics.totalRequests === 0) return 0;
    return Math.round((analytics.successfulRequests / analytics.totalRequests) * 100);
  }, [analytics]);

  const totalTimeElapsed = useMemo(() => {
    const start = analytics.startTime;
    if (!start) return '0s';
    const end = analytics.endTime || Date.now();
    const diff = (end - start) / 1000;
    return diff < 60 ? `${diff.toFixed(1)}s` : `${Math.floor(diff / 60)}m ${Math.floor(diff % 60)}s`;
  }, [analytics.startTime, analytics.endTime]);

  const averageLatencyDisplay = useMemo(() => {
    const totalLatency = Object.values(analytics.modelMetrics).reduce((acc: number, curr) => acc + (curr as ModelMetric).totalLatency, 0);
    const requests = analytics.totalRequests || 1;
    return (totalLatency / requests / 1000).toFixed(2);
  }, [analytics.modelMetrics, analytics.totalRequests]);

  return (
    <div className="min-h-screen p-4 md:p-10 flex flex-col gap-8 max-w-7xl mx-auto selection:bg-emerald-500/30">
      {/* Header */}
      <header className="flex flex-col lg:flex-row items-stretch gap-6">
        <div className="flex-1 glass-panel p-8 rounded-[2.5rem] flex items-center gap-6 shadow-xl ring-1 ring-white/5">
          <div className="w-16 h-16 bg-emerald-500 rounded-2xl flex items-center justify-center shadow-[0_0_30px_rgba(16,185,129,0.2)]">
            <svg className="w-10 h-10 text-slate-950" fill="currentColor" viewBox="0 0 24 24">
              <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 14h-2v-2h2v2zm0-4h-2V7h2v5z"/>
            </svg>
          </div>
          <div>
            <h1 className="text-4xl font-black tracking-tighter text-white">Philip<span className="text-emerald-500">AI</span></h1>
            <p className="text-[10px] font-black uppercase tracking-[0.4em] text-slate-500 mt-1 flex items-center gap-2">
              <span className={`w-1.5 h-1.5 rounded-full ${isOnline ? 'bg-emerald-500' : 'bg-red-500 animate-ping'}`} />
              {isOnline ? 'Pipeline Online' : 'Network Offline'}
            </p>
          </div>
        </div>

        {/* Engine Selection Matrix */}
        <div className="flex-[2] glass-panel p-4 rounded-[2.5rem] grid grid-cols-1 md:grid-cols-3 gap-3 shadow-xl ring-1 ring-white/5">
          {[
            { id: 'titan', name: 'Titan Core', desc: 'Gemini Standard', icon: 'M13 10V3L4 14h7v7l9-11h-7z', color: 'text-blue-400' },
            { id: 'silentwave', name: 'SilentWave', desc: 'Whisper Specialized', icon: 'M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z', color: 'text-purple-400' },
            { id: 'globallink', name: 'GlobalLink', desc: 'Meta Optimized', icon: 'M3.055 11H5a2 2 0 012 2v1a2 2 0 002 2 2 2 0 012 2v2.945M8 3.935V5.5A2.5 2.5 0 0010.5 8h.5a2 2 0 012 2 2 2 0 104 0 2 2 0 012-2h1.065', color: 'text-amber-400' }
          ].map((engine) => (
            <button
              key={engine.id}
              disabled={isProcessing}
              onClick={() => setSelectedEngine(engine.id as ProcessingEngine)}
              className={`p-4 rounded-3xl border transition-all text-left flex flex-col gap-1 relative overflow-hidden group ${
                selectedEngine === engine.id 
                  ? 'bg-white/5 border-emerald-500/40 shadow-lg' 
                  : 'bg-transparent border-white/5 opacity-50 hover:opacity-100 hover:border-white/10'
              }`}
            >
              <div className="flex items-center gap-2">
                <svg className={`w-4 h-4 ${engine.color}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d={engine.icon} /></svg>
                <span className="text-xs font-black text-white uppercase">{engine.name}</span>
              </div>
              <p className="text-[9px] text-slate-500 font-medium leading-tight">{engine.desc}</p>
              {selectedEngine === engine.id && <div className="absolute top-0 right-0 p-2"><div className="w-1 h-1 bg-emerald-500 rounded-full animate-ping" /></div>}
            </button>
          ))}
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Workspace */}
        <div className="lg:col-span-8 flex flex-col gap-6">
          <div className="aspect-video bg-black rounded-[3rem] overflow-hidden border border-white/5 shadow-2xl relative ring-1 ring-white/10 group">
            {videoUrl ? (
              <video src={videoUrl} controls className="w-full h-full object-contain" />
            ) : (
              <label className="absolute inset-0 flex flex-col items-center justify-center cursor-pointer hover:bg-slate-900/50 transition-all">
                <div className="w-20 h-20 bg-slate-900 rounded-[2rem] flex items-center justify-center mb-4 border border-white/10 group-hover:border-emerald-500/50 transition-all duration-500">
                  <svg className="w-8 h-8 text-slate-500 group-hover:text-emerald-500 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg>
                </div>
                <span className="text-slate-500 font-bold uppercase tracking-widest text-xs">Import Local Source</span>
                <input type="file" className="hidden" accept="video/*" onChange={handleFileChange} />
              </label>
            )}

            {isProcessing && (
              <div className="absolute top-6 right-6 px-4 py-2 bg-slate-950/80 backdrop-blur-md rounded-xl border border-white/10 text-[10px] font-black text-emerald-500 flex items-center gap-2 shadow-xl">
                <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-ping" />
                LINKING: {progress}%
              </div>
            )}
          </div>

          <div className="flex flex-col md:flex-row gap-6">
            <div className="flex-1 glass-panel p-10 rounded-[3rem] flex flex-col md:flex-row items-center justify-between gap-8 shadow-xl border border-white/5">
              <div className="space-y-1">
                <span className="text-emerald-500 text-[10px] font-black uppercase tracking-widest">Active Core: {selectedEngine.toUpperCase()}</span>
                <h2 className="text-2xl font-bold text-white tracking-tight">Neural Pipeline</h2>
                <p className="text-slate-500 text-sm">Processing for YouTube-ready SRT.</p>
              </div>
              <div className="flex gap-4 w-full md:w-auto">
                <button 
                  onClick={startProcessing}
                  disabled={!videoFile || isProcessing || !isOnline}
                  className="flex-1 md:flex-none bg-emerald-500 hover:bg-emerald-400 disabled:opacity-20 text-slate-950 font-black px-12 py-5 rounded-2xl transition-all shadow-[0_15px_40px_-10px_rgba(16,185,129,0.3)] active:scale-95"
                >
                  {isProcessing ? `Running...` : 'Run Engine'}
                </button>
                <button 
                  onClick={downloadSRT}
                  disabled={segments.length === 0}
                  className="flex-1 md:flex-none bg-slate-800 hover:bg-slate-700 disabled:opacity-20 text-white font-bold px-10 py-5 rounded-2xl border border-white/10 transition-all"
                >
                  Export SRT
                </button>
              </div>
            </div>

            <div className={`md:w-64 glass-panel p-8 rounded-[3rem] flex flex-col justify-center items-center gap-2 shadow-xl border ${status.status === 'error' ? 'border-red-500/40' : 'border-white/5'}`}>
               <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Efficiency Score</span>
               <div className={`text-4xl font-black ${globalSuccessRate < 40 ? 'text-red-500' : 'text-emerald-500'}`}>{globalSuccessRate}%</div>
               <div className="w-full bg-slate-900 h-1 rounded-full overflow-hidden mt-2">
                 <div className={`${globalSuccessRate < 40 ? 'bg-red-500' : 'bg-emerald-500'} h-full transition-all duration-700`} style={{ width: `${globalSuccessRate}%` }} />
               </div>
            </div>
          </div>

          <div className={`text-center px-10 py-3 rounded-2xl transition-colors ${status.status === 'error' ? 'bg-red-500/5 border border-red-500/10' : ''}`}>
            <p className={`text-[10px] font-black uppercase tracking-[0.4em] ${status.status === 'error' ? 'text-red-500' : 'text-slate-600 animate-pulse'}`}>
              {status.message} {cooldown > 0 && `(Cooling ${cooldown}s)`}
            </p>
          </div>
        </div>

        {/* Sidebar */}
        <div className="lg:col-span-4 flex flex-col gap-6">
          <div className="glass-panel rounded-[2.5rem] p-6 shadow-xl ring-1 ring-white/10 flex flex-col">
            <h3 className="text-[10px] font-black uppercase tracking-widest text-slate-500 mb-4 flex items-center justify-between">
              <span>Diagnostics</span>
              <span className="text-emerald-500/50">ENGINE: {selectedEngine}</span>
            </h3>
            <div className="grid grid-cols-2 gap-3 mb-6">
              <div className="bg-slate-950/50 p-4 rounded-2xl border border-white/5">
                <p className="text-[8px] font-black text-slate-600 uppercase">Requests</p>
                <p className="text-lg font-bold text-white">{analytics.totalRequests}</p>
              </div>
              <div className="bg-slate-950/50 p-4 rounded-2xl border border-white/5">
                <p className="text-[8px] font-black text-slate-600 uppercase">Avg Latency</p>
                <p className="text-lg font-bold text-white">{averageLatencyDisplay}s</p>
              </div>
            </div>

            <div className="flex-1 max-h-[250px] overflow-y-auto custom-scrollbar space-y-2">
              {incidents.length === 0 ? (
                <div className="text-center py-10 opacity-20 text-[9px] font-black uppercase tracking-widest">Neural Streams Nominal</div>
              ) : (
                incidents.map((inc, i) => (
                  <div key={i} className={`text-[9px] p-3 rounded-xl border transition-all ${inc.severity === 'critical' ? 'bg-red-500/10 border-red-500/20' : 'bg-slate-900/50 border-white/5'}`}>
                    <div className="flex justify-between items-start mb-1">
                      <span className={`font-black ${inc.severity === 'critical' ? 'text-red-400' : 'text-amber-500'}`}>{inc.type}</span>
                      <span className="text-slate-600 font-mono text-[8px]">{inc.time}</span>
                    </div>
                    <p className="text-slate-400 leading-tight">[{inc.model}] {inc.detail}</p>
                  </div>
                ))
              )}
            </div>
          </div>

          {/* Stream Output */}
          <div className="glass-panel rounded-[3rem] flex-1 flex flex-col shadow-2xl overflow-hidden ring-1 ring-white/10 min-h-[400px]">
            <div className="p-8 border-b border-white/5 bg-slate-950/20 flex items-center justify-between">
              <h3 className="text-xs font-black uppercase tracking-widest text-white">Neural Stream</h3>
              <span className="text-emerald-500 bg-emerald-500/10 px-3 py-1 rounded-lg text-[9px] font-black">{segments.length} BLOCKS</span>
            </div>

            <div className="flex-1 overflow-y-auto p-6 space-y-4 custom-scrollbar">
              {segments.length === 0 && (
                <div className="h-full flex flex-col items-center justify-center text-center opacity-10 italic text-xs space-y-3 py-20">
                  <div className="w-12 h-12 border-2 border-slate-700 border-dashed rounded-full animate-spin-slow" />
                  <p className="font-black uppercase tracking-widest">Waiting for Input...</p>
                </div>
              )}
              {segments.map((seg, idx) => (
                <div key={seg.id} className="bg-slate-900/40 p-5 rounded-2xl border border-white/5 hover:border-emerald-500/30 transition-all group animate-in fade-in slide-in-from-bottom-2 duration-300">
                  <div className="flex justify-between items-center mb-2">
                    <span className="text-[9px] font-black text-slate-700 uppercase">Segment {String(idx + 1).padStart(3, '0')}</span>
                    <span className="text-[9px] font-mono text-emerald-500 bg-emerald-500/5 px-2 py-1 rounded-md">
                      {Math.floor(seg.start_seconds / 60)}:{(seg.start_seconds % 60).toFixed(1).padStart(4, '0')}
                    </span>
                  </div>
                  <p className="text-slate-300 text-xs leading-relaxed font-medium group-hover:text-white transition-colors">{seg.text}</p>
                </div>
              ))}
              <div ref={transcriptEndRef} />
            </div>

            <div className="p-4 bg-slate-950/50 border-t border-white/5">
              <div className="w-full h-1 bg-slate-800 rounded-full overflow-hidden">
                <div className={`h-full bg-emerald-500 transition-all duration-1000 ${isProcessing ? 'animate-pulse' : ''}`} style={{ width: `${progress}%` }} />
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { GoogleGenAI, Type } from '@google/genai';
import { blobToBase64, audioBufferToWav, downsampleAudioBuffer } from './utils/audioUtils';
import { generateSRT } from './utils/timeFormatter';
import { ProcessingState, CaptionSegment, AnalyticsData, ModelMetric, ProcessingEngine } from './types';

// Neural Model Pool for Failover - Hierarchical order
const MODEL_POOL = [
  { id: 'gemini-3-flash-preview', label: 'Flash 3.0', description: 'Optimal Balanced Core' },
  { id: 'gemini-2.5-flash-native-audio-preview-12-2025', label: 'Audio Native 2.5', description: 'Waveform Specialist' },
  { id: 'gemini-3-pro-preview', label: 'Pro 3.0', description: 'Advanced Reasoning Logic' },
  { id: 'gemini-flash-lite-latest', label: 'Flash Lite', description: 'High-Throughput Fallback' }
];

const CHUNK_DURATION = 300; // 5-minute segments
const REQUEST_GAP = 5000; // 5s gap between batches to prevent 429

const INITIAL_ANALYTICS: AnalyticsData = {
  totalRequests: 0,
  successfulRequests: 0,
  failoverEvents: 0,
  startTime: null,
  endTime: null,
  modelMetrics: MODEL_POOL.reduce((acc, model) => {
    acc[model.id] = { success: 0, fail: 0, avgLatency: 0, totalLatency: 0 };
    return acc;
  }, {} as Record<string, ModelMetric>)
};

interface Incident {
  time: string;
  model: string;
  type: string;
  detail: string;
  severity: 'warning' | 'critical';
}

const App: React.FC = () => {
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [videoFile, setVideoFile] = useState<File | null>(null);
  const [selectedEngine, setSelectedEngine] = useState<ProcessingEngine>('titan');
  const [status, setStatus] = useState<ProcessingState>({
    status: 'idle',
    message: 'Multi-Engine System Ready.'
  });
  const [segments, setSegments] = useState<CaptionSegment[]>([]);
  const [progress, setProgress] = useState(0);
  const [isProcessing, setIsProcessing] = useState(false);
  const [activeModelIndex, setActiveModelIndex] = useState(0);
  const [cooldown, setCooldown] = useState(0);
  const [analytics, setAnalytics] = useState<AnalyticsData>(INITIAL_ANALYTICS);
  const [incidents, setIncidents] = useState<Incident[]>([]);
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  const transcriptEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleStatusChange = () => setIsOnline(navigator.onLine);
    window.addEventListener('online', handleStatusChange);
    window.addEventListener('offline', handleStatusChange);
    return () => {
      window.removeEventListener('online', handleStatusChange);
      window.removeEventListener('offline', handleStatusChange);
    };
  }, []);

  useEffect(() => {
    transcriptEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [segments]);

  useEffect(() => {
    if (cooldown > 0) {
      const timer = setTimeout(() => setCooldown(cooldown - 1), 1000);
      return () => clearTimeout(timer);
    }
  }, [cooldown]);

  const updateAnalytics = (modelId: string, latency: number, success: boolean, failover: boolean = false) => {
    setAnalytics(prev => {
      const modelMetric = prev.modelMetrics[modelId] || { success: 0, fail: 0, avgLatency: 0, totalLatency: 0 };
      const newSuccess = modelMetric.success + (success ? 1 : 0);
      const newFail = modelMetric.fail + (success ? 0 : 1);
      const newTotalLatency = modelMetric.totalLatency + latency;

      return {
        ...prev,
        totalRequests: prev.totalRequests + 1,
        successfulRequests: prev.successfulRequests + (success ? 1 : 0),
        failoverEvents: prev.failoverEvents + (failover ? 1 : 0),
        modelMetrics: {
          ...prev.modelMetrics,
          [modelId]: {
            success: newSuccess,
            fail: newFail,
            totalLatency: newTotalLatency,
            avgLatency: newTotalLatency / (newSuccess + newFail || 1)
          }
        }
      };
    });
  };

  const logIncident = (model: string, type: string, detail: string, severity: 'warning' | 'critical' = 'warning') => {
    const newIncident: Incident = {
      time: new Date().toLocaleTimeString([], { hour12: false, hour: '2-digit', minute: '2-digit', second: '2-digit' }),
      model,
      type,
      detail,
      severity
    };
    setIncidents(prev => [newIncident, ...prev].slice(0, 30));
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      setVideoFile(file);
      setVideoUrl(URL.createObjectURL(file));
      setSegments([]);
      setProgress(0);
      setIncidents([]);
      setAnalytics(INITIAL_ANALYTICS);
      setStatus({ status: 'idle', message: 'Video Imported. Engines Warm.' });
    }
  };

  const processBatchWithFailover = async (
    audioBuffer: AudioBuffer, 
    offset: number, 
    batchIndex: number, 
    poolIndex: number = 0,
    retryCount: number = 0
  ): Promise<boolean> => {
    if (poolIndex >= MODEL_POOL.length) return false;
    if (!navigator.onLine) return false;

    let targetModelId = MODEL_POOL[poolIndex].id;
    let engineLabel = "Titan Core";
    let systemInstruction = "Precisely transcribe and translate this audio into natural English. Return a JSON array of objects with: start (float seconds), end (float seconds), text (English string).";

    // Engine Specific Customization
    if (selectedEngine === 'silentwave') {
      targetModelId = 'gemini-2.5-flash-native-audio-preview-12-2025';
      engineLabel = "SilentWave (Whisper Mode)";
      systemInstruction = "Acting as a Whisper-class transcription engine, prioritize verbatim acoustic accuracy. Translate any foreign speech into standard English. Output as JSON array: [{start, end, text}].";
    } else if (selectedEngine === 'globallink') {
      targetModelId = poolIndex === 0 ? 'gemini-3-pro-preview' : MODEL_POOL[poolIndex].id;
      engineLabel = "GlobalLink (Meta/Whisper Mode)";
      systemInstruction = "Acting as a high-precision translation engine (SeamlessM4T style), perform deep semantic analysis of the audio. Translate nuanced foreign expressions into equivalent natural English idioms. Output as JSON array: [{start, end, text}].";
    }

    const currentModelLabel = selectedEngine === 'titan' ? MODEL_POOL[poolIndex].label : engineLabel;
    setActiveModelIndex(poolIndex);
    const requestStart = performance.now();

    try {
      // Create fresh instance per request to handle potential key updates or session isolation
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const optimizedBuffer = await downsampleAudioBuffer(audioBuffer, 16000);
      const wavBlob = audioBufferToWav(optimizedBuffer);
      const base64Data = await blobToBase64(wavBlob);

      setStatus({ 
        status: 'streaming', 
        message: `[${engineLabel}] Processing Batch ${batchIndex + 1}...` 
      });

      const response = await ai.models.generateContent({
        model: targetModelId,
        contents: [{
          parts: [
            { inlineData: { mimeType: 'audio/wav', data: base64Data } },
            { text: systemInstruction }
          ]
        }],
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                start: { type: Type.NUMBER },
                end: { type: Type.NUMBER },
                text: { type: Type.STRING }
              },
              required: ['start', 'end', 'text']
            }
          }
        }
      });

      const latency = performance.now() - requestStart;
      updateAnalytics(targetModelId, latency, true);

      const data = JSON.parse(response.text || "[]");
      const adjustedSegments = data.map((s: any, i: number) => ({
        id: Date.now() + Math.random() + i,
        start_seconds: s.start + offset,
        end_seconds: s.end + offset,
        text: s.text
      }));

      setSegments(prev => [...prev, ...adjustedSegments].sort((a, b) => a.start_seconds - b.start_seconds));
      return true;
    } catch (error: any) {
      const latency = performance.now() - requestStart;
      const errMsg = error.message || String(error);
      const isQuota = errMsg.includes("429") || errMsg.includes("RESOURCE_EXHAUSTED");

      logIncident(currentModelLabel, isQuota ? "Quota" : "Fault", errMsg, isQuota ? 'warning' : 'critical');
      updateAnalytics(targetModelId, latency, false, isQuota);

      if (isQuota && selectedEngine === 'titan' && poolIndex < MODEL_POOL.length - 1) {
        setStatus({ status: 'connecting', message: `Failover Active...` });
        await new Promise(r => setTimeout(r, 10000));
        return processBatchWithFailover(audioBuffer, offset, batchIndex, poolIndex + 1, 0);
      } else if (retryCount < 1) {
        setStatus({ status: 'connecting', message: `Engine Syncing...` });
        await new Promise(r => setTimeout(r, 5000));
        return processBatchWithFailover(audioBuffer, offset, batchIndex, poolIndex, retryCount + 1);
      }

      return false;
    }
  };

  const startProcessing = async () => {
    if (!videoFile || isProcessing) return;

    try {
      setIsProcessing(true);
      setAnalytics(prev => ({ ...prev, startTime: Date.now(), endTime: null }));
      setStatus({ status: 'connecting', message: 'Initiating Neural Link...' });

      const arrayBuffer = await videoFile.arrayBuffer();
      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
      const decodedBuffer = await audioCtx.decodeAudioData(arrayBuffer);

      const duration = decodedBuffer.duration;
      const numChunks = Math.ceil(duration / CHUNK_DURATION);

      for (let i = 0; i < numChunks; i++) {
        const start = i * CHUNK_DURATION;
        const end = Math.min(start + CHUNK_DURATION, duration);
        const frameStart = Math.floor(start * decodedBuffer.sampleRate);
        const frameEnd = Math.floor(end * decodedBuffer.sampleRate);

        const chunkBuffer = audioCtx.createBuffer(1, frameEnd - frameStart, decodedBuffer.sampleRate);
        chunkBuffer.copyToChannel(decodedBuffer.getChannelData(0).subarray(frameStart, frameEnd), 0);

        const success = await processBatchWithFailover(chunkBuffer, start, i, 0);
        if (!success) throw new Error("Total Pipeline Collapse. Try swapping engines.");

        setProgress(Math.round(((i + 1) / numChunks) * 100));
        if (i < numChunks - 1) await new Promise(r => setTimeout(r, REQUEST_GAP));
      }

      setAnalytics(prev => ({ ...prev, endTime: Date.now() }));
      setStatus({ status: 'completed', message: 'Processing Stream Completed.' });
      setIsProcessing(false);
    } catch (error: any) {
      setIsProcessing(false);
      setAnalytics(prev => ({ ...prev, endTime: Date.now() }));
      setStatus({ status: 'error', message: error.message });
      logIncident("Pipeline", "Fatal", error.message, "critical");
    }
  };

  const downloadSRT = () => {
    const srt = generateSRT(segments);
    const blob = new Blob([srt], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `PhilipAI_Captions.srt`;
    document.body.appendChild(a); a.click(); document.body.removeChild(a);
  };

  const globalSuccessRate = useMemo(() => {
    if (analytics.totalRequests === 0) return 0;
    return Math.round((analytics.successfulRequests / analytics.totalRequests) * 100);
  }, [analytics]);

  const totalTimeElapsed = useMemo(() => {
    // Fix type error by explicitly checking for null and ensuring start/end are numbers for arithmetic operations
    const start = analytics.startTime;
    if (start === null) return '0s';

    const end = analytics.endTime !== null ? analytics.endTime : Date.now();
    const diff = (end - start) / 1000;
    return diff < 60 ? `${diff.toFixed(1)}s` : `${Math.floor(diff / 60)}m ${Math.floor(diff % 60)}s`;
  }, [analytics.startTime, analytics.endTime]);

  const averageLatencyDisplay = useMemo(() => {
    const totalLatency = Object.values(analytics.modelMetrics).reduce((acc: number, curr) => acc + (curr as ModelMetric).totalLatency, 0);
    const requests = analytics.totalRequests || 1;
    return (totalLatency / requests / 1000).toFixed(2);
  }, [analytics.modelMetrics, analytics.totalRequests]);

  return (
    <div className="min-h-screen p-4 md:p-10 flex flex-col gap-8 max-w-7xl mx-auto selection:bg-emerald-500/30">
      {/* Header */}
      <header className="flex flex-col lg:flex-row items-stretch gap-6">
        <div className="flex-1 glass-panel p-8 rounded-[2.5rem] flex items-center gap-6 shadow-xl ring-1 ring-white/5">
          <div className="w-16 h-16 bg-emerald-500 rounded-2xl flex items-center justify-center shadow-[0_0_30px_rgba(16,185,129,0.2)]">
            <svg className="w-10 h-10 text-slate-950" fill="currentColor" viewBox="0 0 24 24">
              <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 14h-2v-2h2v2zm0-4h-2V7h2v5z"/>
            </svg>
          </div>
          <div>
            <h1 className="text-4xl font-black tracking-tighter text-white">Philip<span className="text-emerald-500">AI</span></h1>
            <p className="text-[10px] font-black uppercase tracking-[0.4em] text-slate-500 mt-1 flex items-center gap-2">
              <span className={`w-1.5 h-1.5 rounded-full ${isOnline ? 'bg-emerald-500' : 'bg-red-500 animate-ping'}`} />
              {isOnline ? 'Pipeline Online' : 'Network Offline'}
            </p>
          </div>
        </div>

        {/* Engine Selection Matrix */}
        <div className="flex-[2] glass-panel p-4 rounded-[2.5rem] grid grid-cols-1 md:grid-cols-3 gap-3 shadow-xl ring-1 ring-white/5">
          {[
            { id: 'titan', name: 'Titan Core', desc: 'Gemini Standard', icon: 'M13 10V3L4 14h7v7l9-11h-7z', color: 'text-blue-400' },
            { id: 'silentwave', name: 'SilentWave', desc: 'Whisper Specialized', icon: 'M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z', color: 'text-purple-400' },
            { id: 'globallink', name: 'GlobalLink', desc: 'Meta Optimized', icon: 'M3.055 11H5a2 2 0 012 2v1a2 2 0 002 2 2 2 0 012 2v2.945M8 3.935V5.5A2.5 2.5 0 0010.5 8h.5a2 2 0 012 2 2 2 0 104 0 2 2 0 012-2h1.065', color: 'text-amber-400' }
          ].map((engine) => (
            <button
              key={engine.id}
              disabled={isProcessing}
              onClick={() => setSelectedEngine(engine.id as ProcessingEngine)}
              className={`p-4 rounded-3xl border transition-all text-left flex flex-col gap-1 relative overflow-hidden group ${
                selectedEngine === engine.id 
                  ? 'bg-white/5 border-emerald-500/40 shadow-lg' 
                  : 'bg-transparent border-white/5 opacity-50 hover:opacity-100 hover:border-white/10'
              }`}
            >
              <div className="flex items-center gap-2">
                <svg className={`w-4 h-4 ${engine.color}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d={engine.icon} /></svg>
                <span className="text-xs font-black text-white uppercase">{engine.name}</span>
              </div>
              <p className="text-[9px] text-slate-500 font-medium leading-tight">{engine.desc}</p>
              {selectedEngine === engine.id && <div className="absolute top-0 right-0 p-2"><div className="w-1 h-1 bg-emerald-500 rounded-full animate-ping" /></div>}
            </button>
          ))}
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Workspace */}
        <div className="lg:col-span-8 flex flex-col gap-6">
          <div className="aspect-video bg-black rounded-[3rem] overflow-hidden border border-white/5 shadow-2xl relative ring-1 ring-white/10 group">
            {videoUrl ? (
              <video src={videoUrl} controls className="w-full h-full object-contain" />
            ) : (
              <label className="absolute inset-0 flex flex-col items-center justify-center cursor-pointer hover:bg-slate-900/50 transition-all">
                <div className="w-20 h-20 bg-slate-900 rounded-[2rem] flex items-center justify-center mb-4 border border-white/10 group-hover:border-emerald-500/50 transition-all duration-500">
                  <svg className="w-8 h-8 text-slate-500 group-hover:text-emerald-500 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg>
                </div>
                <span className="text-slate-500 font-bold uppercase tracking-widest text-xs">Import Local Source</span>
                <input type="file" className="hidden" accept="video/*" onChange={handleFileChange} />
              </label>
            )}

            {isProcessing && (
              <div className="absolute top-6 right-6 px-4 py-2 bg-slate-950/80 backdrop-blur-md rounded-xl border border-white/10 text-[10px] font-black text-emerald-500 flex items-center gap-2 shadow-xl">
                <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-ping" />
                LINKING: {progress}%
              </div>
            )}
          </div>

          <div className="flex flex-col md:flex-row gap-6">
            <div className="flex-1 glass-panel p-10 rounded-[3rem] flex flex-col md:flex-row items-center justify-between gap-8 shadow-xl border border-white/5">
              <div className="space-y-1">
                <span className="text-emerald-500 text-[10px] font-black uppercase tracking-widest">Active Core: {selectedEngine.toUpperCase()}</span>
                <h2 className="text-2xl font-bold text-white tracking-tight">Neural Pipeline</h2>
                <p className="text-slate-500 text-sm">Processing for YouTube-ready SRT.</p>
              </div>
              <div className="flex gap-4 w-full md:w-auto">
                <button 
                  onClick={startProcessing}
                  disabled={!videoFile || isProcessing || !isOnline}
                  className="flex-1 md:flex-none bg-emerald-500 hover:bg-emerald-400 disabled:opacity-20 text-slate-950 font-black px-12 py-5 rounded-2xl transition-all shadow-[0_15px_40px_-10px_rgba(16,185,129,0.3)] active:scale-95"
                >
                  {isProcessing ? `Running...` : 'Run Engine'}
                </button>
                <button 
                  onClick={downloadSRT}
                  disabled={segments.length === 0}
                  className="flex-1 md:flex-none bg-slate-800 hover:bg-slate-700 disabled:opacity-20 text-white font-bold px-10 py-5 rounded-2xl border border-white/10 transition-all"
                >
                  Export SRT
                </button>
              </div>
            </div>

            <div className={`md:w-64 glass-panel p-8 rounded-[3rem] flex flex-col justify-center items-center gap-2 shadow-xl border ${status.status === 'error' ? 'border-red-500/40' : 'border-white/5'}`}>
               <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Efficiency Score</span>
               <div className={`text-4xl font-black ${globalSuccessRate < 40 ? 'text-red-500' : 'text-emerald-500'}`}>{globalSuccessRate}%</div>
               <div className="w-full bg-slate-900 h-1 rounded-full overflow-hidden mt-2">
                 <div className={`${globalSuccessRate < 40 ? 'bg-red-500' : 'bg-emerald-500'} h-full transition-all duration-700`} style={{ width: `${globalSuccessRate}%` }} />
               </div>
            </div>
          </div>

          <div className={`text-center px-10 py-3 rounded-2xl transition-colors ${status.status === 'error' ? 'bg-red-500/5 border border-red-500/10' : ''}`}>
            <p className={`text-[10px] font-black uppercase tracking-[0.4em] ${status.status === 'error' ? 'text-red-500' : 'text-slate-600 animate-pulse'}`}>
              {status.message} {cooldown > 0 && `(Cooling ${cooldown}s)`}
            </p>
          </div>
        </div>

        {/* Sidebar */}
        <div className="lg:col-span-4 flex flex-col gap-6">
          <div className="glass-panel rounded-[2.5rem] p-6 shadow-xl ring-1 ring-white/10 flex flex-col">
            <h3 className="text-[10px] font-black uppercase tracking-widest text-slate-500 mb-4 flex items-center justify-between">
              <span>Diagnostics</span>
              <span className="text-emerald-500/50">ENGINE: {selectedEngine}</span>
            </h3>
            <div className="grid grid-cols-2 gap-3 mb-6">
              <div className="bg-slate-950/50 p-4 rounded-2xl border border-white/5">
                <p className="text-[8px] font-black text-slate-600 uppercase">Requests</p>
                <p className="text-lg font-bold text-white">{analytics.totalRequests}</p>
              </div>
              <div className="bg-slate-950/50 p-4 rounded-2xl border border-white/5">
                <p className="text-[8px] font-black text-slate-600 uppercase">Avg Latency</p>
                <p className="text-lg font-bold text-white">{averageLatencyDisplay}s</p>
              </div>
            </div>

            <div className="flex-1 max-h-[250px] overflow-y-auto custom-scrollbar space-y-2">
              {incidents.length === 0 ? (
                <div className="text-center py-10 opacity-20 text-[9px] font-black uppercase tracking-widest">Neural Streams Nominal</div>
              ) : (
                incidents.map((inc, i) => (
                  <div key={i} className={`text-[9px] p-3 rounded-xl border transition-all ${inc.severity === 'critical' ? 'bg-red-500/10 border-red-500/20' : 'bg-slate-900/50 border-white/5'}`}>
                    <div className="flex justify-between items-start mb-1">
                      <span className={`font-black ${inc.severity === 'critical' ? 'text-red-400' : 'text-amber-500'}`}>{inc.type}</span>
                      <span className="text-slate-600 font-mono text-[8px]">{inc.time}</span>
                    </div>
                    <p className="text-slate-400 leading-tight">[{inc.model}] {inc.detail}</p>
                  </div>
                ))
              )}
            </div>
          </div>

          {/* Stream Output */}
          <div className="glass-panel rounded-[3rem] flex-1 flex flex-col shadow-2xl overflow-hidden ring-1 ring-white/10 min-h-[400px]">
            <div className="p-8 border-b border-white/5 bg-slate-950/20 flex items-center justify-between">
              <h3 className="text-xs font-black uppercase tracking-widest text-white">Neural Stream</h3>
              <span className="text-emerald-500 bg-emerald-500/10 px-3 py-1 rounded-lg text-[9px] font-black">{segments.length} BLOCKS</span>
            </div>

            <div className="flex-1 overflow-y-auto p-6 space-y-4 custom-scrollbar">
              {segments.length === 0 && (
                <div className="h-full flex flex-col items-center justify-center text-center opacity-10 italic text-xs space-y-3 py-20">
                  <div className="w-12 h-12 border-2 border-slate-700 border-dashed rounded-full animate-spin-slow" />
                  <p className="font-black uppercase tracking-widest">Waiting for Input...</p>
                </div>
              )}
              {segments.map((seg, idx) => (
                <div key={seg.id} className="bg-slate-900/40 p-5 rounded-2xl border border-white/5 hover:border-emerald-500/30 transition-all group animate-in fade-in slide-in-from-bottom-2 duration-300">
                  <div className="flex justify-between items-center mb-2">
                    <span className="text-[9px] font-black text-slate-700 uppercase">Segment {String(idx + 1).padStart(3, '0')}</span>
                    <span className="text-[9px] font-mono text-emerald-500 bg-emerald-500/5 px-2 py-1 rounded-md">
                      {Math.floor(seg.start_seconds / 60)}:{(seg.start_seconds % 60).toFixed(1).padStart(4, '0')}
                    </span>
                  </div>
                  <p className="text-slate-300 text-xs leading-relaxed font-medium group-hover:text-white transition-colors">{seg.text}</p>
                </div>
              ))}
              <div ref={transcriptEndRef} />
            </div>

            <div className="p-4 bg-slate-950/50 border-t border-white/5">
              <div className="w-full h-1 bg-slate-800 rounded-full overflow-hidden">
                <div className={`h-full bg-emerald-500 transition-all duration-1000 ${isProcessing ? 'animate-pulse' : ''}`} style={{ width: `${progress}%` }} />
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { GoogleGenAI, Type } from '@google/genai';
import { blobToBase64, audioBufferToWav, downsampleAudioBuffer } from './utils/audioUtils';
import { generateSRT } from './utils/timeFormatter';
import { ProcessingState, CaptionSegment, AnalyticsData, ModelMetric, ProcessingEngine } from './types';

// Neural Model Pool definitions
const MODEL_POOL = [
  { id: 'gemini-3-flash-preview', label: 'Flash 3.0', description: 'Optimal Balanced Core' },
  { id: 'gemini-2.5-flash-native-audio-preview-12-2025', label: 'Audio Native 2.5', description: 'Waveform Specialist' },
  { id: 'gemini-3-pro-preview', label: 'Pro 3.0', description: 'Advanced Reasoning Logic' },
  { id: 'gemini-flash-lite-latest', label: 'Flash Lite', description: 'High-Throughput Fallback' }
];

// Engine sequences: prioritized indices from MODEL_POOL
const ENGINE_MAP: Record<ProcessingEngine, number[]> = {
  titan: [0, 1, 2, 3],
  silentwave: [1, 0, 3],
  globallink: [2, 0, 1, 3]
};

const CHUNK_DURATION = 300; // 5-minute segments
const REQUEST_GAP = 5000; // 5s gap between batches to prevent 429

const INITIAL_ANALYTICS: AnalyticsData = {
  totalRequests: 0,
  successfulRequests: 0,
  failoverEvents: 0,
  startTime: null,
  endTime: null,
  modelMetrics: MODEL_POOL.reduce((acc, model) => {
    acc[model.id] = { success: 0, fail: 0, avgLatency: 0, totalLatency: 0 };
    return acc;
  }, {} as Record<string, ModelMetric>)
};

interface Incident {
  time: string;
  model: string;
  type: string;
  detail: string;
  severity: 'warning' | 'critical' | 'info';
}

const App: React.FC = () => {
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [videoFile, setVideoFile] = useState<File | null>(null);
  const [selectedEngine, setSelectedEngine] = useState<ProcessingEngine>('titan');
  const [status, setStatus] = useState<ProcessingState>({
    status: 'idle',
    message: 'Multi-Engine System Ready.'
  });
  const [segments, setSegments] = useState<CaptionSegment[]>([]);
  const [progress, setProgress] = useState(0);
  const [isProcessing, setIsProcessing] = useState(false);
  const [activeModelId, setActiveModelId] = useState<string>(MODEL_POOL[0].id);
  const [cooldown, setCooldown] = useState(0);
  const [analytics, setAnalytics] = useState<AnalyticsData>(INITIAL_ANALYTICS);
  const [incidents, setIncidents] = useState<Incident[]>([]);
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  const transcriptEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleStatusChange = () => setIsOnline(navigator.onLine);
    window.addEventListener('online', handleStatusChange);
    window.addEventListener('offline', handleStatusChange);
    return () => {
      window.removeEventListener('online', handleStatusChange);
      window.removeEventListener('offline', handleStatusChange);
    };
  }, []);

  useEffect(() => {
    transcriptEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [segments]);

  useEffect(() => {
    if (cooldown > 0) {
      const timer = setTimeout(() => setCooldown(cooldown - 1), 1000);
      return () => clearTimeout(timer);
    }
  }, [cooldown]);

  const updateAnalytics = (modelId: string, latency: number, success: boolean, failover: boolean = false) => {
    setAnalytics(prev => {
      const modelMetric = prev.modelMetrics[modelId] || { success: 0, fail: 0, avgLatency: 0, totalLatency: 0 };
      const newSuccess = modelMetric.success + (success ? 1 : 0);
      const newFail = modelMetric.fail + (success ? 0 : 1);
      const newTotalLatency = modelMetric.totalLatency + latency;

      return {
        ...prev,
        totalRequests: prev.totalRequests + 1,
        successfulRequests: prev.successfulRequests + (success ? 1 : 0),
        failoverEvents: prev.failoverEvents + (failover ? 1 : 0),
        modelMetrics: {
          ...prev.modelMetrics,
          [modelId]: {
            success: newSuccess,
            fail: newFail,
            totalLatency: newTotalLatency,
            avgLatency: newTotalLatency / (newSuccess + newFail || 1)
          }
        }
      };
    });
  };

  const logIncident = (model: string, type: string, detail: string, severity: 'warning' | 'critical' | 'info' = 'warning') => {
    const newIncident: Incident = {
      time: new Date().toLocaleTimeString([], { hour12: false, hour: '2-digit', minute: '2-digit', second: '2-digit' }),
      model,
      type,
      detail,
      severity
    };
    setIncidents(prev => [newIncident, ...prev].slice(0, 30));
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      setVideoFile(file);
      setVideoUrl(URL.createObjectURL(file));
      setSegments([]);
      setProgress(0);
      setIncidents([]);
      setAnalytics(INITIAL_ANALYTICS);
      setStatus({ status: 'idle', message: 'Video Imported. Engines Warm.' });
    }
  };

  const processBatchWithFailover = async (
    audioBuffer: AudioBuffer, 
    offset: number, 
    batchIndex: number, 
    attemptIndex: number = 0,
    retryCount: number = 0
  ): Promise<boolean> => {
    const sequence = ENGINE_MAP[selectedEngine];
    if (attemptIndex >= sequence.length) return false;
    if (!navigator.onLine) return false;

    const modelIdx = sequence[attemptIndex];
    const currentModel = MODEL_POOL[modelIdx];
    setActiveModelId(currentModel.id);

    let systemInstruction = "Precisely transcribe and translate this audio into natural English. Return a JSON array of objects with: start (float seconds), end (float seconds), text (English string).";
    if (selectedEngine === 'silentwave') {
      systemInstruction = "Acting as a Whisper-class transcription engine, prioritize verbatim acoustic accuracy. Translate any foreign speech into standard English. Output as JSON array: [{start, end, text}].";
    } else if (selectedEngine === 'globallink') {
      systemInstruction = "Acting as a high-precision translation engine, perform deep semantic analysis. Translate foreign expressions into idiomatic natural English. Output as JSON array: [{start, end, text}].";
    }

    const requestStart = performance.now();

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const optimizedBuffer = await downsampleAudioBuffer(audioBuffer, 16000);
      const wavBlob = audioBufferToWav(optimizedBuffer);
      const base64Data = await blobToBase64(wavBlob);

      setStatus({ 
        status: 'streaming', 
        message: `[${selectedEngine.toUpperCase()}] Batch ${batchIndex + 1} using ${currentModel.label}...` 
      });

      const response = await ai.models.generateContent({
        model: currentModel.id,
        contents: [{
          parts: [
            { inlineData: { mimeType: 'audio/wav', data: base64Data } },
            { text: systemInstruction }
          ]
        }],
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                start: { type: Type.NUMBER },
                end: { type: Type.NUMBER },
                text: { type: Type.STRING }
              },
              required: ['start, end, text']
            }
          }
        }
      });

      const latency = performance.now() - requestStart;
      updateAnalytics(currentModel.id, latency, true);

      const data = JSON.parse(response.text || "[]");
      const adjustedSegments = data.map((s: any, i: number) => ({
        id: Date.now() + Math.random() + i,
        start_seconds: s.start + offset,
        end_seconds: s.end + offset,
        text: s.text
      }));

      setSegments(prev => [...prev, ...adjustedSegments].sort((a, b) => a.start_seconds - b.start_seconds));
      return true;
    } catch (error: any) {
      const latency = performance.now() - requestStart;
      const errMsg = error.message || String(error);
      const isQuota = errMsg.includes("429") || errMsg.includes("RESOURCE_EXHAUSTED");

      logIncident(currentModel.label, isQuota ? "Quota" : "Fault", errMsg, isQuota ? 'warning' : 'critical');
      updateAnalytics(currentModel.id, latency, false);

      // Automatic Failover Logic
      if (isQuota || retryCount >= 1) {
        if (attemptIndex < sequence.length - 1) {
          const nextModel = MODEL_POOL[sequence[attemptIndex + 1]];
          logIncident("Failover", "Sequence Shift", `Core ${currentModel.label} exhausted. Transitioning to ${nextModel.label}...`, 'info');
          setStatus({ status: 'connecting', message: `Failover: Switching Core...` });

          // Increment failover count in analytics
          setAnalytics(prev => ({ ...prev, failoverEvents: prev.failoverEvents + 1 }));

          await new Promise(r => setTimeout(r, isQuota ? 8000 : 2000));
          return processBatchWithFailover(audioBuffer, offset, batchIndex, attemptIndex + 1, 0);
        }
      }

      // Simple Retry Logic for transient errors before failover
      if (retryCount < 1 && !isQuota) {
        setStatus({ status: 'connecting', message: `Retrying ${currentModel.label}...` });
        await new Promise(r => setTimeout(r, 3000));
        return processBatchWithFailover(audioBuffer, offset, batchIndex, attemptIndex, retryCount + 1);
      }

      return false;
    }
  };

  const startProcessing = async () => {
    if (!videoFile || isProcessing) return;

    try {
      setIsProcessing(true);
      setAnalytics(prev => ({ ...prev, startTime: Date.now(), endTime: null }));
      setStatus({ status: 'connecting', message: 'Initiating Neural Link...' });

      const arrayBuffer = await videoFile.arrayBuffer();
      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
      const decodedBuffer = await audioCtx.decodeAudioData(arrayBuffer);

      const duration = decodedBuffer.duration;
      const numChunks = Math.ceil(duration / CHUNK_DURATION);

      for (let i = 0; i < numChunks; i++) {
        const start = i * CHUNK_DURATION;
        const end = Math.min(start + CHUNK_DURATION, duration);
        const frameStart = Math.floor(start * decodedBuffer.sampleRate);
        const frameEnd = Math.floor(end * decodedBuffer.sampleRate);

        const chunkBuffer = audioCtx.createBuffer(1, frameEnd - frameStart, decodedBuffer.sampleRate);
        chunkBuffer.copyToChannel(decodedBuffer.getChannelData(0).subarray(frameStart, frameEnd), 0);

        const success = await processBatchWithFailover(chunkBuffer, start, i, 0, 0);
        if (!success) throw new Error("Processing logic failed after all failover attempts.");

        setProgress(Math.round(((i + 1) / numChunks) * 100));
        if (i < numChunks - 1) await new Promise(r => setTimeout(r, REQUEST_GAP));
      }

      setAnalytics(prev => ({ ...prev, endTime: Date.now() }));
      setStatus({ status: 'completed', message: 'Processing Stream Completed.' });
      setIsProcessing(false);
    } catch (error: any) {
      setIsProcessing(false);
      setAnalytics(prev => ({ ...prev, endTime: Date.now() }));
      setStatus({ status: 'error', message: error.message });
      logIncident("Pipeline", "Fatal", error.message, "critical");
    }
  };

  const downloadSRT = () => {
    const srt = generateSRT(segments);
    const blob = new Blob([srt], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `PhilipAI_Captions.srt`;
    document.body.appendChild(a); a.click(); document.body.removeChild(a);
  };

  const globalSuccessRate = useMemo(() => {
    if (analytics.totalRequests === 0) return 0;
    return Math.round((analytics.successfulRequests / analytics.totalRequests) * 100);
  }, [analytics]);

  const totalTimeElapsed = useMemo(() => {
    const start = analytics.startTime;
    if (start === null) return '0s';
    const end = analytics.endTime !== null ? analytics.endTime : Date.now();
    const diff = (end - start) / 1000;
    return diff < 60 ? `${diff.toFixed(1)}s` : `${Math.floor(diff / 60)}m ${Math.floor(diff % 60)}s`;
  }, [analytics.startTime, analytics.endTime]);

  const averageLatencyDisplay = useMemo(() => {
    const totalLatency = Object.values(analytics.modelMetrics).reduce((acc: number, curr) => acc + (curr as ModelMetric).totalLatency, 0);
    const requests = analytics.totalRequests || 1;
    return (totalLatency / requests / 1000).toFixed(2);
  }, [analytics.modelMetrics, analytics.totalRequests]);

  return (
    <div className="min-h-screen p-4 md:p-10 flex flex-col gap-8 max-w-7xl mx-auto selection:bg-emerald-500/30">
      {/* Header */}
      <header className="flex flex-col lg:flex-row items-stretch gap-6">
        <div className="flex-1 glass-panel p-8 rounded-[2.5rem] flex items-center gap-6 shadow-xl ring-1 ring-white/5">
          <div className="w-16 h-16 bg-emerald-500 rounded-2xl flex items-center justify-center shadow-[0_0_30px_rgba(16,185,129,0.2)]">
            <svg className="w-10 h-10 text-slate-950" fill="currentColor" viewBox="0 0 24 24">
              <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 14h-2v-2h2v2zm0-4h-2V7h2v5z"/>
            </svg>
          </div>
          <div>
            <h1 className="text-4xl font-black tracking-tighter text-white">Philip<span className="text-emerald-500">AI</span></h1>
            <p className="text-[10px] font-black uppercase tracking-[0.4em] text-slate-500 mt-1 flex items-center gap-2">
              <span className={`w-1.5 h-1.5 rounded-full ${isOnline ? 'bg-emerald-500' : 'bg-red-500 animate-ping'}`} />
              {isOnline ? 'Neural Grid Online' : 'Local Offline'}
            </p>
          </div>
        </div>

        {/* Engine Selection Matrix */}
        <div className="flex-[2] glass-panel p-4 rounded-[2.5rem] grid grid-cols-1 md:grid-cols-3 gap-3 shadow-xl ring-1 ring-white/5">
          {[
            { id: 'titan', name: 'Titan Core', desc: 'Full Failover Stack', icon: 'M13 10V3L4 14h7v7l9-11h-7z', color: 'text-blue-400' },
            { id: 'silentwave', name: 'SilentWave', desc: 'Audio Native Sequence', icon: 'M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z', color: 'text-purple-400' },
            { id: 'globallink', name: 'GlobalLink', desc: 'Pro Reasoning Sequence', icon: 'M3.055 11H5a2 2 0 012 2v1a2 2 0 002 2 2 2 0 012 2v2.945M8 3.935V5.5A2.5 2.5 0 0010.5 8h.5a2 2 0 012 2 2 2 0 104 0 2 2 0 012-2h1.065', color: 'text-amber-400' }
          ].map((engine) => (
            <button
              key={engine.id}
              disabled={isProcessing}
              onClick={() => setSelectedEngine(engine.id as ProcessingEngine)}
              className={`p-4 rounded-3xl border transition-all text-left flex flex-col gap-1 relative overflow-hidden group ${
                selectedEngine === engine.id 
                  ? 'bg-white/5 border-emerald-500/40 shadow-lg' 
                  : 'bg-transparent border-white/5 opacity-50 hover:opacity-100 hover:border-white/10'
              }`}
            >
              <div className="flex items-center gap-2">
                <svg className={`w-4 h-4 ${engine.color}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d={engine.icon} /></svg>
                <span className="text-xs font-black text-white uppercase">{engine.name}</span>
              </div>
              <p className="text-[9px] text-slate-500 font-medium leading-tight">{engine.desc}</p>
              {selectedEngine === engine.id && <div className="absolute top-0 right-0 p-2"><div className="w-1 h-1 bg-emerald-500 rounded-full animate-ping" /></div>}
            </button>
          ))}
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Workspace */}
        <div className="lg:col-span-8 flex flex-col gap-6">
          <div className="aspect-video bg-black rounded-[3rem] overflow-hidden border border-white/5 shadow-2xl relative ring-1 ring-white/10 group">
            {videoUrl ? (
              <video src={videoUrl} controls className="w-full h-full object-contain" />
            ) : (
              <label className="absolute inset-0 flex flex-col items-center justify-center cursor-pointer hover:bg-slate-900/50 transition-all">
                <div className="w-20 h-20 bg-slate-900 rounded-[2rem] flex items-center justify-center mb-4 border border-white/10 group-hover:border-emerald-500/50 transition-all duration-500">
                  <svg className="w-8 h-8 text-slate-500 group-hover:text-emerald-500 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg>
                </div>
                <span className="text-slate-500 font-bold uppercase tracking-widest text-xs">Import Local Source</span>
                <input type="file" className="hidden" accept="video/*" onChange={handleFileChange} />
              </label>
            )}

            {isProcessing && (
              <div className="absolute top-6 right-6 px-4 py-2 bg-slate-950/80 backdrop-blur-md rounded-xl border border-white/10 text-[10px] font-black text-emerald-500 flex items-center gap-2 shadow-xl">
                <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-ping" />
                ACTIVE: {MODEL_POOL.find(m => m.id === activeModelId)?.label || 'Neural Link'}
              </div>
            )}
          </div>

          <div className="flex flex-col md:flex-row gap-6">
            <div className="flex-1 glass-panel p-10 rounded-[3rem] flex flex-col md:flex-row items-center justify-between gap-8 shadow-xl border border-white/5">
              <div className="space-y-1">
                <span className="text-emerald-500 text-[10px] font-black uppercase tracking-widest">Failover Protection: Enabled</span>
                <h2 className="text-2xl font-bold text-white tracking-tight">Active Engine Stream</h2>
                <p className="text-slate-500 text-sm">Processing in {progress}% completion.</p>
              </div>
              <div className="flex gap-4 w-full md:w-auto">
                <button 
                  onClick={startProcessing}
                  disabled={!videoFile || isProcessing || !isOnline}
                  className="flex-1 md:flex-none bg-emerald-500 hover:bg-emerald-400 disabled:opacity-20 text-slate-950 font-black px-12 py-5 rounded-2xl transition-all shadow-[0_15px_40px_-10px_rgba(16,185,129,0.3)] active:scale-95"
                >
                  {isProcessing ? `Batching...` : 'Engage Engine'}
                </button>
                <button 
                  onClick={downloadSRT}
                  disabled={segments.length === 0}
                  className="flex-1 md:flex-none bg-slate-800 hover:bg-slate-700 disabled:opacity-20 text-white font-bold px-10 py-5 rounded-2xl border border-white/10 transition-all"
                >
                  Export SRT
                </button>
              </div>
            </div>

            <div className={`md:w-64 glass-panel p-8 rounded-[3rem] flex flex-col justify-center items-center gap-2 shadow-xl border ${status.status === 'error' ? 'border-red-500/40' : 'border-white/5'}`}>
               <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Pipeline Health</span>
               <div className={`text-4xl font-black ${globalSuccessRate < 40 ? 'text-red-500' : 'text-emerald-500'}`}>{globalSuccessRate}%</div>
               <div className="w-full bg-slate-900 h-1 rounded-full overflow-hidden mt-2">
                 <div className={`${globalSuccessRate < 40 ? 'bg-red-500' : 'bg-emerald-500'} h-full transition-all duration-700`} style={{ width: `${globalSuccessRate}%` }} />
               </div>
            </div>
          </div>

          <div className={`text-center px-10 py-3 rounded-2xl transition-colors ${status.status === 'error' ? 'bg-red-500/5 border border-red-500/10' : ''}`}>
            <p className={`text-[10px] font-black uppercase tracking-[0.4em] ${status.status === 'error' ? 'text-red-500' : 'text-slate-600 animate-pulse'}`}>
              {status.message} {cooldown > 0 && `(Cooling ${cooldown}s)`}
            </p>
          </div>
        </div>

        {/* Sidebar */}
        <div className="lg:col-span-4 flex flex-col gap-6">
          <div className="glass-panel rounded-[2.5rem] p-6 shadow-xl ring-1 ring-white/10 flex flex-col">
            <h3 className="text-[10px] font-black uppercase tracking-widest text-slate-500 mb-4 flex items-center justify-between">
              <span>Diagnostics</span>
              <span className="text-emerald-500 font-bold uppercase">Failovers: {analytics.failoverEvents}</span>
            </h3>
            <div className="grid grid-cols-2 gap-3 mb-6">
              <div className="bg-slate-950/50 p-4 rounded-2xl border border-white/5">
                <p className="text-[8px] font-black text-slate-600 uppercase">Requests</p>
                <p className="text-lg font-bold text-white">{analytics.totalRequests}</p>
              </div>
              <div className="bg-slate-950/50 p-4 rounded-2xl border border-white/5">
                <p className="text-[8px] font-black text-slate-600 uppercase">Avg Latency</p>
                <p className="text-lg font-bold text-white">{averageLatencyDisplay}s</p>
              </div>
            </div>

            <div className="flex-1 max-h-[250px] overflow-y-auto custom-scrollbar space-y-2">
              {incidents.length === 0 ? (
                <div className="text-center py-10 opacity-20 text-[9px] font-black uppercase tracking-widest">Neural Link Nominal</div>
              ) : (
                incidents.map((inc, i) => (
                  <div key={i} className={`text-[9px] p-3 rounded-xl border transition-all ${
                    inc.severity === 'critical' ? 'bg-red-500/10 border-red-500/20' : 
                    inc.severity === 'info' ? 'bg-emerald-500/10 border-emerald-500/20' : 
                    'bg-slate-900/50 border-white/5'
                  }`}>
                    <div className="flex justify-between items-start mb-1">
                      <span className={`font-black ${
                        inc.severity === 'critical' ? 'text-red-400' : 
                        inc.severity === 'info' ? 'text-emerald-400' : 
                        'text-amber-500'
                      }`}>{inc.type}</span>
                      <span className="text-slate-600 font-mono text-[8px]">{inc.time}</span>
                    </div>
                    <p className="text-slate-400 leading-tight">[{inc.model}] {inc.detail}</p>
                  </div>
                ))
              )}
            </div>
          </div>

          {/* Stream Output */}
          <div className="glass-panel rounded-[3rem] flex-1 flex flex-col shadow-2xl overflow-hidden ring-1 ring-white/10 min-h-[400px]">
            <div className="p-8 border-b border-white/5 bg-slate-950/20 flex items-center justify-between">
              <h3 className="text-xs font-black uppercase tracking-widest text-white">Neural Stream</h3>
              <span className="text-emerald-500 bg-emerald-500/10 px-3 py-1 rounded-lg text-[9px] font-black">{segments.length} BLOCKS</span>
            </div>

            <div className="flex-1 overflow-y-auto p-6 space-y-4 custom-scrollbar">
              {segments.length === 0 && (
                <div className="h-full flex flex-col items-center justify-center text-center opacity-10 italic text-xs space-y-3 py-20">
                  <div className="w-12 h-12 border-2 border-slate-700 border-dashed rounded-full animate-spin-slow" />
                  <p className="font-black uppercase tracking-widest">Waiting for Sync...</p>
                </div>
              )}
              {segments.map((seg, idx) => (
                <div key={seg.id} className="bg-slate-900/40 p-5 rounded-2xl border border-white/5 hover:border-emerald-500/30 transition-all group animate-in fade-in slide-in-from-bottom-2 duration-300">
                  <div className="flex justify-between items-center mb-2">
                    <span className="text-[9px] font-black text-slate-700 uppercase">Block {String(idx + 1).padStart(3, '0')}</span>
                    <span className="text-[9px] font-mono text-emerald-500 bg-emerald-500/5 px-2 py-1 rounded-md">
                      {Math.floor(seg.start_seconds / 60)}:{(seg.start_seconds % 60).toFixed(1).padStart(4, '0')}
                    </span>
                  </div>
                  <p className="text-slate-300 text-xs leading-relaxed font-medium group-hover:text-white transition-colors">{seg.text}</p>
                </div>
              ))}
              <div ref={transcriptEndRef} />
            </div>

            <div className="p-4 bg-slate-950/50 border-t border-white/5">
              <div className="w-full h-1 bg-slate-800 rounded-full overflow-hidden">
                <div className={`h-full bg-emerald-500 transition-all duration-1000 ${isProcessing ? 'animate-pulse' : ''}`} style={{ width: `${progress}%` }} />
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { GoogleGenAI, Type } from '@google/genai';
import { blobToBase64, audioBufferToWav, downsampleAudioBuffer } from './utils/audioUtils';
import { generateSRT } from './utils/timeFormatter';
import { ProcessingState, CaptionSegment, AnalyticsData, ModelMetric, ProcessingEngine } from './types';

// Neural Model Pool definitions
const MODEL_POOL = [
  { id: 'gemini-3-flash-preview', label: 'Flash 3.0', description: 'Optimal Balanced Core' },
  { id: 'gemini-2.5-flash-native-audio-preview-12-2025', label: 'Audio Native 2.5', description: 'Waveform Specialist' },
  { id: 'gemini-3-pro-preview', label: 'Pro 3.0', description: 'Advanced Reasoning Logic' },
  { id: 'gemini-flash-lite-latest', label: 'Flash Lite', description: 'High-Throughput Fallback' }
];

// Engine sequences: prioritized indices from MODEL_POOL for failover logic
const ENGINE_MAP: Record<ProcessingEngine, number[]> = {
  titan: [0, 1, 2, 3],
  silentwave: [1, 0, 3, 2],
  globallink: [2, 0, 1, 3]
};

const CHUNK_DURATION = 300; // 5-minute segments
const REQUEST_GAP = 5000; // 5s gap between batches to prevent 429 rate limiting

const INITIAL_ANALYTICS: AnalyticsData = {
  totalRequests: 0,
  successfulRequests: 0,
  failoverEvents: 0,
  startTime: null,
  endTime: null,
  modelMetrics: MODEL_POOL.reduce((acc, model) => {
    acc[model.id] = { success: 0, fail: 0, avgLatency: 0, totalLatency: 0 };
    return acc;
  }, {} as Record<string, ModelMetric>)
};

interface Incident {
  time: string;
  model: string;
  type: string;
  detail: string;
  severity: 'warning' | 'critical' | 'info';
}

const App: React.FC = () => {
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [videoFile, setVideoFile] = useState<File | null>(null);
  const [selectedEngine, setSelectedEngine] = useState<ProcessingEngine>('titan');
  const [status, setStatus] = useState<ProcessingState>({
    status: 'idle',
    message: 'Multi-Engine System Ready.'
  });
  const [segments, setSegments] = useState<CaptionSegment[]>([]);
  const [progress, setProgress] = useState(0);
  const [isProcessing, setIsProcessing] = useState(false);
  const [activeModelId, setActiveModelId] = useState<string>(MODEL_POOL[0].id);
  const [cooldown, setCooldown] = useState(0);
  const [analytics, setAnalytics] = useState<AnalyticsData>(INITIAL_ANALYTICS);
  const [incidents, setIncidents] = useState<Incident[]>([]);
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  const transcriptEndRef = useRef<HTMLDivElement>(null);

  // Synchronize network status for failover safety
  useEffect(() => {
    const handleStatusChange = () => setIsOnline(navigator.onLine);
    window.addEventListener('online', handleStatusChange);
    window.addEventListener('offline', handleStatusChange);
    return () => {
      window.removeEventListener('online', handleStatusChange);
      window.removeEventListener('offline', handleStatusChange);
    };
  }, []);

  // Auto-scroll transcript stream
  useEffect(() => {
    transcriptEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [segments]);

  // Handle rate-limit cooldown timers
  useEffect(() => {
    if (cooldown > 0) {
      const timer = setTimeout(() => setCooldown(cooldown - 1), 1000);
      return () => clearTimeout(timer);
    }
  }, [cooldown]);

  const updateAnalytics = (modelId: string, latency: number, success: boolean) => {
    setAnalytics(prev => {
      const modelMetric = prev.modelMetrics[modelId] || { success: 0, fail: 0, avgLatency: 0, totalLatency: 0 };
      const newSuccess = modelMetric.success + (success ? 1 : 0);
      const newFail = modelMetric.fail + (success ? 0 : 1);
      const newTotalLatency = modelMetric.totalLatency + latency;

      return {
        ...prev,
        totalRequests: prev.totalRequests + 1,
        successfulRequests: prev.successfulRequests + (success ? 1 : 0),
        modelMetrics: {
          ...prev.modelMetrics,
          [modelId]: {
            success: newSuccess,
            fail: newFail,
            totalLatency: newTotalLatency,
            avgLatency: newTotalLatency / (newSuccess + newFail || 1)
          }
        }
      };
    });
  };

  const logIncident = (model: string, type: string, detail: string, severity: 'warning' | 'critical' | 'info' = 'warning') => {
    const newIncident: Incident = {
      time: new Date().toLocaleTimeString([], { hour12: false, hour: '2-digit', minute: '2-digit', second: '2-digit' }),
      model,
      type,
      detail,
      severity
    };
    setIncidents(prev => [newIncident, ...prev].slice(0, 30));
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      setVideoFile(file);
      setVideoUrl(URL.createObjectURL(file));
      setSegments([]);
      setProgress(0);
      setIncidents([]);
      setAnalytics(INITIAL_ANALYTICS);
      setStatus({ status: 'idle', message: 'Video Imported. Neural Grid Warm.' });
    }
  };

  /**
   * Main Recursive Failover Logic
   * @param attemptIndex tracks the current model in the ENGINE_MAP sequence
   * @param retryCount tracks transient retries for the CURRENT model
   */
  const processBatchWithFailover = async (
    audioBuffer: AudioBuffer, 
    offset: number, 
    batchIndex: number, 
    attemptIndex: number = 0,
    retryCount: number = 0
  ): Promise<boolean> => {
    const sequence = ENGINE_MAP[selectedEngine];
    if (attemptIndex >= sequence.length) return false;
    if (!navigator.onLine) {
      logIncident("Network", "Connectivity", "Offline state detected. Pipeline paused.", "critical");
      return false;
    }

    const modelIdx = sequence[attemptIndex];
    const currentModel = MODEL_POOL[modelIdx];
    setActiveModelId(currentModel.id);

    // Task-specific prompt tuning
    let systemInstruction = "Precisely transcribe and translate this audio into natural English. Return a JSON array of objects with: start (float seconds), end (float seconds), text (English string).";
    if (selectedEngine === 'silentwave') {
      systemInstruction = "Acting as a Whisper-class transcription engine, prioritize verbatim acoustic accuracy for timestamps and speech. Translate any foreign speech into standard English. Output as JSON array: [{start, end, text}].";
    } else if (selectedEngine === 'globallink') {
      systemInstruction = "Acting as a high-precision translation engine (Meta NLLB style), perform deep semantic analysis. Translate foreign expressions into idiomatic, natural English suitable for YouTube captions. Output as JSON array: [{start, end, text}].";
    }

    const requestStart = performance.now();

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const optimizedBuffer = await downsampleAudioBuffer(audioBuffer, 16000);
      const wavBlob = audioBufferToWav(optimizedBuffer);
      const base64Data = await blobToBase64(wavBlob);

      setStatus({ 
        status: 'streaming', 
        message: `[${selectedEngine.toUpperCase()}] Batch ${batchIndex + 1} using ${currentModel.label}...` 
      });

      const response = await ai.models.generateContent({
        model: currentModel.id,
        contents: [{
          parts: [
            { inlineData: { mimeType: 'audio/wav', data: base64Data } },
            { text: systemInstruction }
          ]
        }],
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                start: { type: Type.NUMBER },
                end: { type: Type.NUMBER },
                text: { type: Type.STRING }
              },
              required: ['start', 'end', 'text'] // FIXED: Independently required fields
            }
          }
        }
      });

      const latency = performance.now() - requestStart;
      updateAnalytics(currentModel.id, latency, true);

      const data = JSON.parse(response.text || "[]");
      const adjustedSegments = data.map((s: any, i: number) => ({
        id: Date.now() + Math.random() + i,
        start_seconds: s.start + offset,
        end_seconds: s.end + offset,
        text: s.text
      }));

      setSegments(prev => [...prev, ...adjustedSegments].sort((a, b) => a.start_seconds - b.start_seconds));
      return true;
    } catch (error: any) {
      const latency = performance.now() - requestStart;
      const errMsg = error.message || String(error);
      const isQuota = errMsg.includes("429") || errMsg.includes("RESOURCE_EXHAUSTED") || errMsg.includes("Quota");

      logIncident(currentModel.label, isQuota ? "Quota" : "Fault", errMsg, isQuota ? 'warning' : 'critical');
      updateAnalytics(currentModel.id, latency, false);

      // FAILOVER DECISION TREE
      // Case A: Quota Limit Reached -> Immediate shift to next model
      if (isQuota) {
        if (attemptIndex < sequence.length - 1) {
          const nextModel = MODEL_POOL[sequence[attemptIndex + 1]];
          logIncident("Failover", "Sequence Shift", `Rate limit on ${currentModel.label}. Transitioning to fallback: ${nextModel.label}...`, 'info');
          setAnalytics(prev => ({ ...prev, failoverEvents: prev.failoverEvents + 1 }));
          setStatus({ status: 'connecting', message: `Quota Shift: Switching Core...` });

          await new Promise(r => setTimeout(r, 8000)); // Buffer for quota cooling
          return processBatchWithFailover(audioBuffer, offset, batchIndex, attemptIndex + 1, 0);
        }
      }

      // Case B: General Fault -> Retry current model once, then shift
      if (retryCount < 1 && !isQuota) {
        setStatus({ status: 'connecting', message: `Transient Error. Retrying ${currentModel.label}...` });
        await new Promise(r => setTimeout(r, 3000));
        return processBatchWithFailover(audioBuffer, offset, batchIndex, attemptIndex, retryCount + 1);
      }

      // Case C: Retries exhausted -> Failover to next model
      if (attemptIndex < sequence.length - 1) {
        const nextModel = MODEL_POOL[sequence[attemptIndex + 1]];
        logIncident("Failover", "Recovery", `Retries exhausted for ${currentModel.label}. Shifting to ${nextModel.label}.`, 'info');
        setAnalytics(prev => ({ ...prev, failoverEvents: prev.failoverEvents + 1 }));
        return processBatchWithFailover(audioBuffer, offset, batchIndex, attemptIndex + 1, 0);
      }

      return false;
    }
  };

  const startProcessing = async () => {
    if (!videoFile || isProcessing) return;

    try {
      setIsProcessing(true);
      setAnalytics(prev => ({ ...prev, startTime: Date.now(), endTime: null }));
      setStatus({ status: 'connecting', message: 'Decoding Local Media Stream...' });

      const arrayBuffer = await videoFile.arrayBuffer();
      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
      const decodedBuffer = await audioCtx.decodeAudioData(arrayBuffer);

      const duration = decodedBuffer.duration;
      const numChunks = Math.ceil(duration / CHUNK_DURATION);

      for (let i = 0; i < numChunks; i++) {
        const start = i * CHUNK_DURATION;
        const end = Math.min(start + CHUNK_DURATION, duration);
        const frameStart = Math.floor(start * decodedBuffer.sampleRate);
        const frameEnd = Math.floor(end * decodedBuffer.sampleRate);

        const chunkBuffer = audioCtx.createBuffer(1, frameEnd - frameStart, decodedBuffer.sampleRate);
        chunkBuffer.copyToChannel(decodedBuffer.getChannelData(0).subarray(frameStart, frameEnd), 0);

        const success = await processBatchWithFailover(chunkBuffer, start, i, 0, 0);
        if (!success) throw new Error("Neural Pipeline Grid Down. Try another engine or check API Key.");

        setProgress(Math.round(((i + 1) / numChunks) * 100));
        if (i < numChunks - 1) await new Promise(r => setTimeout(r, REQUEST_GAP));
      }

      setAnalytics(prev => ({ ...prev, endTime: Date.now() }));
      setStatus({ status: 'completed', message: 'Translation Stream Finalized.' });
      setIsProcessing(false);
    } catch (error: any) {
      setIsProcessing(false);
      setAnalytics(prev => ({ ...prev, endTime: Date.now() }));
      setStatus({ status: 'error', message: error.message });
      logIncident("Pipeline", "Fatal", error.message, "critical");
    }
  };

  const downloadSRT = () => {
    const srt = generateSRT(segments);
    const blob = new Blob([srt], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `PhilipAI_Captions.srt`;
    document.body.appendChild(a); a.click(); document.body.removeChild(a);
  };

  const globalSuccessRate = useMemo(() => {
    if (analytics.totalRequests === 0) return 0;
    return Math.round((analytics.successfulRequests / analytics.totalRequests) * 100);
  }, [analytics]);

  const totalTimeElapsed = useMemo(() => {
    const start = analytics.startTime;
    if (start === null) return '0s';
    const end = analytics.endTime !== null ? analytics.endTime : Date.now();
    const diff = (end - start) / 1000;
    return diff < 60 ? `${diff.toFixed(1)}s` : `${Math.floor(diff / 60)}m ${Math.floor(diff % 60)}s`;
  }, [analytics.startTime, analytics.endTime]);

  const averageLatencyDisplay = useMemo(() => {
    const totalLatency = Object.values(analytics.modelMetrics).reduce((acc: number, curr) => acc + (curr as ModelMetric).totalLatency, 0);
    const requests = analytics.totalRequests || 1;
    return (totalLatency / requests / 1000).toFixed(2);
  }, [analytics.modelMetrics, analytics.totalRequests]);

  return (
    <div className="min-h-screen p-4 md:p-10 flex flex-col gap-8 max-w-7xl mx-auto selection:bg-emerald-500/30">
      {/* Header section with brand and neural connectivity status */}
      <header className="flex flex-col lg:flex-row items-stretch gap-6">
        <div className="flex-1 glass-panel p-8 rounded-[2.5rem] flex items-center gap-6 shadow-xl ring-1 ring-white/5 group">
          <div className="w-16 h-16 bg-emerald-500 rounded-2xl flex items-center justify-center shadow-[0_0_30px_rgba(16,185,129,0.2)] group-hover:rotate-6 transition-transform">
            <svg className="w-10 h-10 text-slate-950" fill="currentColor" viewBox="0 0 24 24">
              <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 14h-2v-2h2v2zm0-4h-2V7h2v5z"/>
            </svg>
          </div>
          <div>
            <h1 className="text-4xl font-black tracking-tighter text-white">Philip<span className="text-emerald-500">AI</span></h1>
            <p className="text-[10px] font-black uppercase tracking-[0.4em] text-slate-500 mt-1 flex items-center gap-2">
              <span className={`w-1.5 h-1.5 rounded-full ${isOnline ? 'bg-emerald-500' : 'bg-red-500 animate-ping'}`} />
              {isOnline ? 'Pipeline Ready' : 'Network Interrupted'}
            </p>
          </div>
        </div>

        {/* Engine Selection Matrix for Model Choice */}
        <div className="flex-[2] glass-panel p-4 rounded-[2.5rem] grid grid-cols-1 md:grid-cols-3 gap-3 shadow-xl ring-1 ring-white/5">
          {[
            { id: 'titan', name: 'Titan Core', desc: 'Full Failover Stack', icon: 'M13 10V3L4 14h7v7l9-11h-7z', color: 'text-blue-400' },
            { id: 'silentwave', name: 'SilentWave', desc: 'Whisper-Class Audio', icon: 'M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z', color: 'text-purple-400' },
            { id: 'globallink', name: 'GlobalLink', desc: 'Meta Idiomatic English', icon: 'M3.055 11H5a2 2 0 012 2v1a2 2 0 002 2 2 2 0 012 2v2.945M8 3.935V5.5A2.5 2.5 0 0010.5 8h.5a2 2 0 012 2 2 2 0 104 0 2 2 0 012-2h1.065', color: 'text-amber-400' }
          ].map((engine) => (
            <button
              key={engine.id}
              disabled={isProcessing}
              onClick={() => setSelectedEngine(engine.id as ProcessingEngine)}
              className={`p-4 rounded-3xl border transition-all text-left flex flex-col gap-1 relative overflow-hidden group ${
                selectedEngine === engine.id 
                  ? 'bg-white/5 border-emerald-500/40 shadow-lg' 
                  : 'bg-transparent border-white/5 opacity-50 hover:opacity-100 hover:border-white/10'
              }`}
            >
              <div className="flex items-center gap-2">
                <svg className={`w-4 h-4 ${engine.color}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d={engine.icon} /></svg>
                <span className="text-xs font-black text-white uppercase">{engine.name}</span>
              </div>
              <p className="text-[9px] text-slate-500 font-medium leading-tight">{engine.desc}</p>
              {selectedEngine === engine.id && <div className="absolute top-0 right-0 p-2"><div className="w-1 h-1 bg-emerald-500 rounded-full animate-ping" /></div>}
            </button>
          ))}
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Main Workspace (Video Player + Action Controls) */}
        <div className="lg:col-span-8 flex flex-col gap-6">
          <div className="aspect-video bg-black rounded-[3rem] overflow-hidden border border-white/5 shadow-2xl relative ring-1 ring-white/10 group">
            {videoUrl ? (
              <video src={videoUrl} controls className="w-full h-full object-contain" />
            ) : (
              <label className="absolute inset-0 flex flex-col items-center justify-center cursor-pointer hover:bg-slate-900/50 transition-all">
                <div className="w-20 h-20 bg-slate-900 rounded-[2rem] flex items-center justify-center mb-4 border border-white/10 group-hover:border-emerald-500/50 transition-all duration-500">
                  <svg className="w-8 h-8 text-slate-500 group-hover:text-emerald-500 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg>
                </div>
                <span className="text-slate-500 font-bold uppercase tracking-widest text-xs">Import Local Source</span>
                <input type="file" className="hidden" accept="video/*" onChange={handleFileChange} />
              </label>
            )}

            {isProcessing && (
              <div className="absolute top-6 right-6 px-4 py-2 bg-slate-950/80 backdrop-blur-md rounded-xl border border-white/10 text-[10px] font-black text-emerald-500 flex items-center gap-2 shadow-xl">
                <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-ping" />
                ACTIVE CORE: {MODEL_POOL.find(m => m.id === activeModelId)?.label || 'Neural Link'}
              </div>
            )}
          </div>

          <div className="flex flex-col md:flex-row gap-6">
            <div className="flex-1 glass-panel p-10 rounded-[3rem] flex flex-col md:flex-row items-center justify-between gap-8 shadow-xl border border-white/5">
              <div className="space-y-1">
                <span className="text-emerald-500 text-[10px] font-black uppercase tracking-widest">Auto-Failover: ACTIVE</span>
                <h2 className="text-2xl font-bold text-white tracking-tight">Active Engine Stream</h2>
                <p className="text-slate-500 text-sm">Target: YouTube Captions (SRT).</p>
              </div>
              <div className="flex gap-4 w-full md:w-auto">
                <button 
                  onClick={startProcessing}
                  disabled={!videoFile || isProcessing || !isOnline}
                  className="flex-1 md:flex-none bg-emerald-500 hover:bg-emerald-400 disabled:opacity-20 text-slate-950 font-black px-12 py-5 rounded-2xl transition-all shadow-[0_15px_40px_-10px_rgba(16,185,129,0.3)] active:scale-95"
                >
                  {isProcessing ? `Batching ${progress}%...` : 'Engage Grid'}
                </button>
                <button 
                  onClick={downloadSRT}
                  disabled={segments.length === 0}
                  className="flex-1 md:flex-none bg-slate-800 hover:bg-slate-700 disabled:opacity-20 text-white font-bold px-10 py-5 rounded-2xl border border-white/10 transition-all"
                >
                  Export SRT
                </button>
              </div>
            </div>

            <div className={`md:w-64 glass-panel p-8 rounded-[3rem] flex flex-col justify-center items-center gap-2 shadow-xl border ${status.status === 'error' ? 'border-red-500/40' : 'border-white/5'}`}>
               <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Efficiency</span>
               <div className={`text-4xl font-black ${globalSuccessRate < 40 ? 'text-red-500' : 'text-emerald-500'}`}>{globalSuccessRate}%</div>
               <div className="w-full bg-slate-900 h-1 rounded-full overflow-hidden mt-2">
                 <div className={`${globalSuccessRate < 40 ? 'bg-red-500' : 'bg-emerald-500'} h-full transition-all duration-700`} style={{ width: `${globalSuccessRate}%` }} />
               </div>
            </div>
          </div>

          <div className={`text-center px-10 py-3 rounded-2xl transition-colors ${status.status === 'error' ? 'bg-red-500/5 border border-red-500/10' : ''}`}>
            <p className={`text-[10px] font-black uppercase tracking-[0.4em] ${status.status === 'error' ? 'text-red-500' : 'text-slate-600 animate-pulse'}`}>
              {status.message} {cooldown > 0 && `(Cooling ${cooldown}s)`}
            </p>
          </div>
        </div>

        {/* Sidebar Diagnostics & Live Transcription Log */}
        <div className="lg:col-span-4 flex flex-col gap-6">
          <div className="glass-panel rounded-[2.5rem] p-6 shadow-xl ring-1 ring-white/10 flex flex-col">
            <h3 className="text-[10px] font-black uppercase tracking-widest text-slate-500 mb-4 flex items-center justify-between">
              <span>Diagnostics Terminal</span>
              <span className="text-emerald-500 font-bold uppercase">Failovers: {analytics.failoverEvents}</span>
            </h3>
            <div className="grid grid-cols-2 gap-3 mb-6">
              <div className="bg-slate-950/50 p-4 rounded-2xl border border-white/5">
                <p className="text-[8px] font-black text-slate-600 uppercase">Requests</p>
                <p className="text-lg font-bold text-white">{analytics.totalRequests}</p>
              </div>
              <div className="bg-slate-950/50 p-4 rounded-2xl border border-white/5">
                <p className="text-[8px] font-black text-slate-600 uppercase">Avg Latency</p>
                <p className="text-lg font-bold text-white">{averageLatencyDisplay}s</p>
              </div>
            </div>

            <div className="flex-1 max-h-[250px] overflow-y-auto custom-scrollbar space-y-2">
              {incidents.length === 0 ? (
                <div className="text-center py-10 opacity-20 text-[9px] font-black uppercase tracking-widest">All Streams Nominal</div>
              ) : (
                incidents.map((inc, i) => (
                  <div key={i} className={`text-[9px] p-3 rounded-xl border transition-all ${
                    inc.severity === 'critical' ? 'bg-red-500/10 border-red-500/20' : 
                    inc.severity === 'info' ? 'bg-emerald-500/10 border-emerald-500/20' : 
                    'bg-slate-900/50 border-white/5'
                  }`}>
                    <div className="flex justify-between items-start mb-1">
                      <span className={`font-black ${
                        inc.severity === 'critical' ? 'text-red-400' : 
                        inc.severity === 'info' ? 'text-emerald-400' : 
                        'text-amber-500'
                      }`}>{inc.type}</span>
                      <span className="text-slate-600 font-mono text-[8px]">{inc.time}</span>
                    </div>
                    <p className="text-slate-400 leading-tight">[{inc.model}] {inc.detail}</p>
                  </div>
                ))
              )}
            </div>
          </div>

          {/* Stream Output (Real-time Preview) */}
          <div className="glass-panel rounded-[3rem] flex-1 flex flex-col shadow-2xl overflow-hidden ring-1 ring-white/10 min-h-[400px]">
            <div className="p-8 border-b border-white/5 bg-slate-950/20 flex items-center justify-between">
              <h3 className="text-xs font-black uppercase tracking-widest text-white">Neural Stream</h3>
              <span className="text-emerald-500 bg-emerald-500/10 px-3 py-1 rounded-lg text-[9px] font-black">{segments.length} UNITS</span>
            </div>

            <div className="flex-1 overflow-y-auto p-6 space-y-4 custom-scrollbar">
              {segments.length === 0 && (
                <div className="h-full flex flex-col items-center justify-center text-center opacity-10 italic text-xs space-y-3 py-20">
                  <div className="w-12 h-12 border-2 border-slate-700 border-dashed rounded-full animate-spin-slow" />
                  <p className="font-black uppercase tracking-widest">Awaiting Audio Frames...</p>
                </div>
              )}
              {segments.map((seg, idx) => (
                <div key={seg.id} className="bg-slate-900/40 p-5 rounded-2xl border border-white/5 hover:border-emerald-500/30 transition-all group animate-in fade-in slide-in-from-bottom-2 duration-300">
                  <div className="flex justify-between items-center mb-2">
                    <span className="text-[9px] font-black text-slate-700 uppercase">Unit {String(idx + 1).padStart(3, '0')}</span>
                    <span className="text-[9px] font-mono text-emerald-500 bg-emerald-500/5 px-2 py-1 rounded-md">
                      {Math.floor(seg.start_seconds / 60)}:{(seg.start_seconds % 60).toFixed(1).padStart(4, '0')}
                    </span>
                  </div>
                  <p className="text-slate-300 text-xs leading-relaxed font-medium group-hover:text-white transition-colors">{seg.text}</p>
                </div>
              ))}
              <div ref={transcriptEndRef} />
            </div>

            <div className="p-4 bg-slate-950/50 border-t border-white/5">
              <div className="w-full h-1 bg-slate-800 rounded-full overflow-hidden">
                <div className={`h-full bg-emerald-500 transition-all duration-1000 ${isProcessing ? 'animate-pulse' : ''}`} style={{ width: `${progress}%` }} />
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { GoogleGenAI, Type } from '@google/genai';
import { blobToBase64, audioBufferToWav, downsampleAudioBuffer } from './utils/audioUtils';
import { generateSRT } from './utils/timeFormatter';
import { ProcessingState, CaptionSegment, AnalyticsData, ModelMetric, ProcessingEngine } from './types';

// Neural Model Pool: Prioritized based on capabilities
const MODEL_POOL = [
  { id: 'gemini-3-flash-preview', label: 'Flash 3.0', description: 'Optimal Balanced Core' },
  { id: 'gemini-2.5-flash-native-audio-preview-12-2025', label: 'Audio Native 2.5', description: 'Waveform Specialist' },
  { id: 'gemini-3-pro-preview', label: 'Pro 3.0', description: 'Advanced Reasoning Logic' },
  { id: 'gemini-flash-lite-latest', label: 'Flash Lite', description: 'High-Throughput Fallback' }
];

// Failover Sequence Map: Defines the recovery path for each processing mode
const ENGINE_MAP: Record<ProcessingEngine, number[]> = {
  titan: [0, 1, 2, 3],       // Standard balanced approach
  silentwave: [1, 0, 3, 2],  // Starts with Native Audio for max transcription fidelity
  globallink: [2, 0, 1, 3]   // Starts with Pro 3.0 for nuanced semantic translation
};

const CHUNK_DURATION = 300; // 5-minute segments
const REQUEST_GAP = 5000; // 5s gap between batches to prevent 429 rate limiting

const INITIAL_ANALYTICS: AnalyticsData = {
  totalRequests: 0,
  successfulRequests: 0,
  failoverEvents: 0,
  startTime: null,
  endTime: null,
  modelMetrics: MODEL_POOL.reduce((acc, model) => {
    acc[model.id] = { success: 0, fail: 0, avgLatency: 0, totalLatency: 0 };
    return acc;
  }, {} as Record<string, ModelMetric>)
};

interface Incident {
  time: string;
  model: string;
  type: string;
  detail: string;
  severity: 'warning' | 'critical' | 'info';
}

const App: React.FC = () => {
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [videoFile, setVideoFile] = useState<File | null>(null);
  const [selectedEngine, setSelectedEngine] = useState<ProcessingEngine>('titan');
  const [status, setStatus] = useState<ProcessingState>({
    status: 'idle',
    message: 'Multi-Engine Neural Link Ready.'
  });
  const [segments, setSegments] = useState<CaptionSegment[]>([]);
  const [progress, setProgress] = useState(0);
  const [isProcessing, setIsProcessing] = useState(false);
  const [activeModelId, setActiveModelId] = useState<string>(MODEL_POOL[0].id);
  const [analytics, setAnalytics] = useState<AnalyticsData>(INITIAL_ANALYTICS);
  const [incidents, setIncidents] = useState<Incident[]>([]);
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  const transcriptEndRef = useRef<HTMLDivElement>(null);

  // Connectivity monitoring for failover safety
  useEffect(() => {
    const handleStatusChange = () => setIsOnline(navigator.onLine);
    window.addEventListener('online', handleStatusChange);
    window.addEventListener('offline', handleStatusChange);
    return () => {
      window.removeEventListener('online', handleStatusChange);
      window.removeEventListener('offline', handleStatusChange);
    };
  }, []);

  // Ensure the live transcription feed always follows the latest output
  useEffect(() => {
    transcriptEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [segments]);

  const updateAnalytics = (modelId: string, latency: number, success: boolean) => {
    setAnalytics(prev => {
      const modelMetric = prev.modelMetrics[modelId] || { success: 0, fail: 0, avgLatency: 0, totalLatency: 0 };
      const newSuccess = modelMetric.success + (success ? 1 : 0);
      const newFail = modelMetric.fail + (success ? 0 : 1);
      const newTotalLatency = modelMetric.totalLatency + latency;

      return {
        ...prev,
        totalRequests: prev.totalRequests + 1,
        successfulRequests: prev.successfulRequests + (success ? 1 : 0),
        modelMetrics: {
          ...prev.modelMetrics,
          [modelId]: {
            success: newSuccess,
            fail: newFail,
            totalLatency: newTotalLatency,
            avgLatency: newTotalLatency / (newSuccess + newFail || 1)
          }
        }
      };
    });
  };

  const logIncident = (model: string, type: string, detail: string, severity: 'warning' | 'critical' | 'info' = 'warning') => {
    const newIncident: Incident = {
      time: new Date().toLocaleTimeString([], { hour12: false, hour: '2-digit', minute: '2-digit', second: '2-digit' }),
      model,
      type,
      detail,
      severity
    };
    setIncidents(prev => [newIncident, ...prev].slice(0, 30));
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      setVideoFile(file);
      setVideoUrl(URL.createObjectURL(file));
      setSegments([]);
      setProgress(0);
      setIncidents([]);
      setAnalytics(INITIAL_ANALYTICS);
      setStatus({ status: 'idle', message: 'Neural Grid Standby.' });
    }
  };

  /**
   * Recursive Neural Failover Handler
   * Orchestrates retries and model shifting based on engine priority.
   */
  const processBatchWithFailover = async (
    audioBuffer: AudioBuffer, 
    offset: number, 
    batchIndex: number, 
    attemptIndex: number = 0,
    retryCount: number = 0
  ): Promise<boolean> => {
    const sequence = ENGINE_MAP[selectedEngine];
    if (attemptIndex >= sequence.length) return false;
    if (!navigator.onLine) return false;

    const modelIdx = sequence[attemptIndex];
    const currentModel = MODEL_POOL[modelIdx];
    setActiveModelId(currentModel.id);

    let systemInstruction = "Precisely transcribe and translate this audio into natural English. Return a JSON array of objects with: start (float seconds), end (float seconds), text (English string).";
    if (selectedEngine === 'silentwave') {
      systemInstruction = "Acting as a Whisper-class transcription specialist, prioritize verbatim acoustic fidelity. Translate any foreign speech into standard English. Output as JSON array: [{start, end, text}].";
    } else if (selectedEngine === 'globallink') {
      systemInstruction = "Acting as a high-precision translation agent (Meta NLLB style), perform deep semantic analysis. Translate foreign expressions into natural idiomatic English. Output as JSON array: [{start, end, text}].";
    }

    const requestStart = performance.now();

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const optimizedBuffer = await downsampleAudioBuffer(audioBuffer, 16000);
      const wavBlob = audioBufferToWav(optimizedBuffer);
      const base64Data = await blobToBase64(wavBlob);

      setStatus({ 
        status: 'streaming', 
        message: `[${selectedEngine.toUpperCase()}] Batch ${batchIndex + 1} processing on ${currentModel.label}...` 
      });

      const response = await ai.models.generateContent({
        model: currentModel.id,
        contents: [{
          parts: [
            { inlineData: { mimeType: 'audio/wav', data: base64Data } },
            { text: systemInstruction }
          ]
        }],
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                start: { type: Type.NUMBER },
                end: { type: Type.NUMBER },
                text: { type: Type.STRING }
              },
              required: ['start', 'end', 'text']
            }
          }
        }
      });

      const latency = performance.now() - requestStart;
      updateAnalytics(currentModel.id, latency, true);

      const data = JSON.parse(response.text || "[]");
      const adjustedSegments = data.map((s: any, i: number) => ({
        id: Date.now() + Math.random() + i,
        start_seconds: s.start + offset,
        end_seconds: s.end + offset,
        text: s.text
      }));

      setSegments(prev => [...prev, ...adjustedSegments].sort((a, b) => a.start_seconds - b.start_seconds));
      return true;
    } catch (error: any) {
      const latency = performance.now() - requestStart;
      const errMsg = error.message || String(error);
      const isQuota = errMsg.includes("429") || errMsg.includes("RESOURCE_EXHAUSTED") || errMsg.includes("Quota");

      logIncident(currentModel.label, isQuota ? "Quota" : "Fault", errMsg, isQuota ? 'warning' : 'critical');
      updateAnalytics(currentModel.id, latency, false);

      // 1. Quota Failover: Immediate shift to next model
      if (isQuota) {
        if (attemptIndex < sequence.length - 1) {
          const nextModel = MODEL_POOL[sequence[attemptIndex + 1]];
          logIncident("Failover", "Quota Shift", `Core ${currentModel.label} exhausted. Shifting to fallback: ${nextModel.label}.`, 'info');
          setAnalytics(prev => ({ ...prev, failoverEvents: prev.failoverEvents + 1 }));
          setStatus({ status: 'connecting', message: `Failover Sequence: Activating Secondary Core...` });

          await new Promise(r => setTimeout(r, 7000)); // Allow API some breathing room
          return processBatchWithFailover(audioBuffer, offset, batchIndex, attemptIndex + 1, 0);
        }
      }

      // 2. Transient Retry: Try same model once before shifting
      if (retryCount < 1 && !isQuota) {
        setStatus({ status: 'connecting', message: `Transient Error. Retrying current core...` });
        await new Promise(r => setTimeout(r, 2000));
        return processBatchWithFailover(audioBuffer, offset, batchIndex, attemptIndex, retryCount + 1);
      }

      // 3. Exhaustion Failover: Shift to next model in sequence
      if (attemptIndex < sequence.length - 1) {
        const nextModel = MODEL_POOL[sequence[attemptIndex + 1]];
        logIncident("Failover", "Fault Recovery", `Exhausted core ${currentModel.label}. Shifting to ${nextModel.label}.`, 'info');
        setAnalytics(prev => ({ ...prev, failoverEvents: prev.failoverEvents + 1 }));
        return processBatchWithFailover(audioBuffer, offset, batchIndex, attemptIndex + 1, 0);
      }

      return false;
    }
  };

  const startProcessing = async () => {
    if (!videoFile || isProcessing) return;

    try {
      setIsProcessing(true);
      setAnalytics(prev => ({ ...prev, startTime: Date.now(), endTime: null }));
      setStatus({ status: 'connecting', message: 'Decoding Local Media Buffer...' });

      const arrayBuffer = await videoFile.arrayBuffer();
      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
      const decodedBuffer = await audioCtx.decodeAudioData(arrayBuffer);

      const duration = decodedBuffer.duration;
      const numChunks = Math.ceil(duration / CHUNK_DURATION);

      for (let i = 0; i < numChunks; i++) {
        const start = i * CHUNK_DURATION;
        const end = Math.min(start + CHUNK_DURATION, duration);
        const frameStart = Math.floor(start * decodedBuffer.sampleRate);
        const frameEnd = Math.floor(end * decodedBuffer.sampleRate);

        const chunkBuffer = audioCtx.createBuffer(1, frameEnd - frameStart, decodedBuffer.sampleRate);
        chunkBuffer.copyToChannel(decodedBuffer.getChannelData(0).subarray(frameStart, frameEnd), 0);

        const success = await processBatchWithFailover(chunkBuffer, start, i, 0, 0);
        if (!success) throw new Error("Neural Grid Failure. All fallback cores exhausted.");

        setProgress(Math.round(((i + 1) / numChunks) * 100));
        if (i < numChunks - 1) await new Promise(r => setTimeout(r, REQUEST_GAP));
      }

      setAnalytics(prev => ({ ...prev, endTime: Date.now() }));
      setStatus({ status: 'completed', message: 'Neural Translation Link Terminated Successfully.' });
      setIsProcessing(false);
    } catch (error: any) {
      setIsProcessing(false);
      setAnalytics(prev => ({ ...prev, endTime: Date.now() }));
      setStatus({ status: 'error', message: error.message });
      logIncident("Pipeline", "Fatal", error.message, "critical");
    }
  };

  const downloadSRT = () => {
    const srt = generateSRT(segments);
    const blob = new Blob([srt], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `PhilipAI_Captions.srt`;
    document.body.appendChild(a); a.click(); document.body.removeChild(a);
  };

  const globalSuccessRate = useMemo(() => {
    if (analytics.totalRequests === 0) return 0;
    return Math.round((analytics.successfulRequests / analytics.totalRequests) * 100);
  }, [analytics]);

  const totalTimeElapsed = useMemo(() => {
    const start = analytics.startTime;
    if (start === null) return '0s';
    const end = analytics.endTime !== null ? analytics.endTime : Date.now();
    const diff = (end - start) / 1000;
    return diff < 60 ? `${diff.toFixed(1)}s` : `${Math.floor(diff / 60)}m ${Math.floor(diff % 60)}s`;
  }, [analytics.startTime, analytics.endTime]);

  const averageLatencyDisplay = useMemo(() => {
    const totalLatency = Object.values(analytics.modelMetrics).reduce((acc: number, curr) => acc + (curr as ModelMetric).totalLatency, 0);
    const requests = analytics.totalRequests || 1;
    return (totalLatency / requests / 1000).toFixed(2);
  }, [analytics.modelMetrics, analytics.totalRequests]);

  return (
    <div className="min-h-screen p-4 md:p-10 flex flex-col gap-8 max-w-7xl mx-auto selection:bg-emerald-500/30">
      {/* Brand Header */}
      <header className="flex flex-col lg:flex-row items-stretch gap-6">
        <div className="flex-1 glass-panel p-8 rounded-[2.5rem] flex items-center gap-6 shadow-xl ring-1 ring-white/5 hover:ring-white/10 transition-all group">
          <div className="w-16 h-16 bg-emerald-500 rounded-2xl flex items-center justify-center shadow-[0_0_30px_rgba(16,185,129,0.2)] group-hover:rotate-12 transition-transform">
            <svg className="w-10 h-10 text-slate-950" fill="currentColor" viewBox="0 0 24 24">
              <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 14h-2v-2h2v2zm0-4h-2V7h2v5z"/>
            </svg>
          </div>
          <div>
            <h1 className="text-4xl font-black tracking-tighter text-white">Philip<span className="text-emerald-500">AI</span></h1>
            <p className="text-[10px] font-black uppercase tracking-[0.4em] text-slate-500 mt-1 flex items-center gap-2">
              <span className={`w-1.5 h-1.5 rounded-full ${isOnline ? 'bg-emerald-500' : 'bg-red-500 animate-ping'}`} />
              {isOnline ? 'Neural Link Ready' : 'Core Connection Interrupted'}
            </p>
          </div>
        </div>

        {/* Engine Control Interface */}
        <div className="flex-[2] glass-panel p-4 rounded-[2.5rem] grid grid-cols-1 md:grid-cols-3 gap-3 shadow-xl ring-1 ring-white/5">
          {[
            { id: 'titan', name: 'Titan Core', desc: 'Full Failover Stack', icon: 'M13 10V3L4 14h7v7l9-11h-7z', color: 'text-blue-400' },
            { id: 'silentwave', name: 'SilentWave', desc: 'Whisper-Class Acoustic', icon: 'M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z', color: 'text-purple-400' },
            { id: 'globallink', name: 'GlobalLink', desc: 'Meta High-Reasoning', icon: 'M3.055 11H5a2 2 0 012 2v1a2 2 0 002 2 2 2 0 012 2v2.945M8 3.935V5.5A2.5 2.5 0 0010.5 8h.5a2 2 0 012 2 2 2 0 104 0 2 2 0 012-2h1.065', color: 'text-amber-400' }
          ].map((engine) => (
            <button
              key={engine.id}
              disabled={isProcessing}
              onClick={() => setSelectedEngine(engine.id as ProcessingEngine)}
              className={`p-4 rounded-3xl border transition-all text-left flex flex-col gap-1 relative overflow-hidden group ${
                selectedEngine === engine.id 
                  ? 'bg-white/5 border-emerald-500/40 shadow-lg' 
                  : 'bg-transparent border-white/5 opacity-50 hover:opacity-100 hover:border-white/10'
              }`}
            >
              <div className="flex items-center gap-2">
                <svg className={`w-4 h-4 ${engine.color}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d={engine.icon} /></svg>
                <span className="text-xs font-black text-white uppercase">{engine.name}</span>
              </div>
              <p className="text-[9px] text-slate-500 font-medium leading-tight">{engine.desc}</p>
              {selectedEngine === engine.id && <div className="absolute top-0 right-0 p-2"><div className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-ping" /></div>}
            </button>
          ))}
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Workspace: Media Processing Central */}
        <div className="lg:col-span-8 flex flex-col gap-6">
          <div className="aspect-video bg-black rounded-[3rem] overflow-hidden border border-white/5 shadow-2xl relative ring-1 ring-white/10 group">
            {videoUrl ? (
              <video src={videoUrl} controls className="w-full h-full object-contain" />
            ) : (
              <label className="absolute inset-0 flex flex-col items-center justify-center cursor-pointer hover:bg-slate-900/50 transition-all">
                <div className="w-20 h-20 bg-slate-900 rounded-[2rem] flex items-center justify-center mb-4 border border-white/10 group-hover:border-emerald-500/50 transition-all duration-500">
                  <svg className="w-8 h-8 text-slate-500 group-hover:text-emerald-500 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg>
                </div>
                <span className="text-slate-500 font-bold uppercase tracking-widest text-xs">Import Local Source</span>
                <input type="file" className="hidden" accept="video/*" onChange={handleFileChange} />
              </label>
            )}

            {isProcessing && (
              <div className="absolute top-6 right-6 px-4 py-2 bg-slate-950/80 backdrop-blur-md rounded-xl border border-white/10 text-[10px] font-black text-emerald-500 flex items-center gap-2 shadow-xl ring-1 ring-emerald-500/20">
                <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-ping" />
                ACTIVE: {MODEL_POOL.find(m => m.id === activeModelId)?.label}
              </div>
            )}
          </div>

          <div className="flex flex-col md:flex-row gap-6">
            <div className="flex-1 glass-panel p-10 rounded-[3rem] flex flex-col md:flex-row items-center justify-between gap-8 shadow-xl border border-white/5">
              <div className="space-y-1">
                <span className="text-emerald-500 text-[10px] font-black uppercase tracking-widest">Neural Failover: ARMED</span>
                <h2 className="text-2xl font-bold text-white tracking-tight">Transcription Pipeline</h2>
                <p className="text-slate-500 text-sm">Target: YouTube Multi-Language SRT.</p>
              </div>
              <div className="flex gap-4 w-full md:w-auto">
                <button 
                  onClick={startProcessing}
                  disabled={!videoFile || isProcessing || !isOnline}
                  className="flex-1 md:flex-none bg-emerald-500 hover:bg-emerald-400 disabled:opacity-20 text-slate-950 font-black px-12 py-5 rounded-2xl transition-all shadow-[0_15px_40px_-10px_rgba(16,185,129,0.3)] active:scale-95"
                >
                  {isProcessing ? `Linking...` : 'Engage Grid'}
                </button>
                <button 
                  onClick={downloadSRT}
                  disabled={segments.length === 0}
                  className="flex-1 md:flex-none bg-slate-800 hover:bg-slate-700 disabled:opacity-20 text-white font-bold px-10 py-5 rounded-2xl border border-white/10 transition-all"
                >
                  Export SRT
                </button>
              </div>
            </div>

            <div className={`md:w-64 glass-panel p-8 rounded-[3rem] flex flex-col justify-center items-center gap-2 shadow-xl border ${status.status === 'error' ? 'border-red-500/40' : 'border-white/5'}`}>
               <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Engine Health</span>
               <div className={`text-4xl font-black ${globalSuccessRate < 40 ? 'text-red-500' : 'text-emerald-500'}`}>{globalSuccessRate}%</div>
               <div className="w-full bg-slate-900 h-1 rounded-full overflow-hidden mt-2">
                 <div className={`${globalSuccessRate < 40 ? 'bg-red-500' : 'bg-emerald-500'} h-full transition-all duration-700`} style={{ width: `${globalSuccessRate}%` }} />
               </div>
            </div>
          </div>

          <div className={`text-center px-10 py-3 rounded-2xl transition-colors ${status.status === 'error' ? 'bg-red-500/5 border border-red-500/10' : ''}`}>
            <p className={`text-[10px] font-black uppercase tracking-[0.4em] ${status.status === 'error' ? 'text-red-500' : 'text-slate-600 animate-pulse'}`}>
              {status.message}
            </p>
          </div>
        </div>

        {/* Sidebar: Analytics & Diagnostic Stream */}
        <div className="lg:col-span-4 flex flex-col gap-6">
          <div className="glass-panel rounded-[2.5rem] p-6 shadow-xl ring-1 ring-white/10 flex flex-col">
            <h3 className="text-[10px] font-black uppercase tracking-widest text-slate-500 mb-4 flex items-center justify-between">
              <span>Diagnostic Feed</span>
              <span className="text-emerald-500/70 font-bold uppercase">Failovers: {analytics.failoverEvents}</span>
            </h3>
            <div className="grid grid-cols-2 gap-3 mb-6">
              <div className="bg-slate-950/50 p-4 rounded-2xl border border-white/5">
                <p className="text-[8px] font-black text-slate-600 uppercase">Requests</p>
                <p className="text-lg font-bold text-white">{analytics.totalRequests}</p>
              </div>
              <div className="bg-slate-950/50 p-4 rounded-2xl border border-white/5">
                <p className="text-[8px] font-black text-slate-600 uppercase">Avg Latency</p>
                <p className="text-lg font-bold text-white">{averageLatencyDisplay}s</p>
              </div>
            </div>

            <div className="flex-1 max-h-[200px] overflow-y-auto custom-scrollbar space-y-2">
              {incidents.length === 0 ? (
                <div className="text-center py-10 opacity-20 text-[9px] font-black uppercase tracking-widest">Neural Link Nominal</div>
              ) : (
                incidents.map((inc, i) => (
                  <div key={i} className={`text-[9px] p-3 rounded-xl border transition-all ${
                    inc.severity === 'critical' ? 'bg-red-500/10 border-red-500/20' : 
                    inc.severity === 'info' ? 'bg-emerald-500/10 border-emerald-500/20' : 
                    'bg-slate-900/50 border-white/5'
                  }`}>
                    <div className="flex justify-between items-start mb-1">
                      <span className={`font-black ${
                        inc.severity === 'critical' ? 'text-red-400' : 
                        inc.severity === 'info' ? 'text-emerald-400' : 
                        'text-amber-500'
                      }`}>{inc.type}</span>
                      <span className="text-slate-600 font-mono text-[8px]">{inc.time}</span>
                    </div>
                    <p className="text-slate-400 leading-tight">[{inc.model}] {inc.detail}</p>
                  </div>
                ))
              )}
            </div>
          </div>

          {/* Transcription Feed Output */}
          <div className="glass-panel rounded-[3rem] flex-1 flex flex-col shadow-2xl overflow-hidden ring-1 ring-white/10 min-h-[400px]">
            <div className="p-8 border-b border-white/5 bg-slate-950/20 flex items-center justify-between">
              <h3 className="text-xs font-black uppercase tracking-widest text-white">Live Neural Feed</h3>
              <span className="text-emerald-500 bg-emerald-500/10 px-3 py-1 rounded-lg text-[9px] font-black">{segments.length} BLOCKS</span>
            </div>

            <div className="flex-1 overflow-y-auto p-6 space-y-4 custom-scrollbar">
              {segments.length === 0 && (
                <div className="h-full flex flex-col items-center justify-center text-center opacity-10 italic text-xs space-y-3 py-20">
                  <div className="w-12 h-12 border-2 border-slate-700 border-dashed rounded-full animate-spin-slow" />
                  <p className="font-black uppercase tracking-widest">Synchronizing Cores...</p>
                </div>
              )}
              {segments.map((seg, idx) => (
                <div key={seg.id} className="bg-slate-900/40 p-5 rounded-2xl border border-white/5 hover:border-emerald-500/30 transition-all group animate-in fade-in slide-in-from-bottom-2 duration-300">
                  <div className="flex justify-between items-center mb-2">
                    <span className="text-[9px] font-black text-slate-700 uppercase">Block {String(idx + 1).padStart(3, '0')}</span>
                    <span className="text-[9px] font-mono text-emerald-500 bg-emerald-500/5 px-2 py-1 rounded-md">
                      {Math.floor(seg.start_seconds / 60)}:{(seg.start_seconds % 60).toFixed(1).padStart(4, '0')}
                    </span>
                  </div>
                  <p className="text-slate-300 text-xs leading-relaxed font-medium group-hover:text-white transition-colors">{seg.text}</p>
                </div>
              ))}
              <div ref={transcriptEndRef} />
            </div>

            <div className="p-4 bg-slate-950/50 border-t border-white/5">
              <div className="w-full h-1.5 bg-slate-800 rounded-full overflow-hidden">
                <div className={`h-full bg-emerald-500 transition-all duration-1000 ${isProcessing ? 'animate-pulse' : ''}`} style={{ width: `${progress}%` }} />
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { GoogleGenAI, Type } from '@google/genai';
import { blobToBase64, audioBufferToWav, downsampleAudioBuffer } from './utils/audioUtils';
import { generateSRT } from './utils/timeFormatter';
import { ProcessingState, CaptionSegment, AnalyticsData, ModelMetric, ProcessingEngine } from './types';

// Neural Model Pool: Prioritized based on capabilities
const MODEL_POOL = [
  { id: 'gemini-3-flash-preview', label: 'Flash 3.0', description: 'Optimal Balanced Core' },
  { id: 'gemini-2.5-flash-native-audio-preview-12-2025', label: 'Audio Native 2.5', description: 'Waveform Specialist' },
  { id: 'gemini-3-pro-preview', label: 'Pro 3.0', description: 'Advanced Reasoning Logic' },
  { id: 'gemini-flash-lite-latest', label: 'Flash Lite', description: 'High-Throughput Fallback' }
];

// Failover Sequence Map: Defines the recovery path for each processing mode
const ENGINE_MAP: Record<ProcessingEngine, number[]> = {
  titan: [0, 1, 2, 3],       // Standard balanced approach
  silentwave: [1, 0, 3, 2],  // Starts with Native Audio for max transcription fidelity
  globallink: [2, 0, 1, 3]   // Starts with Pro 3.0 for nuanced semantic translation
};

const CHUNK_DURATION = 300; // 5-minute segments
const REQUEST_GAP = 5000; // 5s gap between batches to prevent 429 rate limiting

const INITIAL_ANALYTICS: AnalyticsData = {
  totalRequests: 0,
  successfulRequests: 0,
  failoverEvents: 0,
  startTime: null,
  endTime: null,
  modelMetrics: MODEL_POOL.reduce((acc, model) => {
    acc[model.id] = { success: 0, fail: 0, avgLatency: 0, totalLatency: 0 };
    return acc;
  }, {} as Record<string, ModelMetric>)
};

interface Incident {
  time: string;
  model: string;
  type: string;
  detail: string;
  severity: 'warning' | 'critical' | 'info';
}

const App: React.FC = () => {
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [videoFile, setVideoFile] = useState<File | null>(null);
  const [selectedEngine, setSelectedEngine] = useState<ProcessingEngine>('titan');
  const [status, setStatus] = useState<ProcessingState>({
    status: 'idle',
    message: 'Multi-Engine Neural Link Ready.'
  });
  const [segments, setSegments] = useState<CaptionSegment[]>([]);
  const [progress, setProgress] = useState(0);
  const [isProcessing, setIsProcessing] = useState(false);
  const [activeModelId, setActiveModelId] = useState<string>(MODEL_POOL[0].id);
  const [analytics, setAnalytics] = useState<AnalyticsData>(INITIAL_ANALYTICS);
  const [incidents, setIncidents] = useState<Incident[]>([]);
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  const transcriptEndRef = useRef<HTMLDivElement>(null);

  // Connectivity monitoring for failover safety
  useEffect(() => {
    const handleStatusChange = () => setIsOnline(navigator.onLine);
    window.addEventListener('online', handleStatusChange);
    window.addEventListener('offline', handleStatusChange);
    return () => {
      window.removeEventListener('online', handleStatusChange);
      window.removeEventListener('offline', handleStatusChange);
    };
  }, []);

  // Ensure the live transcription feed always follows the latest output
  useEffect(() => {
    transcriptEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [segments]);

  const updateAnalytics = (modelId: string, latency: number, success: boolean) => {
    setAnalytics(prev => {
      const modelMetric = prev.modelMetrics[modelId] || { success: 0, fail: 0, avgLatency: 0, totalLatency: 0 };
      const newSuccess = modelMetric.success + (success ? 1 : 0);
      const newFail = modelMetric.fail + (success ? 0 : 1);
      const newTotalLatency = modelMetric.totalLatency + latency;

      return {
        ...prev,
        totalRequests: prev.totalRequests + 1,
        successfulRequests: prev.successfulRequests + (success ? 1 : 0),
        modelMetrics: {
          ...prev.modelMetrics,
          [modelId]: {
            success: newSuccess,
            fail: newFail,
            totalLatency: newTotalLatency,
            avgLatency: newTotalLatency / (newSuccess + newFail || 1)
          }
        }
      };
    });
  };

  const logIncident = (model: string, type: string, detail: string, severity: 'warning' | 'critical' | 'info' = 'warning') => {
    const newIncident: Incident = {
      time: new Date().toLocaleTimeString([], { hour12: false, hour: '2-digit', minute: '2-digit', second: '2-digit' }),
      model,
      type,
      detail,
      severity
    };
    setIncidents(prev => [newIncident, ...prev].slice(0, 30));
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      setVideoFile(file);
      setVideoUrl(URL.createObjectURL(file));
      setSegments([]);
      setProgress(0);
      setIncidents([]);
      setAnalytics(INITIAL_ANALYTICS);
      setStatus({ status: 'idle', message: 'Neural Grid Standby.' });
    }
  };

  /**
   * Recursive Neural Failover Handler
   * Orchestrates retries and model shifting based on engine priority.
   */
  const processBatchWithFailover = async (
    audioBuffer: AudioBuffer, 
    offset: number, 
    batchIndex: number, 
    attemptIndex: number = 0,
    retryCount: number = 0
  ): Promise<boolean> => {
    const sequence = ENGINE_MAP[selectedEngine];
    if (attemptIndex >= sequence.length) return false;
    if (!navigator.onLine) return false;

    const modelIdx = sequence[attemptIndex];
    const currentModel = MODEL_POOL[modelIdx];
    setActiveModelId(currentModel.id);

    let systemInstruction = "Precisely transcribe and translate this audio into natural English. Return a JSON array of objects with: start (float seconds), end (float seconds), text (English string).";
    if (selectedEngine === 'silentwave') {
      systemInstruction = "Acting as a Whisper-class transcription specialist, prioritize verbatim acoustic fidelity. Translate any foreign speech into standard English. Output as JSON array: [{start, end, text}].";
    } else if (selectedEngine === 'globallink') {
      systemInstruction = "Acting as a high-precision translation agent (Meta NLLB style), perform deep semantic analysis. Translate foreign expressions into natural idiomatic English. Output as JSON array: [{start, end, text}].";
    }

    const requestStart = performance.now();

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const optimizedBuffer = await downsampleAudioBuffer(audioBuffer, 16000);
      const wavBlob = audioBufferToWav(optimizedBuffer);
      const base64Data = await blobToBase64(wavBlob);

      setStatus({ 
        status: 'streaming', 
        message: `[${selectedEngine.toUpperCase()}] Batch ${batchIndex + 1} processing on ${currentModel.label}...` 
      });

      const response = await ai.models.generateContent({
        model: currentModel.id,
        contents: [{
          parts: [
            { inlineData: { mimeType: 'audio/wav', data: base64Data } },
            { text: systemInstruction }
          ]
        }],
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                start: { type: Type.NUMBER },
                end: { type: Type.NUMBER },
                text: { type: Type.STRING }
              },
              required: ['start', 'end', 'text']
            }
          }
        }
      });

      const latency = performance.now() - requestStart;
      updateAnalytics(currentModel.id, latency, true);

      const data = JSON.parse(response.text || "[]");
      const adjustedSegments = data.map((s: any, i: number) => ({
        id: Date.now() + Math.random() + i,
        start_seconds: s.start + offset,
        end_seconds: s.end + offset,
        text: s.text
      }));

      setSegments(prev => [...prev, ...adjustedSegments].sort((a, b) => a.start_seconds - b.start_seconds));
      return true;
    } catch (error: any) {
      const latency = performance.now() - requestStart;
      const errMsg = error.message || String(error);
      const isQuota = errMsg.includes("429") || errMsg.includes("RESOURCE_EXHAUSTED") || errMsg.includes("Quota");

      logIncident(currentModel.label, isQuota ? "Quota" : "Fault", errMsg, isQuota ? 'warning' : 'critical');
      updateAnalytics(currentModel.id, latency, false);

      // 1. Quota Failover: Immediate shift to next model
      if (isQuota) {
        if (attemptIndex < sequence.length - 1) {
          const nextModel = MODEL_POOL[sequence[attemptIndex + 1]];
          logIncident("Failover", "Quota Shift", `Core ${currentModel.label} exhausted. Shifting to fallback: ${nextModel.label}.`, 'info');
          setAnalytics(prev => ({ ...prev, failoverEvents: prev.failoverEvents + 1 }));
          setStatus({ status: 'connecting', message: `Failover Sequence: Activating Secondary Core...` });

          await new Promise(r => setTimeout(r, 7000)); // Allow API some breathing room
          return processBatchWithFailover(audioBuffer, offset, batchIndex, attemptIndex + 1, 0);
        }
      }

      // 2. Transient Retry: Try same model once before shifting
      if (retryCount < 1 && !isQuota) {
        setStatus({ status: 'connecting', message: `Transient Error. Retrying current core...` });
        await new Promise(r => setTimeout(r, 2000));
        return processBatchWithFailover(audioBuffer, offset, batchIndex, attemptIndex, retryCount + 1);
      }

      // 3. Exhaustion Failover: Shift to next model in sequence
      if (attemptIndex < sequence.length - 1) {
        const nextModel = MODEL_POOL[sequence[attemptIndex + 1]];
        logIncident("Failover", "Fault Recovery", `Exhausted core ${currentModel.label}. Shifting to ${nextModel.label}.`, 'info');
        setAnalytics(prev => ({ ...prev, failoverEvents: prev.failoverEvents + 1 }));
        return processBatchWithFailover(audioBuffer, offset, batchIndex, attemptIndex + 1, 0);
      }

      return false;
    }
  };

  const startProcessing = async () => {
    if (!videoFile || isProcessing) return;

    try {
      setIsProcessing(true);
      setAnalytics(prev => ({ ...prev, startTime: Date.now(), endTime: null }));
      setStatus({ status: 'connecting', message: 'Decoding Local Media Buffer...' });

      const arrayBuffer = await videoFile.arrayBuffer();
      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
      const decodedBuffer = await audioCtx.decodeAudioData(arrayBuffer);

      const duration = decodedBuffer.duration;
      const numChunks = Math.ceil(duration / CHUNK_DURATION);

      for (let i = 0; i < numChunks; i++) {
        const start = i * CHUNK_DURATION;
        const end = Math.min(start + CHUNK_DURATION, duration);
        const frameStart = Math.floor(start * decodedBuffer.sampleRate);
        const frameEnd = Math.floor(end * decodedBuffer.sampleRate);

        const chunkBuffer = audioCtx.createBuffer(1, frameEnd - frameStart, decodedBuffer.sampleRate);
        chunkBuffer.copyToChannel(decodedBuffer.getChannelData(0).subarray(frameStart, frameEnd), 0);

        const success = await processBatchWithFailover(chunkBuffer, start, i, 0, 0);
        if (!success) throw new Error("Neural Grid Failure. All fallback cores exhausted.");

        setProgress(Math.round(((i + 1) / numChunks) * 100));
        if (i < numChunks - 1) await new Promise(r => setTimeout(r, REQUEST_GAP));
      }

      setAnalytics(prev => ({ ...prev, endTime: Date.now() }));
      setStatus({ status: 'completed', message: 'Neural Translation Link Terminated Successfully.' });
      setIsProcessing(false);
    } catch (error: any) {
      setIsProcessing(false);
      setAnalytics(prev => ({ ...prev, endTime: Date.now() }));
      setStatus({ status: 'error', message: error.message });
      logIncident("Pipeline", "Fatal", error.message, "critical");
    }
  };

  const downloadSRT = () => {
    const srt = generateSRT(segments);
    const blob = new Blob([srt], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `PhilipAI_Captions.srt`;
    document.body.appendChild(a); a.click(); document.body.removeChild(a);
  };

  const globalSuccessRate = useMemo(() => {
    if (analytics.totalRequests === 0) return 0;
    return Math.round((analytics.successfulRequests / analytics.totalRequests) * 100);
  }, [analytics]);

  const totalTimeElapsed = useMemo(() => {
    const { startTime, endTime } = analytics;
    // Explicit null checks and narrowing to satisfy arithmetic constraints in TS.
    if (startTime === null) return '0s';
    const end = endTime !== null ? endTime : Date.now();
    const diff = (end - startTime) / 1000;
    return diff < 60 ? `${diff.toFixed(1)}s` : `${Math.floor(diff / 60)}m ${Math.floor(diff % 60)}s`;
  }, [analytics.startTime, analytics.endTime]);

  const averageLatencyDisplay = useMemo(() => {
    // Explicitly cast to ModelMetric[] and handle reduction with a typed accumulator to prevent arithmetic errors.
    const metrics = Object.values(analytics.modelMetrics) as ModelMetric[];
    const totalLatency = metrics.reduce((acc: number, curr: ModelMetric) => acc + curr.totalLatency, 0);
    const requests = analytics.totalRequests || 1;
    return (totalLatency / requests / 1000).toFixed(2);
  }, [analytics.modelMetrics, analytics.totalRequests]);

  return (
    <div className="min-h-screen p-4 md:p-10 flex flex-col gap-8 max-w-7xl mx-auto selection:bg-emerald-500/30">
      {/* Brand Header */}
      <header className="flex flex-col lg:flex-row items-stretch gap-6">
        <div className="flex-1 glass-panel p-8 rounded-[2.5rem] flex items-center gap-6 shadow-xl ring-1 ring-white/5 hover:ring-white/10 transition-all group">
          <div className="w-16 h-16 bg-emerald-500 rounded-2xl flex items-center justify-center shadow-[0_0_30px_rgba(16,185,129,0.2)] group-hover:rotate-12 transition-transform">
            <svg className="w-10 h-10 text-slate-950" fill="currentColor" viewBox="0 0 24 24">
              <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 14h-2v-2h2v2zm0-4h-2V7h2v5z"/>
            </svg>
          </div>
          <div>
            <h1 className="text-4xl font-black tracking-tighter text-white">Philip<span className="text-emerald-500">AI</span></h1>
            <p className="text-[10px] font-black uppercase tracking-[0.4em] text-slate-500 mt-1 flex items-center gap-2">
              <span className={`w-1.5 h-1.5 rounded-full ${isOnline ? 'bg-emerald-500' : 'bg-red-500 animate-ping'}`} />
              {isOnline ? 'Neural Link Ready' : 'Core Connection Interrupted'}
            </p>
          </div>
        </div>

        {/* Engine Control Interface */}
        <div className="flex-[2] glass-panel p-4 rounded-[2.5rem] grid grid-cols-1 md:grid-cols-3 gap-3 shadow-xl ring-1 ring-white/5">
          {[
            { id: 'titan', name: 'Titan Core', desc: 'Full Failover Stack', icon: 'M13 10V3L4 14h7v7l9-11h-7z', color: 'text-blue-400' },
            { id: 'silentwave', name: 'SilentWave', desc: 'Whisper-Class Acoustic', icon: 'M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z', color: 'text-purple-400' },
            { id: 'globallink', name: 'GlobalLink', desc: 'Meta High-Reasoning', icon: 'M3.055 11H5a2 2 0 012 2v1a2 2 0 002 2 2 2 0 012 2v2.945M8 3.935V5.5A2.5 2.5 0 0010.5 8h.5a2 2 0 012 2 2 2 0 104 0 2 2 0 012-2h1.065', color: 'text-amber-400' }
          ].map((engine) => (
            <button
              key={engine.id}
              disabled={isProcessing}
              onClick={() => setSelectedEngine(engine.id as ProcessingEngine)}
              className={`p-4 rounded-3xl border transition-all text-left flex flex-col gap-1 relative overflow-hidden group ${
                selectedEngine === engine.id 
                  ? 'bg-white/5 border-emerald-500/40 shadow-lg' 
                  : 'bg-transparent border-white/5 opacity-50 hover:opacity-100 hover:border-white/10'
              }`}
            >
              <div className="flex items-center gap-2">
                <svg className={`w-4 h-4 ${engine.color}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d={engine.icon} /></svg>
                <span className="text-xs font-black text-white uppercase">{engine.name}</span>
              </div>
              <p className="text-[9px] text-slate-500 font-medium leading-tight">{engine.desc}</p>
              {selectedEngine === engine.id && <div className="absolute top-0 right-0 p-2"><div className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-ping" /></div>}
            </button>
          ))}
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Workspace: Media Processing Central */}
        <div className="lg:col-span-8 flex flex-col gap-6">
          <div className="aspect-video bg-black rounded-[3rem] overflow-hidden border border-white/5 shadow-2xl relative ring-1 ring-white/10 group">
            {videoUrl ? (
              <video src={videoUrl} controls className="w-full h-full object-contain" />
            ) : (
              <label className="absolute inset-0 flex flex-col items-center justify-center cursor-pointer hover:bg-slate-900/50 transition-all">
                <div className="w-20 h-20 bg-slate-900 rounded-[2rem] flex items-center justify-center mb-4 border border-white/10 group-hover:border-emerald-500/50 transition-all duration-500">
                  <svg className="w-8 h-8 text-slate-500 group-hover:text-emerald-500 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg>
                </div>
                <span className="text-slate-500 font-bold uppercase tracking-widest text-xs">Import Local Source</span>
                <input type="file" className="hidden" accept="video/*" onChange={handleFileChange} />
              </label>
            )}

            {isProcessing && (
              <div className="absolute top-6 right-6 px-4 py-2 bg-slate-950/80 backdrop-blur-md rounded-xl border border-white/10 text-[10px] font-black text-emerald-500 flex items-center gap-2 shadow-xl ring-1 ring-emerald-500/20">
                <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-ping" />
                ACTIVE: {MODEL_POOL.find(m => m.id === activeModelId)?.label}
              </div>
            )}
          </div>

          <div className="flex flex-col md:flex-row gap-6">
            <div className="flex-1 glass-panel p-10 rounded-[3rem] flex flex-col md:flex-row items-center justify-between gap-8 shadow-xl border border-white/5">
              <div className="space-y-1">
                <span className="text-emerald-500 text-[10px] font-black uppercase tracking-widest">Neural Failover: ARMED</span>
                <h2 className="text-2xl font-bold text-white tracking-tight">Transcription Pipeline</h2>
                <p className="text-slate-500 text-sm">Target: YouTube Multi-Language SRT.</p>
              </div>
              <div className="flex gap-4 w-full md:w-auto">
                <button 
                  onClick={startProcessing}
                  disabled={!videoFile || isProcessing || !isOnline}
                  className="flex-1 md:flex-none bg-emerald-500 hover:bg-emerald-400 disabled:opacity-20 text-slate-950 font-black px-12 py-5 rounded-2xl transition-all shadow-[0_15px_40px_-10px_rgba(16,185,129,0.3)] active:scale-95"
                >
                  {isProcessing ? `Linking...` : 'Engage Grid'}
                </button>
                <button 
                  onClick={downloadSRT}
                  disabled={segments.length === 0}
                  className="flex-1 md:flex-none bg-slate-800 hover:bg-slate-700 disabled:opacity-20 text-white font-bold px-10 py-5 rounded-2xl border border-white/10 transition-all"
                >
                  Export SRT
                </button>
              </div>
            </div>

            <div className={`md:w-64 glass-panel p-8 rounded-[3rem] flex flex-col justify-center items-center gap-2 shadow-xl border ${status.status === 'error' ? 'border-red-500/40' : 'border-white/5'}`}>
               <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Engine Health</span>
               <div className={`text-4xl font-black ${globalSuccessRate < 40 ? 'text-red-500' : 'text-emerald-500'}`}>{globalSuccessRate}%</div>
               <div className="w-full bg-slate-900 h-1 rounded-full overflow-hidden mt-2">
                 <div className={`${globalSuccessRate < 40 ? 'bg-red-500' : 'bg-emerald-500'} h-full transition-all duration-700`} style={{ width: `${globalSuccessRate}%` }} />
               </div>
            </div>
          </div>

          <div className={`text-center px-10 py-3 rounded-2xl transition-colors ${status.status === 'error' ? 'bg-red-500/5 border border-red-500/10' : ''}`}>
            <p className={`text-[10px] font-black uppercase tracking-[0.4em] ${status.status === 'error' ? 'text-red-500' : 'text-slate-600 animate-pulse'}`}>
              {status.message}
            </p>
          </div>
        </div>

        {/* Sidebar: Analytics & Diagnostic Stream */}
        <div className="lg:col-span-4 flex flex-col gap-6">
          <div className="glass-panel rounded-[2.5rem] p-6 shadow-xl ring-1 ring-white/10 flex flex-col">
            <h3 className="text-[10px] font-black uppercase tracking-widest text-slate-500 mb-4 flex items-center justify-between">
              <span>Diagnostic Feed</span>
              <span className="text-emerald-500/70 font-bold uppercase">Failovers: {analytics.failoverEvents}</span>
            </h3>
            <div className="grid grid-cols-2 gap-3 mb-6">
              <div className="bg-slate-950/50 p-4 rounded-2xl border border-white/5">
                <p className="text-[8px] font-black text-slate-600 uppercase">Requests</p>
                <p className="text-lg font-bold text-white">{analytics.totalRequests}</p>
              </div>
              <div className="bg-slate-950/50 p-4 rounded-2xl border border-white/5">
                <p className="text-[8px] font-black text-slate-600 uppercase">Avg Latency</p>
                <p className="text-lg font-bold text-white">{averageLatencyDisplay}s</p>
              </div>
            </div>

            <div className="flex-1 max-h-[200px] overflow-y-auto custom-scrollbar space-y-2">
              {incidents.length === 0 ? (
                <div className="text-center py-10 opacity-20 text-[9px] font-black uppercase tracking-widest">Neural Link Nominal</div>
              ) : (
                incidents.map((inc, i) => (
                  <div key={i} className={`text-[9px] p-3 rounded-xl border transition-all ${
                    inc.severity === 'critical' ? 'bg-red-500/10 border-red-500/20' : 
                    inc.severity === 'info' ? 'bg-emerald-500/10 border-emerald-500/20' : 
                    'bg-slate-900/50 border-white/5'
                  }`}>
                    <div className="flex justify-between items-start mb-1">
                      <span className={`font-black ${
                        inc.severity === 'critical' ? 'text-red-400' : 
                        inc.severity === 'info' ? 'text-emerald-400' : 
                        'text-amber-500'
                      }`}>{inc.type}</span>
                      <span className="text-slate-600 font-mono text-[8px]">{inc.time}</span>
                    </div>
                    <p className="text-slate-400 leading-tight">[{inc.model}] {inc.detail}</p>
                  </div>
                ))
              )}
            </div>
          </div>

          {/* Transcription Feed Output */}
          <div className="glass-panel rounded-[3rem] flex-1 flex flex-col shadow-2xl overflow-hidden ring-1 ring-white/10 min-h-[400px]">
            <div className="p-8 border-b border-white/5 bg-slate-950/20 flex items-center justify-between">
              <h3 className="text-xs font-black uppercase tracking-widest text-white">Live Neural Feed</h3>
              <span className="text-emerald-500 bg-emerald-500/10 px-3 py-1 rounded-lg text-[9px] font-black">{segments.length} BLOCKS</span>
            </div>

            <div className="flex-1 overflow-y-auto p-6 space-y-4 custom-scrollbar">
              {segments.length === 0 && (
                <div className="h-full flex flex-col items-center justify-center text-center opacity-10 italic text-xs space-y-3 py-20">
                  <div className="w-12 h-12 border-2 border-slate-700 border-dashed rounded-full animate-spin-slow" />
                  <p className="font-black uppercase tracking-widest">Synchronizing Cores...</p>
                </div>
              )}
              {segments.map((seg, idx) => (
                <div key={seg.id} className="bg-slate-900/40 p-5 rounded-2xl border border-white/5 hover:border-emerald-500/30 transition-all group animate-in fade-in slide-in-from-bottom-2 duration-300">
                  <div className="flex justify-between items-center mb-2">
                    <span className="text-[9px] font-black text-slate-700 uppercase">Block {String(idx + 1).padStart(3, '0')}</span>
                    <span className="text-[9px] font-mono text-emerald-500 bg-emerald-500/5 px-2 py-1 rounded-md">
                      {Math.floor(seg.start_seconds / 60)}:{(seg.start_seconds % 60).toFixed(1).padStart(4, '0')}
                    </span>
                  </div>
                  <p className="text-slate-300 text-xs leading-relaxed font-medium group-hover:text-white transition-colors">{seg.text}</p>
                </div>
              ))}
              <div ref={transcriptEndRef} />
            </div>

            <div className="p-4 bg-slate-950/50 border-t border-white/5">
              <div className="w-full h-1.5 bg-slate-800 rounded-full overflow-hidden">
                <div className={`h-full bg-emerald-500 transition-all duration-1000 ${isProcessing ? 'animate-pulse' : ''}`} style={{ width: `${progress}%` }} />
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { GoogleGenAI, Type } from '@google/genai';
import { blobToBase64, audioBufferToWav, downsampleAudioBuffer } from './utils/audioUtils';
import { generateSRT } from './utils/timeFormatter';
import { ProcessingState, CaptionSegment, AnalyticsData, ModelMetric, ProcessingEngine } from './types';

// Neural Model Pool: Prioritized based on capabilities
const MODEL_POOL = [
  { id: 'gemini-3-flash-preview', label: 'Flash 3.0', description: 'Optimal Balanced Core' },
  { id: 'gemini-2.5-flash-native-audio-preview-12-2025', label: 'Audio Native 2.5', description: 'Waveform Specialist' },
  { id: 'gemini-3-pro-preview', label: 'Pro 3.0', description: 'Advanced Reasoning Logic' },
  { id: 'gemini-flash-lite-latest', label: 'Flash Lite', description: 'High-Throughput Fallback' }
];

// Failover Sequence Map: Defines the recovery path for each processing mode
const ENGINE_MAP: Record<ProcessingEngine, number[]> = {
  titan: [0, 1, 2, 3],       // Standard balanced approach
  silentwave: [1, 0, 3, 2],  // Starts with Native Audio for max transcription fidelity
  globallink: [2, 0, 1, 3]   // Starts with Pro 3.0 for nuanced semantic translation
};

const CHUNK_DURATION = 300; // 5-minute segments
const REQUEST_GAP = 5000; // 5s gap between batches to prevent 429 rate limiting

const INITIAL_ANALYTICS: AnalyticsData = {
  totalRequests: 0,
  successfulRequests: 0,
  failoverEvents: 0,
  startTime: null,
  endTime: null,
  modelMetrics: MODEL_POOL.reduce((acc, model) => {
    acc[model.id] = { success: 0, fail: 0, avgLatency: 0, totalLatency: 0 };
    return acc;
  }, {} as Record<string, ModelMetric>)
};

interface Incident {
  time: string;
  model: string;
  type: string;
  detail: string;
  severity: 'warning' | 'critical' | 'info';
}

const App: React.FC = () => {
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [videoFile, setVideoFile] = useState<File | null>(null);
  const [selectedEngine, setSelectedEngine] = useState<ProcessingEngine>('titan');
  const [status, setStatus] = useState<ProcessingState>({
    status: 'idle',
    message: 'Multi-Engine Neural Link Ready.'
  });
  const [segments, setSegments] = useState<CaptionSegment[]>([]);
  const [progress, setProgress] = useState(0);
  const [isProcessing, setIsProcessing] = useState(false);
  const [activeModelId, setActiveModelId] = useState<string>(MODEL_POOL[0].id);
  const [analytics, setAnalytics] = useState<AnalyticsData>(INITIAL_ANALYTICS);
  const [incidents, setIncidents] = useState<Incident[]>([]);
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  const transcriptEndRef = useRef<HTMLDivElement>(null);

  // Connectivity monitoring for failover safety
  useEffect(() => {
    const handleStatusChange = () => setIsOnline(navigator.onLine);
    window.addEventListener('online', handleStatusChange);
    window.addEventListener('offline', handleStatusChange);
    return () => {
      window.removeEventListener('online', handleStatusChange);
      window.removeEventListener('offline', handleStatusChange);
    };
  }, []);

  // Ensure the live transcription feed always follows the latest output
  useEffect(() => {
    transcriptEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [segments]);

  const updateAnalytics = (modelId: string, latency: number, success: boolean) => {
    setAnalytics(prev => {
      const modelMetric = prev.modelMetrics[modelId] || { success: 0, fail: 0, avgLatency: 0, totalLatency: 0 };
      const newSuccess = modelMetric.success + (success ? 1 : 0);
      const newFail = modelMetric.fail + (success ? 0 : 1);
      const newTotalLatency = modelMetric.totalLatency + latency;

      return {
        ...prev,
        totalRequests: prev.totalRequests + 1,
        successfulRequests: prev.successfulRequests + (success ? 1 : 0),
        modelMetrics: {
          ...prev.modelMetrics,
          [modelId]: {
            success: newSuccess,
            fail: newFail,
            totalLatency: newTotalLatency,
            avgLatency: newTotalLatency / (newSuccess + newFail || 1)
          }
        }
      };
    });
  };

  const logIncident = (model: string, type: string, detail: string, severity: 'warning' | 'critical' | 'info' = 'warning') => {
    const newIncident: Incident = {
      time: new Date().toLocaleTimeString([], { hour12: false, hour: '2-digit', minute: '2-digit', second: '2-digit' }),
      model,
      type,
      detail,
      severity
    };
    setIncidents(prev => [newIncident, ...prev].slice(0, 30));
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      setVideoFile(file);
      setVideoUrl(URL.createObjectURL(file));
      setSegments([]);
      setProgress(0);
      setIncidents([]);
      setAnalytics(INITIAL_ANALYTICS);
      setStatus({ status: 'idle', message: 'Neural Grid Standby.' });
    }
  };

  /**
   * Recursive Neural Failover Handler
   * Orchestrates retries and model shifting based on engine priority.
   */
  const processBatchWithFailover = async (
    audioBuffer: AudioBuffer, 
    offset: number, 
    batchIndex: number, 
    attemptIndex: number = 0,
    retryCount: number = 0
  ): Promise<boolean> => {
    const sequence = ENGINE_MAP[selectedEngine];
    if (attemptIndex >= sequence.length) return false;
    if (!navigator.onLine) return false;

    const modelIdx = sequence[attemptIndex];
    const currentModel = MODEL_POOL[modelIdx];
    setActiveModelId(currentModel.id);

    let systemInstruction = "Precisely transcribe and translate this audio into natural English. Return a JSON array of objects with: start (float seconds), end (float seconds), text (English string).";
    if (selectedEngine === 'silentwave') {
      systemInstruction = "Acting as a Whisper-class transcription specialist, prioritize verbatim acoustic fidelity. Translate any foreign speech into standard English. Output as JSON array: [{start, end, text}].";
    } else if (selectedEngine === 'globallink') {
      systemInstruction = "Acting as a high-precision translation agent (Meta NLLB style), perform deep semantic analysis. Translate foreign expressions into natural idiomatic English. Output as JSON array: [{start, end, text}].";
    }

    const requestStart = performance.now();

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const optimizedBuffer = await downsampleAudioBuffer(audioBuffer, 16000);
      const wavBlob = audioBufferToWav(optimizedBuffer);
      const base64Data = await blobToBase64(wavBlob);

      setStatus({ 
        status: 'streaming', 
        message: `[${selectedEngine.toUpperCase()}] Batch ${batchIndex + 1} processing on ${currentModel.label}...` 
      });

      const response = await ai.models.generateContent({
        model: currentModel.id,
        contents: [{
          parts: [
            { inlineData: { mimeType: 'audio/wav', data: base64Data } },
            { text: systemInstruction }
          ]
        }],
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                start: { type: Type.NUMBER },
                end: { type: Type.NUMBER },
                text: { type: Type.STRING }
              },
              required: ['start', 'end', 'text']
            }
          }
        }
      });

      const latency = performance.now() - requestStart;
      updateAnalytics(currentModel.id, latency, true);

      const data = JSON.parse(response.text || "[]");
      const adjustedSegments = data.map((s: any, i: number) => ({
        id: Date.now() + Math.random() + i,
        start_seconds: s.start + offset,
        end_seconds: s.end + offset,
        text: s.text
      }));

      setSegments(prev => [...prev, ...adjustedSegments].sort((a, b) => a.start_seconds - b.start_seconds));
      return true;
    } catch (error: any) {
      const latency = performance.now() - requestStart;
      const errMsg = error.message || String(error);
      const isQuota = errMsg.includes("429") || errMsg.includes("RESOURCE_EXHAUSTED") || errMsg.includes("Quota");

      logIncident(currentModel.label, isQuota ? "Quota" : "Fault", errMsg, isQuota ? 'warning' : 'critical');
      updateAnalytics(currentModel.id, latency, false);

      // 1. Quota Failover: Immediate shift to next model
      if (isQuota) {
        if (attemptIndex < sequence.length - 1) {
          const nextModel = MODEL_POOL[sequence[attemptIndex + 1]];
          logIncident("Failover", "Quota Shift", `Core ${currentModel.label} exhausted. Shifting to fallback: ${nextModel.label}.`, 'info');
          setAnalytics(prev => ({ ...prev, failoverEvents: prev.failoverEvents + 1 }));
          setStatus({ status: 'connecting', message: `Failover Sequence: Activating Secondary Core...` });

          await new Promise(r => setTimeout(r, 7000)); // Allow API some breathing room
          return processBatchWithFailover(audioBuffer, offset, batchIndex, attemptIndex + 1, 0);
        }
      }

      // 2. Transient Retry: Try same model once before shifting
      if (retryCount < 1 && !isQuota) {
        setStatus({ status: 'connecting', message: `Transient Error. Retrying current core...` });
        await new Promise(r => setTimeout(r, 2000));
        return processBatchWithFailover(audioBuffer, offset, batchIndex, attemptIndex, retryCount + 1);
      }

      // 3. Exhaustion Failover: Shift to next model in sequence
      if (attemptIndex < sequence.length - 1) {
        const nextModel = MODEL_POOL[sequence[attemptIndex + 1]];
        logIncident("Failover", "Fault Recovery", `Exhausted core ${currentModel.label}. Shifting to ${nextModel.label}.`, 'info');
        setAnalytics(prev => ({ ...prev, failoverEvents: prev.failoverEvents + 1 }));
        return processBatchWithFailover(audioBuffer, offset, batchIndex, attemptIndex + 1, 0);
      }

      return false;
    }
  };

  const startProcessing = async () => {
    if (!videoFile || isProcessing) return;

    try {
      setIsProcessing(true);
      setAnalytics(prev => ({ ...prev, startTime: Date.now(), endTime: null }));
      setStatus({ status: 'connecting', message: 'Decoding Local Media Buffer...' });

      const arrayBuffer = await videoFile.arrayBuffer();
      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
      const decodedBuffer = await audioCtx.decodeAudioData(arrayBuffer);

      const duration = decodedBuffer.duration;
      const numChunks = Math.ceil(duration / CHUNK_DURATION);

      for (let i = 0; i < numChunks; i++) {
        const start = i * CHUNK_DURATION;
        const end = Math.min(start + CHUNK_DURATION, duration);
        const frameStart = Math.floor(start * decodedBuffer.sampleRate);
        const frameEnd = Math.floor(end * decodedBuffer.sampleRate);

        const chunkBuffer = audioCtx.createBuffer(1, frameEnd - frameStart, decodedBuffer.sampleRate);
        chunkBuffer.copyToChannel(decodedBuffer.getChannelData(0).subarray(frameStart, frameEnd), 0);

        const success = await processBatchWithFailover(chunkBuffer, start, i, 0, 0);
        if (!success) throw new Error("Neural Grid Failure. All fallback cores exhausted.");

        setProgress(Math.round(((i + 1) / numChunks) * 100));
        if (i < numChunks - 1) await new Promise(r => setTimeout(r, REQUEST_GAP));
      }

      setAnalytics(prev => ({ ...prev, endTime: Date.now() }));
      setStatus({ status: 'completed', message: 'Neural Translation Link Terminated Successfully.' });
      setIsProcessing(false);
    } catch (error: any) {
      setIsProcessing(false);
      setAnalytics(prev => ({ ...prev, endTime: Date.now() }));
      setStatus({ status: 'error', message: error.message });
      logIncident("Pipeline", "Fatal", error.message, "critical");
    }
  };

  const downloadSRT = () => {
    const srt = generateSRT(segments);
    const blob = new Blob([srt], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `PhilipAI_Captions.srt`;
    document.body.appendChild(a); a.click(); document.body.removeChild(a);
  };

  const globalSuccessRate = useMemo(() => {
    if (analytics.totalRequests === 0) return 0;
    return Math.round((analytics.successfulRequests / analytics.totalRequests) * 100);
  }, [analytics]);

  const totalTimeElapsed = useMemo(() => {
    const { startTime, endTime } = analytics;
    // Explicit null checks and narrowing to satisfy arithmetic constraints in TS.
    if (startTime === null) return '0s';
    const end = endTime !== null ? endTime : Date.now();
    const diff = (end - startTime) / 1000;
    return diff < 60 ? `${diff.toFixed(1)}s` : `${Math.floor(diff / 60)}m ${Math.floor(diff % 60)}s`;
  }, [analytics.startTime, analytics.endTime]);

  const averageLatencyDisplay = useMemo(() => {
    // Explicitly cast to ModelMetric[] and handle reduction with a typed accumulator to prevent arithmetic errors.
    const metrics = Object.values(analytics.modelMetrics) as ModelMetric[];
    const totalLatency = metrics.reduce((acc: number, curr: ModelMetric) => acc + curr.totalLatency, 0);
    const requests = analytics.totalRequests || 1;
    return (totalLatency / requests / 1000).toFixed(2);
  }, [analytics.modelMetrics, analytics.totalRequests]);

  return (
    <div className="min-h-screen p-4 md:p-10 flex flex-col gap-8 max-w-7xl mx-auto selection:bg-emerald-500/30">
      {/* Brand Header */}
      <header className="flex flex-col lg:flex-row items-stretch gap-6">
        <div className="flex-1 glass-panel p-8 rounded-[2.5rem] flex items-center gap-6 shadow-xl ring-1 ring-white/5 hover:ring-white/10 transition-all group">
          {/* Upgraded Neural-Wave Logo */}
          <div className="relative w-16 h-16 shrink-0 group-hover:scale-105 transition-transform duration-500">
            <div className="absolute inset-0 bg-gradient-to-br from-emerald-400 to-emerald-600 rounded-2xl shadow-[0_0_30px_rgba(16,185,129,0.4)] transition-all duration-500 group-hover:rotate-6"></div>
            <div className="absolute inset-0 flex items-center justify-center">
              <svg className="w-10 h-10 text-slate-950 fill-current" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
                <path d="M12 2L4.5 20.29L5.21 21L12 18L18.79 21L19.5 20.29L12 2Z" opacity="0.2" />
                <path d="M12 3L6 18L12 15L18 18L12 3Z" />
                <circle cx="12" cy="7" r="1.5" />
                <circle cx="9" cy="14" r="1" opacity="0.6" />
                <circle cx="15" cy="14" r="1" opacity="0.6" />
                <path d="M12 7L9 14" stroke="currentColor" strokeWidth="0.5" opacity="0.3" />
                <path d="M12 7L15 14" stroke="currentColor" strokeWidth="0.5" opacity="0.3" />
                <path d="M9 14L15 14" stroke="currentColor" strokeWidth="0.5" opacity="0.3" />
              </svg>
            </div>
            <div className="absolute -bottom-1 -right-1 w-4 h-4 bg-slate-950 rounded-full flex items-center justify-center border border-emerald-500/50">
              <div className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse"></div>
            </div>
          </div>

          <div>
            <h1 className="text-4xl font-black tracking-tighter text-white">Philip<span className="text-emerald-500">AI</span></h1>
            <p className="text-[10px] font-black uppercase tracking-[0.4em] text-slate-500 mt-1 flex items-center gap-2">
              <span className={`w-1.5 h-1.5 rounded-full ${isOnline ? 'bg-emerald-500' : 'bg-red-500 animate-ping'}`} />
              {isOnline ? 'Neural Link Ready' : 'Core Connection Interrupted'}
            </p>
          </div>
        </div>

        {/* Engine Control Interface */}
        <div className="flex-[2] glass-panel p-4 rounded-[2.5rem] grid grid-cols-1 md:grid-cols-3 gap-3 shadow-xl ring-1 ring-white/5">
          {[
            { id: 'titan', name: 'Titan Core', desc: 'Full Failover Stack', icon: 'M13 10V3L4 14h7v7l9-11h-7z', color: 'text-blue-400' },
            { id: 'silentwave', name: 'SilentWave', desc: 'Whisper-Class Acoustic', icon: 'M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z', color: 'text-purple-400' },
            { id: 'globallink', name: 'GlobalLink', desc: 'Meta High-Reasoning', icon: 'M3.055 11H5a2 2 0 012 2v1a2 2 0 002 2 2 2 0 012 2v2.945M8 3.935V5.5A2.5 2.5 0 0010.5 8h.5a2 2 0 012 2 2 2 0 104 0 2 2 0 012-2h1.065', color: 'text-amber-400' }
          ].map((engine) => (
            <button
              key={engine.id}
              disabled={isProcessing}
              onClick={() => setSelectedEngine(engine.id as ProcessingEngine)}
              className={`p-4 rounded-3xl border transition-all text-left flex flex-col gap-1 relative overflow-hidden group ${
                selectedEngine === engine.id 
                  ? 'bg-white/5 border-emerald-500/40 shadow-lg' 
                  : 'bg-transparent border-white/5 opacity-50 hover:opacity-100 hover:border-white/10'
              }`}
            >
              <div className="flex items-center gap-2">
                <svg className={`w-4 h-4 ${engine.color}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d={engine.icon} /></svg>
                <span className="text-xs font-black text-white uppercase">{engine.name}</span>
              </div>
              <p className="text-[9px] text-slate-500 font-medium leading-tight">{engine.desc}</p>
              {selectedEngine === engine.id && <div className="absolute top-0 right-0 p-2"><div className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-ping" /></div>}
            </button>
          ))}
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Workspace: Media Processing Central */}
        <div className="lg:col-span-8 flex flex-col gap-6">
          <div className="aspect-video bg-black rounded-[3rem] overflow-hidden border border-white/5 shadow-2xl relative ring-1 ring-white/10 group">
            {videoUrl ? (
              <video src={videoUrl} controls className="w-full h-full object-contain" />
            ) : (
              <label className="absolute inset-0 flex flex-col items-center justify-center cursor-pointer hover:bg-slate-900/50 transition-all">
                <div className="w-20 h-20 bg-slate-900 rounded-[2rem] flex items-center justify-center mb-4 border border-white/10 group-hover:border-emerald-500/50 transition-all duration-500">
                  <svg className="w-8 h-8 text-slate-500 group-hover:text-emerald-500 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg>
                </div>
                <span className="text-slate-500 font-bold uppercase tracking-widest text-xs">Import Local Source</span>
                <input type="file" className="hidden" accept="video/*" onChange={handleFileChange} />
              </label>
            )}

            {isProcessing && (
              <div className="absolute top-6 right-6 px-4 py-2 bg-slate-950/80 backdrop-blur-md rounded-xl border border-white/10 text-[10px] font-black text-emerald-500 flex items-center gap-2 shadow-xl ring-1 ring-emerald-500/20">
                <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-ping" />
                ACTIVE: {MODEL_POOL.find(m => m.id === activeModelId)?.label}
              </div>
            )}
          </div>

          <div className="flex flex-col md:flex-row gap-6">
            <div className="flex-1 glass-panel p-10 rounded-[3rem] flex flex-col md:flex-row items-center justify-between gap-8 shadow-xl border border-white/5">
              <div className="space-y-1">
                <span className="text-emerald-500 text-[10px] font-black uppercase tracking-widest">Neural Failover: ARMED</span>
                <h2 className="text-2xl font-bold text-white tracking-tight">Transcription Pipeline</h2>
                <p className="text-slate-500 text-sm">Target: YouTube Multi-Language SRT.</p>
              </div>
              <div className="flex gap-4 w-full md:w-auto">
                <button 
                  onClick={startProcessing}
                  disabled={!videoFile || isProcessing || !isOnline}
                  className="flex-1 md:flex-none bg-emerald-500 hover:bg-emerald-400 disabled:opacity-20 text-slate-950 font-black px-12 py-5 rounded-2xl transition-all shadow-[0_15px_40px_-10px_rgba(16,185,129,0.3)] active:scale-95"
                >
                  {isProcessing ? `Linking...` : 'Engage Grid'}
                </button>
                <button 
                  onClick={downloadSRT}
                  disabled={segments.length === 0}
                  className="flex-1 md:flex-none bg-slate-800 hover:bg-slate-700 disabled:opacity-20 text-white font-bold px-10 py-5 rounded-2xl border border-white/10 transition-all"
                >
                  Export SRT
                </button>
              </div>
            </div>

            <div className={`md:w-64 glass-panel p-8 rounded-[3rem] flex flex-col justify-center items-center gap-2 shadow-xl border ${status.status === 'error' ? 'border-red-500/40' : 'border-white/5'}`}>
               <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Engine Health</span>
               <div className={`text-4xl font-black ${globalSuccessRate < 40 ? 'text-red-500' : 'text-emerald-500'}`}>{globalSuccessRate}%</div>
               <div className="w-full bg-slate-900 h-1 rounded-full overflow-hidden mt-2">
                 <div className={`${globalSuccessRate < 40 ? 'bg-red-500' : 'bg-emerald-500'} h-full transition-all duration-700`} style={{ width: `${globalSuccessRate}%` }} />
               </div>
            </div>
          </div>

          <div className={`text-center px-10 py-3 rounded-2xl transition-colors ${status.status === 'error' ? 'bg-red-500/5 border border-red-500/10' : ''}`}>
            <p className={`text-[10px] font-black uppercase tracking-[0.4em] ${status.status === 'error' ? 'text-red-500' : 'text-slate-600 animate-pulse'}`}>
              {status.message}
            </p>
          </div>
        </div>

        {/* Sidebar: Analytics & Diagnostic Stream */}
        <div className="lg:col-span-4 flex flex-col gap-6">
          <div className="glass-panel rounded-[2.5rem] p-6 shadow-xl ring-1 ring-white/10 flex flex-col">
            <h3 className="text-[10px] font-black uppercase tracking-widest text-slate-500 mb-4 flex items-center justify-between">
              <span>Diagnostic Feed</span>
              <span className="text-emerald-500/70 font-bold uppercase">Failovers: {analytics.failoverEvents}</span>
            </h3>
            <div className="grid grid-cols-2 gap-3 mb-6">
              <div className="bg-slate-950/50 p-4 rounded-2xl border border-white/5">
                <p className="text-[8px] font-black text-slate-600 uppercase">Requests</p>
                <p className="text-lg font-bold text-white">{analytics.totalRequests}</p>
              </div>
              <div className="bg-slate-950/50 p-4 rounded-2xl border border-white/5">
                <p className="text-[8px] font-black text-slate-600 uppercase">Avg Latency</p>
                <p className="text-lg font-bold text-white">{averageLatencyDisplay}s</p>
              </div>
            </div>

            <div className="flex-1 max-h-[200px] overflow-y-auto custom-scrollbar space-y-2">
              {incidents.length === 0 ? (
                <div className="text-center py-10 opacity-20 text-[9px] font-black uppercase tracking-widest">Neural Link Nominal</div>
              ) : (
                incidents.map((inc, i) => (
                  <div key={i} className={`text-[9px] p-3 rounded-xl border transition-all ${
                    inc.severity === 'critical' ? 'bg-red-500/10 border-red-500/20' : 
                    inc.severity === 'info' ? 'bg-emerald-500/10 border-emerald-500/20' : 
                    'bg-slate-900/50 border-white/5'
                  }`}>
                    <div className="flex justify-between items-start mb-1">
                      <span className={`font-black ${
                        inc.severity === 'critical' ? 'text-red-400' : 
                        inc.severity === 'info' ? 'text-emerald-400' : 
                        'text-amber-500'
                      }`}>{inc.type}</span>
                      <span className="text-slate-600 font-mono text-[8px]">{inc.time}</span>
                    </div>
                    <p className="text-slate-400 leading-tight">[{inc.model}] {inc.detail}</p>
                  </div>
                ))
              )}
            </div>
          </div>

          {/* Transcription Feed Output */}
          <div className="glass-panel rounded-[3rem] flex-1 flex flex-col shadow-2xl overflow-hidden ring-1 ring-white/10 min-h-[400px]">
            <div className="p-8 border-b border-white/5 bg-slate-950/20 flex items-center justify-between">
              <h3 className="text-xs font-black uppercase tracking-widest text-white">Live Neural Feed</h3>
              <span className="text-emerald-500 bg-emerald-500/10 px-3 py-1 rounded-lg text-[9px] font-black">{segments.length} BLOCKS</span>
            </div>

            <div className="flex-1 overflow-y-auto p-6 space-y-4 custom-scrollbar">
              {segments.length === 0 && (
                <div className="h-full flex flex-col items-center justify-center text-center opacity-10 italic text-xs space-y-3 py-20">
                  <div className="w-12 h-12 border-2 border-slate-700 border-dashed rounded-full animate-spin-slow" />
                  <p className="font-black uppercase tracking-widest">Synchronizing Cores...</p>
                </div>
              )}
              {segments.map((seg, idx) => (
                <div key={seg.id} className="bg-slate-900/40 p-5 rounded-2xl border border-white/5 hover:border-emerald-500/30 transition-all group animate-in fade-in slide-in-from-bottom-2 duration-300">
                  <div className="flex justify-between items-center mb-2">
                    <span className="text-[9px] font-black text-slate-700 uppercase">Block {String(idx + 1).padStart(3, '0')}</span>
                    <span className="text-[9px] font-mono text-emerald-500 bg-emerald-500/5 px-2 py-1 rounded-md">
                      {Math.floor(seg.start_seconds / 60)}:{(seg.start_seconds % 60).toFixed(1).padStart(4, '0')}
                    </span>
                  </div>
                  <p className="text-slate-300 text-xs leading-relaxed font-medium group-hover:text-white transition-colors">{seg.text}</p>
                </div>
              ))}
              <div ref={transcriptEndRef} />
            </div>

            <div className="p-4 bg-slate-950/50 border-t border-white/5">
              <div className="w-full h-1.5 bg-slate-800 rounded-full overflow-hidden">
                <div className={`h-full bg-emerald-500 transition-all duration-1000 ${isProcessing ? 'animate-pulse' : ''}`} style={{ width: `${progress}%` }} />
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;

export type ProcessingEngine = 'titan' | 'silentwave' | 'globallink' | 'nexus';

export interface CaptionSegment {
  id: number;
  start_seconds: number;
  end_seconds: number;
  text: string;
}

export interface ProcessingState {
  status: 'idle' | 'connecting' | 'streaming' | 'completed' | 'error';
  message: string;
}

export interface ModelMetric {
  success: number;
  fail: number;
  avgLatency: number;
  totalLatency: number;
}

export interface AnalyticsData {
  totalRequests: number;
  successfulRequests: number;
  failoverEvents: number;
  startTime: number | null;
  endTime: number | null;
  modelMetrics: Record<string, ModelMetric>;
}

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { GoogleGenAI, Type } from '@google/genai';
import { blobToBase64, audioBufferToWav, downsampleAudioBuffer } from './utils/audioUtils';
import { generateSRT } from './utils/timeFormatter';
import { ProcessingState, CaptionSegment, AnalyticsData, ModelMetric, ProcessingEngine } from './types';

// Neural Model Pool: Prioritized based on capabilities
const MODEL_POOL = [
  { id: 'gemini-3-flash-preview', label: 'Flash 3.0', description: 'Optimal Balanced Core' },
  { id: 'gemini-2.5-flash-native-audio-preview-12-2025', label: 'Audio Native 2.5', description: 'Waveform Specialist' },
  { id: 'gemini-3-pro-preview', label: 'Pro 3.0', description: 'Advanced Reasoning Logic' },
  { id: 'gemini-flash-lite-latest', label: 'Flash Lite', description: 'High-Throughput Fallback' }
];

// Failover Sequence Map: Defines the recovery path for each processing mode
const ENGINE_MAP: Record<ProcessingEngine, number[]> = {
  titan: [0, 1, 2, 3],       // Standard balanced approach
  silentwave: [1, 0, 3, 2],  // Starts with Native Audio for max transcription fidelity
  globallink: [2, 0, 1, 3],  // Starts with Pro 3.0 for nuanced semantic translation
  nexus: [2, 0, 1, 3]        // Anthropic Claude-Class: Maximum reasoning and linguistic precision
};

const CHUNK_DURATION = 300; // 5-minute segments
const REQUEST_GAP = 5000; // 5s gap between batches to prevent 429 rate limiting

const INITIAL_ANALYTICS: AnalyticsData = {
  totalRequests: 0,
  successfulRequests: 0,
  failoverEvents: 0,
  startTime: null,
  endTime: null,
  modelMetrics: MODEL_POOL.reduce((acc, model) => {
    acc[model.id] = { success: 0, fail: 0, avgLatency: 0, totalLatency: 0 };
    return acc;
  }, {} as Record<string, ModelMetric>)
};

interface Incident {
  time: string;
  model: string;
  type: string;
  detail: string;
  severity: 'warning' | 'critical' | 'info';
}

const App: React.FC = () => {
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [videoFile, setVideoFile] = useState<File | null>(null);
  const [selectedEngine, setSelectedEngine] = useState<ProcessingEngine>('titan');
  const [status, setStatus] = useState<ProcessingState>({
    status: 'idle',
    message: 'Multi-Engine Neural Link Ready.'
  });
  const [segments, setSegments] = useState<CaptionSegment[]>([]);
  const [progress, setProgress] = useState(0);
  const [isProcessing, setIsProcessing] = useState(false);
  const [activeModelId, setActiveModelId] = useState<string>(MODEL_POOL[0].id);
  const [analytics, setAnalytics] = useState<AnalyticsData>(INITIAL_ANALYTICS);
  const [incidents, setIncidents] = useState<Incident[]>([]);
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  const transcriptEndRef = useRef<HTMLDivElement>(null);

  // Connectivity monitoring for failover safety
  useEffect(() => {
    const handleStatusChange = () => setIsOnline(navigator.onLine);
    window.addEventListener('online', handleStatusChange);
    window.addEventListener('offline', handleStatusChange);
    return () => {
      window.removeEventListener('online', handleStatusChange);
      window.removeEventListener('offline', handleStatusChange);
    };
  }, []);

  // Ensure the live transcription feed always follows the latest output
  useEffect(() => {
    transcriptEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [segments]);

  const updateAnalytics = (modelId: string, latency: number, success: boolean) => {
    setAnalytics(prev => {
      const modelMetric = prev.modelMetrics[modelId] || { success: 0, fail: 0, avgLatency: 0, totalLatency: 0 };
      const newSuccess = modelMetric.success + (success ? 1 : 0);
      const newFail = modelMetric.fail + (success ? 0 : 1);
      const newTotalLatency = modelMetric.totalLatency + latency;

      return {
        ...prev,
        totalRequests: prev.totalRequests + 1,
        successfulRequests: prev.successfulRequests + (success ? 1 : 0),
        modelMetrics: {
          ...prev.modelMetrics,
          [modelId]: {
            success: newSuccess,
            fail: newFail,
            totalLatency: newTotalLatency,
            avgLatency: newTotalLatency / (newSuccess + newFail || 1)
          }
        }
      };
    });
  };

  const logIncident = (model: string, type: string, detail: string, severity: 'warning' | 'critical' | 'info' = 'warning') => {
    const newIncident: Incident = {
      time: new Date().toLocaleTimeString([], { hour12: false, hour: '2-digit', minute: '2-digit', second: '2-digit' }),
      model,
      type,
      detail,
      severity
    };
    setIncidents(prev => [newIncident, ...prev].slice(0, 30));
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      setVideoFile(file);
      setVideoUrl(URL.createObjectURL(file));
      setSegments([]);
      setProgress(0);
      setIncidents([]);
      setAnalytics(INITIAL_ANALYTICS);
      setStatus({ status: 'idle', message: 'Neural Grid Standby.' });
    }
  };

  /**
   * Recursive Neural Failover Handler
   * Orchestrates retries and model shifting based on engine priority.
   */
  const processBatchWithFailover = async (
    audioBuffer: AudioBuffer, 
    offset: number, 
    batchIndex: number, 
    attemptIndex: number = 0,
    retryCount: number = 0
  ): Promise<boolean> => {
    const sequence = ENGINE_MAP[selectedEngine];
    if (attemptIndex >= sequence.length) return false;
    if (!navigator.onLine) return false;

    const modelIdx = sequence[attemptIndex];
    const currentModel = MODEL_POOL[modelIdx];
    setActiveModelId(currentModel.id);

    let systemInstruction = "Precisely transcribe and translate this audio into natural English. Return a JSON array of objects with: start (float seconds), end (float seconds), text (English string).";

    if (selectedEngine === 'silentwave') {
      systemInstruction = "Acting as a Whisper-class transcription specialist, prioritize verbatim acoustic fidelity. Translate any foreign speech into standard English. Output as JSON array: [{start, end, text}].";
    } else if (selectedEngine === 'globallink') {
      systemInstruction = "Acting as a high-precision translation agent (Meta NLLB style), perform deep semantic analysis. Translate foreign expressions into natural idiomatic English. Output as JSON array: [{start, end, text}].";
    } else if (selectedEngine === 'nexus') {
      systemInstruction = "Acting as a Claude-3 level reasoning engine, prioritize sophisticated linguistic structure and perfect English grammar. You are an expert at capturing complex context and nuanced speech. Output a valid JSON array of objects with keys: start, end, text.";
    }

    const requestStart = performance.now();

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const optimizedBuffer = await downsampleAudioBuffer(audioBuffer, 16000);
      const wavBlob = audioBufferToWav(optimizedBuffer);
      const base64Data = await blobToBase64(wavBlob);

      setStatus({ 
        status: 'streaming', 
        message: `[${selectedEngine.toUpperCase()}] Batch ${batchIndex + 1} processing on ${currentModel.label}...` 
      });

      const response = await ai.models.generateContent({
        model: currentModel.id,
        contents: [{
          parts: [
            { inlineData: { mimeType: 'audio/wav', data: base64Data } },
            { text: systemInstruction }
          ]
        }],
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                start: { type: Type.NUMBER },
                end: { type: Type.NUMBER },
                text: { type: Type.STRING }
              },
              required: ['start', 'end', 'text']
            }
          }
        }
      });

      const latency = performance.now() - requestStart;
      updateAnalytics(currentModel.id, latency, true);

      const data = JSON.parse(response.text || "[]");
      const adjustedSegments = data.map((s: any, i: number) => ({
        id: Date.now() + Math.random() + i,
        start_seconds: s.start + offset,
        end_seconds: s.end + offset,
        text: s.text
      }));

      setSegments(prev => [...prev, ...adjustedSegments].sort((a, b) => a.start_seconds - b.start_seconds));
      return true;
    } catch (error: any) {
      const latency = performance.now() - requestStart;
      const errMsg = error.message || String(error);
      const isQuota = errMsg.includes("429") || errMsg.includes("RESOURCE_EXHAUSTED") || errMsg.includes("Quota");

      logIncident(currentModel.label, isQuota ? "Quota" : "Fault", errMsg, isQuota ? 'warning' : 'critical');
      updateAnalytics(currentModel.id, latency, false);

      // 1. Quota Failover: Immediate shift to next model
      if (isQuota) {
        if (attemptIndex < sequence.length - 1) {
          const nextModel = MODEL_POOL[sequence[attemptIndex + 1]];
          logIncident("Failover", "Quota Shift", `Core ${currentModel.label} exhausted. Shifting to fallback: ${nextModel.label}.`, 'info');
          setAnalytics(prev => ({ ...prev, failoverEvents: prev.failoverEvents + 1 }));
          setStatus({ status: 'connecting', message: `Failover Sequence: Activating Secondary Core...` });

          await new Promise(r => setTimeout(r, 7000)); // Allow API some breathing room
          return processBatchWithFailover(audioBuffer, offset, batchIndex, attemptIndex + 1, 0);
        }
      }

      // 2. Transient Retry: Try same model once before shifting
      if (retryCount < 1 && !isQuota) {
        setStatus({ status: 'connecting', message: `Transient Error. Retrying current core...` });
        await new Promise(r => setTimeout(r, 2000));
        return processBatchWithFailover(audioBuffer, offset, batchIndex, attemptIndex, retryCount + 1);
      }

      // 3. Exhaustion Failover: Shift to next model in sequence
      if (attemptIndex < sequence.length - 1) {
        const nextModel = MODEL_POOL[sequence[attemptIndex + 1]];
        logIncident("Failover", "Fault Recovery", `Exhausted core ${currentModel.label}. Shifting to ${nextModel.label}.`, 'info');
        setAnalytics(prev => ({ ...prev, failoverEvents: prev.failoverEvents + 1 }));
        return processBatchWithFailover(audioBuffer, offset, batchIndex, attemptIndex + 1, 0);
      }

      return false;
    }
  };

  const startProcessing = async () => {
    if (!videoFile || isProcessing) return;

    try {
      setIsProcessing(true);
      setAnalytics(prev => ({ ...prev, startTime: Date.now(), endTime: null }));
      setStatus({ status: 'connecting', message: 'Decoding Local Media Buffer...' });

      const arrayBuffer = await videoFile.arrayBuffer();
      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
      const decodedBuffer = await audioCtx.decodeAudioData(arrayBuffer);

      const duration = decodedBuffer.duration;
      const numChunks = Math.ceil(duration / CHUNK_DURATION);

      for (let i = 0; i < numChunks; i++) {
        const start = i * CHUNK_DURATION;
        const end = Math.min(start + CHUNK_DURATION, duration);
        const frameStart = Math.floor(start * decodedBuffer.sampleRate);
        const frameEnd = Math.floor(end * decodedBuffer.sampleRate);

        const chunkBuffer = audioCtx.createBuffer(1, frameEnd - frameStart, decodedBuffer.sampleRate);
        chunkBuffer.copyToChannel(decodedBuffer.getChannelData(0).subarray(frameStart, frameEnd), 0);

        const success = await processBatchWithFailover(chunkBuffer, start, i, 0, 0);
        if (!success) throw new Error("Neural Grid Failure. All fallback cores exhausted.");

        setProgress(Math.round(((i + 1) / numChunks) * 100));
        if (i < numChunks - 1) await new Promise(r => setTimeout(r, REQUEST_GAP));
      }

      setAnalytics(prev => ({ ...prev, endTime: Date.now() }));
      setStatus({ status: 'completed', message: 'Neural Translation Link Terminated Successfully.' });
      setIsProcessing(false);
    } catch (error: any) {
      setIsProcessing(false);
      setAnalytics(prev => ({ ...prev, endTime: Date.now() }));
      setStatus({ status: 'error', message: error.message });
      logIncident("Pipeline", "Fatal", error.message, "critical");
    }
  };

  const downloadSRT = () => {
    const srt = generateSRT(segments);
    const blob = new Blob([srt], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `PhilipAI_Captions.srt`;
    document.body.appendChild(a); a.click(); document.body.removeChild(a);
  };

  const globalSuccessRate = useMemo(() => {
    if (analytics.totalRequests === 0) return 0;
    return Math.round((analytics.successfulRequests / analytics.totalRequests) * 100);
  }, [analytics]);

  const totalTimeElapsed = useMemo(() => {
    const { startTime, endTime } = analytics;
    // Explicit null checks and narrowing to satisfy arithmetic constraints in TS.
    if (startTime === null) return '0s';
    const end = endTime !== null ? endTime : Date.now();
    const diff = (end - startTime) / 1000;
    return diff < 60 ? `${diff.toFixed(1)}s` : `${Math.floor(diff / 60)}m ${Math.floor(diff % 60)}s`;
  }, [analytics.startTime, analytics.endTime]);

  const averageLatencyDisplay = useMemo(() => {
    // Explicitly cast to ModelMetric[] and handle reduction with a typed accumulator to prevent arithmetic errors.
    const metrics = Object.values(analytics.modelMetrics) as ModelMetric[];
    const totalLatency = metrics.reduce((acc: number, curr: ModelMetric) => acc + curr.totalLatency, 0);
    const requests = analytics.totalRequests || 1;
    return (totalLatency / requests / 1000).toFixed(2);
  }, [analytics.modelMetrics, analytics.totalRequests]);

  return (
    <div className="min-h-screen p-4 md:p-10 flex flex-col gap-8 max-w-7xl mx-auto selection:bg-emerald-500/30">
      {/* Brand Header */}
      <header className="flex flex-col lg:flex-row items-stretch gap-6">
        <div className="flex-1 glass-panel p-8 rounded-[2.5rem] flex items-center gap-6 shadow-xl ring-1 ring-white/5 hover:ring-white/10 transition-all group">
          {/* Upgraded Neural-Wave Logo */}
          <div className="relative w-16 h-16 shrink-0 group-hover:scale-105 transition-transform duration-500">
            <div className="absolute inset-0 bg-gradient-to-br from-emerald-400 to-emerald-600 rounded-2xl shadow-[0_0_30px_rgba(16,185,129,0.4)] transition-all duration-500 group-hover:rotate-6"></div>
            <div className="absolute inset-0 flex items-center justify-center">
              <svg className="w-10 h-10 text-slate-950 fill-current" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
                <path d="M12 2L4.5 20.29L5.21 21L12 18L18.79 21L19.5 20.29L12 2Z" opacity="0.2" />
                <path d="M12 3L6 18L12 15L18 18L12 3Z" />
                <circle cx="12" cy="7" r="1.5" />
                <circle cx="9" cy="14" r="1" opacity="0.6" />
                <circle cx="15" cy="14" r="1" opacity="0.6" />
                <path d="M12 7L9 14" stroke="currentColor" strokeWidth="0.5" opacity="0.3" />
                <path d="M12 7L15 14" stroke="currentColor" strokeWidth="0.5" opacity="0.3" />
                <path d="M9 14L15 14" stroke="currentColor" strokeWidth="0.5" opacity="0.3" />
              </svg>
            </div>
            <div className="absolute -bottom-1 -right-1 w-4 h-4 bg-slate-950 rounded-full flex items-center justify-center border border-emerald-500/50">
              <div className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse"></div>
            </div>
          </div>

          <div>
            <h1 className="text-4xl font-black tracking-tighter text-white">Philip<span className="text-emerald-500">AI</span></h1>
            <p className="text-[10px] font-black uppercase tracking-[0.4em] text-slate-500 mt-1 flex items-center gap-2">
              <span className={`w-1.5 h-1.5 rounded-full ${isOnline ? 'bg-emerald-500' : 'bg-red-500 animate-ping'}`} />
              {isOnline ? 'Neural Link Ready' : 'Core Connection Interrupted'}
            </p>
          </div>
        </div>

        {/* Engine Control Interface */}
        <div className="flex-[2.5] glass-panel p-4 rounded-[2.5rem] grid grid-cols-1 md:grid-cols-4 gap-3 shadow-xl ring-1 ring-white/5">
          {[
            { id: 'titan', name: 'Titan Core', desc: 'Full Failover Stack', icon: 'M13 10V3L4 14h7v7l9-11h-7z', color: 'text-blue-400' },
            { id: 'silentwave', name: 'SilentWave', desc: 'Whisper-Class Acoustic', icon: 'M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z', color: 'text-purple-400' },
            { id: 'globallink', name: 'GlobalLink', desc: 'Meta High-Reasoning', icon: 'M3.055 11H5a2 2 0 012 2v1a2 2 0 002 2 2 2 0 012 2v2.945M8 3.935V5.5A2.5 2.5 0 0010.5 8h.5a2 2 0 012 2 2 2 0 104 0 2 2 0 012-2h1.065', color: 'text-amber-400' },
            { id: 'nexus', name: 'Anthropic Nexus', desc: 'Claude-Class Logic', icon: 'M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253', color: 'text-rose-400' }
          ].map((engine) => (
            <button
              key={engine.id}
              disabled={isProcessing}
              onClick={() => setSelectedEngine(engine.id as ProcessingEngine)}
              className={`p-4 rounded-3xl border transition-all text-left flex flex-col gap-1 relative overflow-hidden group ${
                selectedEngine === engine.id 
                  ? 'bg-white/5 border-emerald-500/40 shadow-lg' 
                  : 'bg-transparent border-white/5 opacity-50 hover:opacity-100 hover:border-white/10'
              }`}
            >
              <div className="flex items-center gap-2">
                <svg className={`w-4 h-4 ${engine.color}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d={engine.icon} /></svg>
                <span className="text-[10px] font-black text-white uppercase truncate">{engine.name}</span>
              </div>
              <p className="text-[8px] text-slate-500 font-medium leading-tight">{engine.desc}</p>
              {selectedEngine === engine.id && <div className="absolute top-0 right-0 p-2"><div className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-ping" /></div>}
            </button>
          ))}
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Workspace: Media Processing Central */}
        <div className="lg:col-span-8 flex flex-col gap-6">
          <div className="aspect-video bg-black rounded-[3rem] overflow-hidden border border-white/5 shadow-2xl relative ring-1 ring-white/10 group">
            {videoUrl ? (
              <video src={videoUrl} controls className="w-full h-full object-contain" />
            ) : (
              <label className="absolute inset-0 flex flex-col items-center justify-center cursor-pointer hover:bg-slate-900/50 transition-all">
                <div className="w-20 h-20 bg-slate-900 rounded-[2rem] flex items-center justify-center mb-4 border border-white/10 group-hover:border-emerald-500/50 transition-all duration-500">
                  <svg className="w-8 h-8 text-slate-500 group-hover:text-emerald-500 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg>
                </div>
                <span className="text-slate-500 font-bold uppercase tracking-widest text-xs">Import Local Source</span>
                <input type="file" className="hidden" accept="video/*" onChange={handleFileChange} />
              </label>
            )}

            {isProcessing && (
              <div className="absolute top-6 right-6 px-4 py-2 bg-slate-950/80 backdrop-blur-md rounded-xl border border-white/10 text-[10px] font-black text-emerald-500 flex items-center gap-2 shadow-xl ring-1 ring-emerald-500/20">
                <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-ping" />
                ACTIVE: {MODEL_POOL.find(m => m.id === activeModelId)?.label}
              </div>
            )}
          </div>

          <div className="flex flex-col md:flex-row gap-6">
            <div className="flex-1 glass-panel p-10 rounded-[3rem] flex flex-col md:flex-row items-center justify-between gap-8 shadow-xl border border-white/5">
              <div className="space-y-1">
                <span className="text-emerald-500 text-[10px] font-black uppercase tracking-widest">Neural Failover: ARMED</span>
                <h2 className="text-2xl font-bold text-white tracking-tight">Transcription Pipeline</h2>
                <p className="text-slate-500 text-sm">Target: YouTube Multi-Language SRT.</p>
              </div>
              <div className="flex gap-4 w-full md:w-auto">
                <button 
                  onClick={startProcessing}
                  disabled={!videoFile || isProcessing || !isOnline}
                  className="flex-1 md:flex-none bg-emerald-500 hover:bg-emerald-400 disabled:opacity-20 text-slate-950 font-black px-12 py-5 rounded-2xl transition-all shadow-[0_15px_40px_-10px_rgba(16,185,129,0.3)] active:scale-95"
                >
                  {isProcessing ? `Linking...` : 'Engage Grid'}
                </button>
                <button 
                  onClick={downloadSRT}
                  disabled={segments.length === 0}
                  className="flex-1 md:flex-none bg-slate-800 hover:bg-slate-700 disabled:opacity-20 text-white font-bold px-10 py-5 rounded-2xl border border-white/10 transition-all"
                >
                  Export SRT
                </button>
              </div>
            </div>

            <div className={`md:w-64 glass-panel p-8 rounded-[3rem] flex flex-col justify-center items-center gap-2 shadow-xl border ${status.status === 'error' ? 'border-red-500/40' : 'border-white/5'}`}>
               <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Engine Health</span>
               <div className={`text-4xl font-black ${globalSuccessRate < 40 ? 'text-red-500' : 'text-emerald-500'}`}>{globalSuccessRate}%</div>
               <div className="w-full bg-slate-900 h-1 rounded-full overflow-hidden mt-2">
                 <div className={`${globalSuccessRate < 40 ? 'bg-red-500' : 'bg-emerald-500'} h-full transition-all duration-700`} style={{ width: `${globalSuccessRate}%` }} />
               </div>
            </div>
          </div>

          <div className={`text-center px-10 py-3 rounded-2xl transition-colors ${status.status === 'error' ? 'bg-red-500/5 border border-red-500/10' : ''}`}>
            <p className={`text-[10px] font-black uppercase tracking-[0.4em] ${status.status === 'error' ? 'text-red-500' : 'text-slate-600 animate-pulse'}`}>
              {status.message}
            </p>
          </div>
        </div>

        {/* Sidebar: Analytics & Diagnostic Stream */}
        <div className="lg:col-span-4 flex flex-col gap-6">
          <div className="glass-panel rounded-[2.5rem] p-6 shadow-xl ring-1 ring-white/10 flex flex-col">
            <h3 className="text-[10px] font-black uppercase tracking-widest text-slate-500 mb-4 flex items-center justify-between">
              <span>Diagnostic Feed</span>
              <span className="text-emerald-500/70 font-bold uppercase">Failovers: {analytics.failoverEvents}</span>
            </h3>
            <div className="grid grid-cols-2 gap-3 mb-6">
              <div className="bg-slate-950/50 p-4 rounded-2xl border border-white/5">
                <p className="text-[8px] font-black text-slate-600 uppercase">Requests</p>
                <p className="text-lg font-bold text-white">{analytics.totalRequests}</p>
              </div>
              <div className="bg-slate-950/50 p-4 rounded-2xl border border-white/5">
                <p className="text-[8px] font-black text-slate-600 uppercase">Avg Latency</p>
                <p className="text-lg font-bold text-white">{averageLatencyDisplay}s</p>
              </div>
            </div>

            <div className="flex-1 max-h-[200px] overflow-y-auto custom-scrollbar space-y-2">
              {incidents.length === 0 ? (
                <div className="text-center py-10 opacity-20 text-[9px] font-black uppercase tracking-widest">Neural Link Nominal</div>
              ) : (
                incidents.map((inc, i) => (
                  <div key={i} className={`text-[9px] p-3 rounded-xl border transition-all ${
                    inc.severity === 'critical' ? 'bg-red-500/10 border-red-500/20' : 
                    inc.severity === 'info' ? 'bg-emerald-500/10 border-emerald-500/20' : 
                    'bg-slate-900/50 border-white/5'
                  }`}>
                    <div className="flex justify-between items-start mb-1">
                      <span className={`font-black ${
                        inc.severity === 'critical' ? 'text-red-400' : 
                        inc.severity === 'info' ? 'text-emerald-400' : 
                        'text-amber-500'
                      }`}>{inc.type}</span>
                      <span className="text-slate-600 font-mono text-[8px]">{inc.time}</span>
                    </div>
                    <p className="text-slate-400 leading-tight">[{inc.model}] {inc.detail}</p>
                  </div>
                ))
              )}
            </div>
          </div>

          {/* Transcription Feed Output */}
          <div className="glass-panel rounded-[3rem] flex-1 flex flex-col shadow-2xl overflow-hidden ring-1 ring-white/10 min-h-[400px]">
            <div className="p-8 border-b border-white/5 bg-slate-950/20 flex items-center justify-between">
              <h3 className="text-xs font-black uppercase tracking-widest text-white">Live Neural Feed</h3>
              <span className="text-emerald-500 bg-emerald-500/10 px-3 py-1 rounded-lg text-[9px] font-black">{segments.length} BLOCKS</span>
            </div>

            <div className="flex-1 overflow-y-auto p-6 space-y-4 custom-scrollbar">
              {segments.length === 0 && (
                <div className="h-full flex flex-col items-center justify-center text-center opacity-10 italic text-xs space-y-3 py-20">
                  <div className="w-12 h-12 border-2 border-slate-700 border-dashed rounded-full animate-spin-slow" />
                  <p className="font-black uppercase tracking-widest">Synchronizing Cores...</p>
                </div>
              )}
              {segments.map((seg, idx) => (
                <div key={seg.id} className="bg-slate-900/40 p-5 rounded-2xl border border-white/5 hover:border-emerald-500/30 transition-all group animate-in fade-in slide-in-from-bottom-2 duration-300">
                  <div className="flex justify-between items-center mb-2">
                    <span className="text-[9px] font-black text-slate-700 uppercase">Block {String(idx + 1).padStart(3, '0')}</span>
                    <span className="text-[9px] font-mono text-emerald-500 bg-emerald-500/5 px-2 py-1 rounded-md">
                      {Math.floor(seg.start_seconds / 60)}:{(seg.start_seconds % 60).toFixed(1).padStart(4, '0')}
                    </span>
                  </div>
                  <p className="text-slate-300 text-xs leading-relaxed font-medium group-hover:text-white transition-colors">{seg.text}</p>
                </div>
              ))}
              <div ref={transcriptEndRef} />
            </div>

            <div className="p-4 bg-slate-950/50 border-t border-white/5">
              <div className="w-full h-1.5 bg-slate-800 rounded-full overflow-hidden">
                <div className={`h-full bg-emerald-500 transition-all duration-1000 ${isProcessing ? 'animate-pulse' : ''}`} style={{ width: `${progress}%` }} />
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;
